export interface BaseMemory {
  id: string;
  date: string;
  title: string;
  category: 'college' | 'personal';
  tags?: string[];
  course?: string;
  voiceNote?: {
    transcript: string;
  };
  location?: {
    latitude: number;
    longitude: number;
  };
}

export interface TranscriptSegment {
  speakerId: number;
  text: string;
}

export interface StrokePoint {
    x: number;
    y: number;
    t: number; // Timestamp in milliseconds relative to recording start
}

export interface DrawingStroke {
    points: StrokePoint[];
    color: string;
    width: number;
}

export interface NotebookData {
    strokes: DrawingStroke[];
    backgroundImageUrl?: string;
    textNotes?: { text: string; x: number; y: number; t: number }[];
}

export interface VoiceMemory extends BaseMemory {
  type: 'voice';
  transcript: string;
  summary?: string;
  structuredTranscript?: TranscriptSegment[];
  speakerMappings?: { [key: number]: string };
  actionItems?: { text: string; done: boolean }[];
  notebook?: NotebookData;
}

export interface WebMemory extends BaseMemory {
  type: 'web';
  url: string;
  content: string;
  contentType?: string;
}

export interface PhysicalItemMemory extends BaseMemory {
  type: 'item';
  description: string;
  imageDataUrl: string;
}

export interface VideoItemMemory extends BaseMemory {
  type: 'video';
  description: string;
  videoDataUrl: string;
  transcript: string;
}

export interface DocumentMemory extends BaseMemory {
  type: 'document';
  extractedText: string;
  imageDataUrl: string;
}

export interface FileMemory extends BaseMemory {
  type: 'file';
  fileUrl: string;
  mimeType: string;
  size?: number;
}

export type AnyMemory = VoiceMemory | WebMemory | PhysicalItemMemory | VideoItemMemory | DocumentMemory | FileMemory;

export type TaskStatus = 'idea' | 'todo' | 'in-progress' | 'done';

export interface SubTask {
    id: string;
    title: string;
    done: boolean;
}

export interface Task {
  id: string;
  title: string;
  description?: string;
  status: TaskStatus;
  category: 'college' | 'personal';
  course?: string;
  project?: string;
  subtasks?: SubTask[];
  dueDate?: string;
  linkedMemoryIds?: string[];
  createdAt: string;
}

export interface CalendarEvent {
  id: string;
  title: string;
  startTime: string; // ISO string
  endTime: string;   // ISO string
  category: 'college' | 'personal';
  description?: string;
  relatedTaskId?: string;
  source?: 'moodle' | 'google' | 'manual';
}

import React, { useState, useMemo, useEffect } from 'react';
import BottomNavBar from './components/BottomNavBar';
import Sidebar from './components/Sidebar';
import CollegeView from './components/CollegeView';
import QASession from './components/QASession';
import VisionView from './components/VisionView';
import WebClipsView from './components/WebClipsView';
import PersonalView from './components/PersonalView';
import ScheduleView from './components/ScheduleView';
import FilesView from './components/FilesView';
import UpdateNotification from './components/UpdateNotification';
import SyncSetup from './components/SyncSetup';
import SettingsModal from './components/SettingsModal';
import AddWebMemoryModal from './components/AddWebMemoryModal';
import TopInstallBanner from './components/TopInstallBanner';
import { useRecordings } from './hooks/useRecordings';
import { useServiceWorker } from './hooks/useServiceWorker';
import { fetchMoodleEvents } from './services/moodleService';
import type { AnyMemory, WebMemory, CalendarEvent, Task } from './types';
import { SettingsIcon, Loader2Icon, BrainCircuitIcon, CalendarIcon } from './components/Icons';

export type View = 'physical' | 'college' | 'webclips' | 'askai' | 'voicenotes' | 'files';

const viewTitles: Record<View, string> = {
    physical: 'Items',
    college: 'College',
    webclips: 'Web Clips',
    askai: 'Ask AI',
    voicenotes: 'Personal',
    files: 'Files',
};

function App() {
  const [view, setView] = useState<View>('college');
  const [showSettings, setShowSettings] = useState(false);
  const [showSchedule, setShowSchedule] = useState(false);
  const [calendarEvents, setCalendarEvents] = useState<CalendarEvent[]>([]);
  const [moodleEvents, setMoodleEvents] = useState<CalendarEvent[]>([]);
  const [sharedContent, setSharedContent] = useState<{ url: string; title: string } | null>(null);

  const { 
    memories, addMemory, deleteMemory, updateMemory, bulkDeleteMemories,
    tasks, addTask, updateTask, deleteTask, 
    courses, addCourse, user, loading,
    moodleToken, saveMoodleToken,
  } = useRecordings();

  const { updateAvailable, updateServiceWorker } = useServiceWorker();

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const isShared = params.has('shared') || params.has('url') || params.has('text');

    if (isShared) {
      const title = params.get('title') || '';
      const text = params.get('text') || '';
      const url = params.get('url') || '';

      let detectedUrl = url;
      let detectedTitle = title;

      if (!detectedUrl && text.includes('http')) {
        const urlMatch = text.match(/(https?:\/\/[^\s]+)/);
        if (urlMatch) {
          detectedUrl = urlMatch[0];
          if (!detectedTitle) {
            detectedTitle = text.replace(detectedUrl, '').trim();
          }
        }
      }

      if (detectedUrl || detectedTitle) {
        setSharedContent({ url: detectedUrl, title: detectedTitle || 'Shared Link' });
        setView('webclips');
      }

      window.history.replaceState({}, document.title, window.location.pathname);
    }
  }, []);

  useEffect(() => {
    const getMoodleEvents = async () => {
      if (moodleToken) {
        const events = await fetchMoodleEvents(moodleToken);
        setMoodleEvents(events);
      } else {
        setMoodleEvents([]);
      }
    };
    getMoodleEvents();
  }, [moodleToken]);

  const addCalendarEvent = (event: Omit<CalendarEvent, 'id'>) => {
    const newEvent = { ...event, id: Date.now().toString(), source: 'manual' as const };
    setCalendarEvents(prev => [...prev, newEvent].sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime()));
  };

  const deleteCalendarEvent = (eventId: string) => {
      if (window.confirm('Are you sure you want to delete this event?')) {
          setCalendarEvents(prev => prev.filter(e => e.id !== eventId));
      }
  };

  const handleSaveSharedClip = (memory: Omit<WebMemory, 'id' | 'date' | 'category'>) => {
    addMemory({ ...memory, category: 'personal' });
    setSharedContent(null);
  };

  if (loading) return <div className="flex h-screen items-center justify-center bg-gray-900"><Loader2Icon className="w-20 h-20 animate-spin text-blue-500" /></div>;
  if (!user) return <SyncSetup onSyncIdSet={() => {}} />;

  const allCalendarEvents = useMemo(() => [...calendarEvents, ...moodleEvents], [calendarEvents, moodleEvents]);

  const renderView = () => {
    switch (view) {
      case 'physical': return <VisionView memories={memories.filter(m => m.type === 'item' || m.type === 'video')} onDelete={deleteMemory} onUpdate={updateMemory} onSave={addMemory} bulkDelete={bulkDeleteMemories} />;
      case 'college': return <CollegeView lectures={memories.filter(m => m.category === 'college')} onDelete={deleteMemory} onUpdate={updateMemory} onSave={addMemory} bulkDelete={bulkDeleteMemories} courses={courses} addCourse={addCourse} tasks={tasks} addTask={addTask} updateTask={updateTask} deleteTask={deleteTask} />;
      case 'webclips': return <WebClipsView memories={memories.filter(m => m.type === 'web')} onDelete={deleteMemory} onUpdate={updateMemory} onSave={addMemory} syncSharedClips={async()=>0} pendingClipsCount={0} bulkDelete={bulkDeleteMemories}/>;
      case 'askai': return <QASession memories={memories} tasks={tasks} calendarEvents={allCalendarEvents} onAddCalendarEvent={addCalendarEvent} />;
      case 'voicenotes': return <PersonalView memories={memories.filter(m => m.category === 'personal')} tasks={tasks} onSaveMemory={addMemory} onDeleteMemory={deleteMemory} onUpdateMemory={updateMemory} bulkDeleteMemories={bulkDeleteMemories} onAddTask={addTask} onUpdateTask={updateTask} onDeleteTask={deleteTask} />;
      case 'files': return <FilesView memories={memories} onSave={addMemory} onDelete={deleteMemory} onUpdate={updateMemory} />;
      default: return <QASession memories={memories} tasks={tasks} />;
    }
  };

  return (
    <div className="fixed inset-0 bg-[#0b0f1a] text-white flex flex-col md:flex-row overflow-hidden overscroll-none">
      <TopInstallBanner />
      <div className="hidden md:block flex-shrink-0">
        <Sidebar view={view} setView={setView} onOpenSettings={() => setShowSettings(true)} onOpenSchedule={() => setShowSchedule(true)} />
      </div>

      <div className="flex-grow flex flex-col min-w-0 bg-[#111827] md:rounded-l-[2rem] md:my-3 md:mr-3 shadow-2xl border-l border-t border-b border-gray-800/50 relative overflow-hidden">
        {showSchedule && (
          <ScheduleView 
            events={allCalendarEvents} 
            onClose={() => setShowSchedule(false)} 
            onAddEvent={addCalendarEvent}
            onDeleteEvent={deleteCalendarEvent}
          />
        )}

        {showSettings && (
          <SettingsModal 
            syncId={user.email || user.uid} 
            onClose={() => setShowSettings(false)} 
            onReset={() => {}} 
            data={{ memories, courses, tasks }}
            onImport={() => {}} 
            moodleToken={moodleToken}
            onSaveMoodleToken={saveMoodleToken}
          />
        )}

        {sharedContent && (
          <AddWebMemoryModal 
            initialUrl={sharedContent.url}
            initialTitle={sharedContent.title}
            onClose={() => setSharedContent(null)}
            onSave={handleSaveSharedClip}
          />
        )}

        <header className="flex-shrink-0 bg-gray-800 border-b-2 border-gray-700 shadow-md z-20 md:hidden" style={{ paddingTop: 'var(--sat)' }}>
          <div className="flex justify-between items-center px-4 py-3">
              <button onClick={() => setShowSchedule(true)} className="p-3 bg-gray-900 rounded-xl border-2 border-gray-700 text-blue-400 active:scale-90 transition-transform">
                  <CalendarIcon className="w-8 h-8" />
              </button>

              <div className="flex items-center gap-3">
                  <BrainCircuitIcon className="w-8 h-8 text-blue-400" />
                  <h1 className="text-xl font-black uppercase tracking-tight">{viewTitles[view]}</h1>
              </div>

              <button onClick={() => setShowSettings(true)} className="p-3 rounded-xl bg-gray-900 border-2 border-gray-700 active:scale-90 transition-transform">
                  <SettingsIcon className="w-8 h-8 text-gray-400" />
              </button>
          </div>
        </header>

        <main className="flex-grow min-h-0 relative z-10 flex flex-col">
          <div className="flex-grow overflow-y-auto p-4 sm:p-6 lg:p-10 scroll-smooth pb-10">
            <div className="max-w-7xl mx-auto h-full">
              {renderView()}
            </div>
          </div>
        </main>

        <footer className="flex-shrink-0 bg-gray-900 border-t-2 border-gray-800 shadow-[0_-4px_10px_rgba(0,0,0,0.3)] z-20 md:hidden" style={{ paddingBottom: 'max(var(--sab), 0.5rem)' }}>
          <BottomNavBar view={view} setView={setView} />
        </footer>
      </div>

      {updateAvailable && <UpdateNotification onUpdate={updateServiceWorker} />}
    </div>
  );
}

export default App;

