import React, { useState, useMemo } from 'react';
import type { AnyMemory, FileMemory, DocumentMemory, VoiceMemory, PhysicalItemMemory } from '../types';
import { 
    FolderIcon, MicIcon, CameraIcon, FileTextIcon, GraduationCapIcon, 
    DownloadIcon, SendIcon, PlusIcon, XIcon, GlobeIcon, Loader2Icon, SearchIcon, ShareIcon
} from './Icons';
import AddDocumentModal from './AddDocumentModal';
import { generatePDF } from '../services/pdfService';

interface FilesViewProps {
    memories: AnyMemory[];
    onSave: (memory: Omit<AnyMemory, 'id' | 'date'>) => void;
    onDelete: (id: string) => void;
    onUpdate: (id: string, updates: Partial<AnyMemory>) => void;
}

const FileItem: React.FC<{ 
    memory: AnyMemory; 
    onDelete: (id: string) => void;
    onShare: (memory: AnyMemory) => void;
}> = ({ memory, onDelete, onShare }) => {
    const getIcon = () => {
        if (memory.category === 'college' && memory.type === 'voice') return <GraduationCapIcon className="w-8 h-8 text-blue-400" />;
        switch (memory.type) {
            case 'voice': return <MicIcon className="w-8 h-8 text-blue-400" />;
            case 'document': return <FileTextIcon className="w-8 h-8 text-indigo-400" />;
            case 'item': return <CameraIcon className="w-8 h-8 text-purple-400" />;
            case 'web': return <GlobeIcon className="w-8 h-8 text-teal-400" />;
            case 'file': return <FileTextIcon className="w-8 h-8 text-white" />;
            default: return <FolderIcon className="w-8 h-8 text-gray-400" />;
        }
    };

    const getTypeLabel = () => {
        if (memory.category === 'college') return 'College Material';
        switch (memory.type) {
            case 'voice': return 'Voice Note';
            case 'document': return 'Document Scan';
            case 'item': return 'Physical Item';
            case 'web': return 'Web Link';
            case 'file': return 'Stored File';
            default: return 'Asset';
        }
    };

    return (
        <div className="bg-gray-800/80 p-5 rounded-3xl border-4 border-gray-800 hover:border-blue-600 transition-all flex items-center justify-between group shadow-xl">
            <div className="flex items-center gap-5 overflow-hidden">
                <div className="p-4 bg-gray-900 rounded-2xl group-hover:bg-blue-900/30 transition-colors shrink-0">
                    {getIcon()}
                </div>
                <div className="overflow-hidden">
                    <h3 className="text-xl font-black text-white truncate uppercase tracking-tighter">{memory.title}</h3>
                    <div className="flex items-center gap-2 mt-1">
                        <span className="text-xs font-black text-blue-500 uppercase tracking-widest">{getTypeLabel()}</span>
                        <span className="text-xs text-gray-500 font-bold">• {new Date(memory.date).toLocaleDateString()}</span>
                    </div>
                </div>
            </div>

            <div className="flex items-center gap-3 shrink-0">
                <button 
                    onClick={() => onShare(memory)}
                    className="p-3 bg-gray-900 text-blue-400 rounded-xl hover:bg-gray-700 transition-colors shadow-lg"
                    aria-label="Share file"
                >
                    <ShareIcon className="w-6 h-6" />
                </button>
                <button 
                    onClick={() => { if(confirm('Delete this file permanently?')) onDelete(memory.id); }}
                    className="p-3 bg-gray-900 text-red-500 rounded-xl hover:bg-gray-700 transition-colors shadow-lg"
                    aria-label="Delete file"
                >
                    <XIcon className="w-6 h-6" />
                </button>
            </div>
        </div>
    );
};

const AddFileMenu: React.FC<{ 
    onClose: () => void;
    onAction: (action: 'scan' | 'upload' | 'cloud') => void;
}> = ({ onClose, onAction }) => (
    <div className="fixed inset-0 bg-black/80 z-[80] flex items-center justify-center p-6 animate-fade-in" onClick={onClose}>
        <div className="bg-gray-800 rounded-[3rem] border-4 border-gray-700 p-8 w-full max-w-md space-y-6 shadow-2xl" onClick={e => e.stopPropagation()}>
            <h2 className="text-2xl font-black text-white uppercase tracking-tighter text-center">Add to Vault</h2>

            <div className="space-y-4">
                <button onClick={() => onAction('scan')} className="w-full flex items-center gap-5 p-6 bg-blue-600 rounded-[2rem] hover:bg-blue-500 transition-all shadow-xl group">
                    <CameraIcon className="w-10 h-10 text-white group-hover:scale-110 transition-transform" />
                    <div className="text-left">
                        <p className="text-xl font-black text-white uppercase tracking-tighter">Scan to PDF</p>
                        <p className="text-sm text-blue-100 font-bold">Use camera for OCR</p>
                    </div>
                </button>

                <button onClick={() => onAction('upload')} className="w-full flex items-center gap-5 p-6 bg-indigo-600 rounded-[2rem] hover:bg-indigo-500 transition-all shadow-xl group">
                    <DownloadIcon className="w-10 h-10 text-white group-hover:scale-110 transition-transform rotate-180" />
                    <div className="text-left">
                        <p className="text-xl font-black text-white uppercase tracking-tighter">Upload Local</p>
                        <p className="text-sm text-indigo-100 font-bold">Files from device</p>
                    </div>
                </button>

                <button onClick={() => onAction('cloud')} className="w-full flex items-center gap-5 p-6 bg-purple-600 rounded-[2rem] hover:bg-purple-500 transition-all shadow-xl group">
                    <GlobeIcon className="w-10 h-10 text-white group-hover:scale-110 transition-transform" />
                    <div className="text-left">
                        <p className="text-xl font-black text-white uppercase tracking-tighter">Cloud Import</p>
                        <p className="text-sm text-purple-100 font-bold">Google Drive / Moodle</p>
                    </div>
                </button>
            </div>

            <button onClick={onClose} className="w-full py-4 bg-gray-700 text-gray-400 font-black rounded-2xl hover:text-white transition-colors">CANCEL</button>
        </div>
    </div>
);

const FilesView: React.FC<FilesViewProps> = ({ memories, onSave, onDelete, onUpdate }) => {
    const [searchQuery, setSearchQuery] = useState('');
    const [filter, setFilter] = useState<'all' | 'audio' | 'image' | 'doc'>('all');
    const [showAddMenu, setShowAddMenu] = useState(false);
    const [showScanModal, setShowScanModal] = useState(false);

    const filteredMemories = useMemo(() => {
        let results = memories;

        if (filter === 'audio') results = results.filter(m => m.type === 'voice');
        if (filter === 'image') results = results.filter(m => m.type === 'item');
        if (filter === 'doc') results = results.filter(m => m.type === 'document' || m.type === 'web');

        if (searchQuery.trim()) {
            const q = searchQuery.toLowerCase();
            results = results.filter(m => 
                m.title.toLowerCase().includes(q) || 
                (m.tags && m.tags.some(t => t.toLowerCase().includes(q)))
            );
        }

        return results.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    }, [memories, filter, searchQuery]);

    const handleAction = (action: 'scan' | 'upload' | 'cloud') => {
        setShowAddMenu(false);
        if (action === 'scan') setShowScanModal(true);
        if (action === 'upload') {
            const input = document.createElement('input');
            input.type = 'file';
            input.onchange = (e: any) => {
                const file = e.target.files[0];
                if (file) {
                    const reader = new FileReader();
                    reader.onload = (loadEvent) => {
                        onSave({
                            type: 'file',
                            title: file.name,
                            fileUrl: loadEvent.target?.result as string,
                            mimeType: file.type,
                            size: file.size,
                            category: 'personal'
                        } as Omit<FileMemory, 'id' | 'date'>);
                    };
                    reader.readAsDataURL(file);
                }
            };
            input.click();
        }
        if (action === 'cloud') {
            alert("Integrating with Moodle and Google Drive... Please ensure tokens are set in Settings.");
        }
    };

    const handleShare = async (memory: AnyMemory) => {
        try {
            if (navigator.share) {
                await navigator.share({
                    title: memory.title,
                    text: `Shared from My Second Brain: ${memory.title}`,
                    url: memory.type === 'web' ? (memory as any).url : window.location.href
                });
            } else {
                // Fallback for document PDF download
                if (memory.type === 'document') {
                    const doc = memory as DocumentMemory;
                    generatePDF(doc.title, doc.extractedText, doc.imageDataUrl);
                } else {
                    alert("Sharing not supported on this browser. Use Download instead.");
                }
            }
        } catch (e) {
            console.error("Share failed", e);
        }
    };

    return (
        <div className="flex flex-col h-full space-y-8">
            {showAddMenu && <AddFileMenu onClose={() => setShowAddMenu(false)} onAction={handleAction} />}
            {showScanModal && <AddDocumentModal onSave={onSave} onClose={() => setShowScanModal(false)} />}

            <header className="flex flex-col sm:flex-row gap-6 justify-between items-start sm:items-center">
                <div className="flex-grow w-full max-w-lg relative">
                    <SearchIcon className="absolute left-5 top-1/2 -translate-y-1/2 w-6 h-6 text-gray-500" />
                    <input 
                        type="text" 
                        placeholder="SEARCH YOUR BRAIN..." 
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="w-full bg-gray-800 p-6 pl-14 rounded-3xl border-4 border-gray-800 focus:border-blue-600 outline-none font-black uppercase text-xl tracking-tighter shadow-inner"
                    />
                </div>

                <button 
                    onClick={() => setShowAddMenu(true)}
                    className="flex items-center justify-center gap-4 px-10 py-6 bg-blue-600 text-white rounded-[2rem] shadow-2xl hover:bg-blue-700 transition-all border-b-8 border-blue-800 active:border-b-0 active:translate-y-2 group"
                >
                    <PlusIcon className="w-8 h-8 group-hover:rotate-90 transition-transform" />
                    <span className="text-2xl font-black uppercase tracking-tighter">ADD FILE</span>
                </button>
            </header>

            <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide">
                {[
                    { id: 'all', label: 'All Files' },
                    { id: 'audio', label: 'Recordings' },
                    { id: 'image', label: 'Images' },
                    { id: 'doc', label: 'Documents' }
                ].map(opt => (
                    <button 
                        key={opt.id}
                        onClick={() => setFilter(opt.id as any)}
                        className={`px-8 py-3 rounded-2xl font-black text-sm uppercase tracking-widest whitespace-nowrap transition-all ${filter === opt.id ? 'bg-blue-600 text-white shadow-lg' : 'bg-gray-800 text-gray-500 hover:text-gray-300 border-2 border-gray-700'}`}
                    >
                        {opt.label}
                    </button>
                ))}
            </div>

            <main className="flex-grow min-h-0 overflow-y-auto space-y-4 pb-40 pr-1">
                {filteredMemories.length === 0 ? (
                    <div className="text-center py-24 bg-gray-800/30 rounded-[3rem] border-4 border-dashed border-gray-800">
                        <FolderIcon className="w-24 h-24 mx-auto text-gray-800 mb-6" />
                        <p className="text-2xl text-gray-600 font-black uppercase tracking-tighter">Vault Empty</p>
                    </div>
                ) : (
                    filteredMemories.map(mem => (
                        <FileItem 
                            key={mem.id} 
                            memory={mem} 
                            onDelete={onDelete} 
                            onShare={handleShare}
                        />
                    ))
                )}
            </main>
        </div>
    );
};

