import { useState, useEffect, useCallback } from 'react';

export const useServiceWorker = () => {
    const [waitingWorker, setWaitingWorker] = useState<ServiceWorker | null>(null);
    const [updateAvailable, setUpdateAvailable] = useState(false);

    const onUpdate = useCallback((registration: ServiceWorkerRegistration) => {
        if (registration.waiting) {
            setWaitingWorker(registration.waiting);
            setUpdateAvailable(true);
        }
    }, []);

    useEffect(() => {
        if ('serviceWorker' in navigator) {
            const registerAndListen = () => {
                // Use a relative path to ensure the Service Worker is registered 
                // within the same origin as the application, avoiding cross-origin errors.
                navigator.serviceWorker.register('./sw.js').then(registration => {
                    if (registration.waiting) {
                        onUpdate(registration);
                    }
                    registration.addEventListener('updatefound', () => {
                        const newWorker = registration.installing;
                        if (newWorker) {
                            newWorker.addEventListener('statechange', () => {
                                if (newWorker.state === 'installed') {
                                    onUpdate(registration);
                                }
                            });
                        }
                    });
                }).catch(error => {
                    console.error('Service Worker registration failed:', error);
                });
            };

            // Register the service worker once the page is fully loaded.
            if (document.readyState === 'complete') {
                registerAndListen();
            } else {
                window.addEventListener('load', registerAndListen);
                return () => window.removeEventListener('load', registerAndListen);
            }

            let refreshing = false;
            navigator.serviceWorker.addEventListener('controllerchange', () => {
                if (!refreshing) {
                    window.location.reload();
                    refreshing = true;
                }
            });
        }
    }, [onUpdate]);

    const updateServiceWorker = useCallback(() => {
        if (waitingWorker) {
            waitingWorker.postMessage({ type: 'SKIP_WAITING' });
        }
    }, [waitingWorker]);

    return { updateAvailable, updateServiceWorker };
};

const CACHE_NAME = 'second-brain-v15';
const ASSETS_TO_CACHE = [
  './',
  './index.html',
  './manifest.json',
  './icon.svg'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(ASSETS_TO_CACHE);
    })
  );
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cacheName) => {
          if (cacheName !== CACHE_NAME) {
            return caches.delete(cacheName);
          }
        })
      );
    })
  );
  self.clients.claim();
});

self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url);

  // Handle shared intent navigation
  if (url.searchParams.has('shared') || url.searchParams.has('url') || url.searchParams.has('text')) {
      // For shared content, we always want the root app to load and parse the query params
      event.respondWith(
          fetch(event.request)
            .catch(() => caches.match('./index.html'))
      );
      return;
  }

  event.respondWith(
    caches.match(event.request).then(response => {
      return response || fetch(event.request);
    })
  );
});

