const FileItem: React.FC<{ 
    memory: AnyMemory; 
    onDelete: (id: string) => void;
    onShare: (memory: AnyMemory) => void;
    onPreview: (memory: AnyMemory) => void;
}> = ({ memory, onDelete, onShare, onPreview }) => {
    const getIcon = () => {
        if (memory.category === 'college' && memory.type === 'voice') return <GraduationCapIcon className="w-8 h-8 text-blue-400" />;
        switch (memory.type) {
            case 'voice': return <MicIcon className="w-8 h-8 text-blue-400" />;
            case 'document': return <FileTextIcon className="w-8 h-8 text-indigo-400" />;
            case 'item': return <CameraIcon className="w-8 h-8 text-purple-400" />;
            case 'video': return <VideoIcon className="w-8 h-8 text-orange-400" />;
            case 'web': return <GlobeIcon className="w-8 h-8 text-teal-400" />;
            default: return <FolderIcon className="w-8 h-8 text-gray-400" />;
        }
    };

    const getTypeLabel = () => {
        if (memory.category === 'college') return 'College Material';
        switch (memory.type) {
            case 'voice': return 'Audio Note';
            case 'document': return 'Document Scan';
            case 'item': return 'Physical Item';
            case 'video': return 'Video Clip';
            case 'web': return 'Web Link';
            default: return 'Asset';
        }
    };

    const getActionIcon = () => {
        if (memory.type === 'voice' || memory.type === 'video') return <PlayIcon className="w-8 h-8" />;
        return <EyeIcon className="w-8 h-8" />;
    };

    return (
        <div className="bg-gray-800/80 p-4 rounded-[2rem] border-4 border-gray-800 hover:border-blue-600 transition-all flex flex-col gap-4 group shadow-xl">
            <div className="flex items-center gap-4">
