                    <h3 className="text-xl font-black text-white truncate uppercase tracking-tighter leading-tight">{memory.title}</h3>
                    <div className="flex items-center gap-2">
                        <span className="text-xs font-black text-blue-500 uppercase tracking-widest">{getTypeLabel()}</span>
                        <span className="text-xs text-gray-500 font-bold">• {new Date(memory.date).toLocaleDateString()}</span>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-4 gap-2">
                <button 
                    onClick={() => onPreview(memory)}
                    className="col-span-2 flex items-center justify-center gap-2 py-4 bg-blue-600 text-white rounded-2xl hover:bg-blue-500 transition-all font-black uppercase text-sm shadow-lg border-b-4 border-blue-800 active:border-b-0 active:translate-y-1"
                    aria-label="View or play file"
                >
                    {getActionIcon()} OKAY
                </button>
                <button 
                    onClick={() => onShare(memory)}
                    className="flex items-center justify-center p-4 bg-gray-900 text-gray-400 rounded-2xl hover:text-white transition-colors"
                    aria-label="Share"
                >
                    <ShareIcon className="w-6 h-6" />
                </button>
                <button 
                    onClick={() => { if(confirm('Delete permanently?')) onDelete(memory.id); }}
                    className="flex items-center justify-center p-4 bg-gray-900 text-red-500 rounded-2xl hover:bg-red-900/20 transition-colors"
                    aria-label="Delete"
                >
                    <XIcon className="w-6 h-6" />
                </button>
            </div>
        </div>
    );
};

const FilesView: React.FC<FilesViewProps> = ({ memories, onSave, onDelete, onUpdate }) => {
    const [searchQuery, setSearchQuery] = useState('');
    const [filter, setFilter] = useState<'all' | 'audio' | 'image' | 'doc'>('all');
    const [showAddMenu, setShowAddMenu] = useState(false);
    const [showScanModal, setShowScanModal] = useState(false);
    const [previewMemory, setPreviewMemory] = useState<AnyMemory | null>(null);

    const filteredMemories = useMemo(() => {
        let results = memories;

        if (filter === 'audio') results = results.filter(m => m.type === 'voice');
        if (filter === 'image') results = results.filter(m => m.type === 'item' || m.type === 'video');
        if (filter === 'doc') results = results.filter(m => m.type === 'document' || m.type === 'web');

        if (searchQuery.trim()) {
            const q = searchQuery.toLowerCase();
            results = results.filter(m => 
                m.title.toLowerCase().includes(q) || 
                (m.tags && m.tags.some(t => t.toLowerCase().includes(q)))
            );
        }

        return results.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    }, [memories, filter, searchQuery]);

    return (
        <div className="flex flex-col h-full space-y-6 max-w-4xl mx-auto">
            {showAddMenu && <AddFileMenu onClose={() => setShowAddMenu(false)} onAction={(a) => {
                if(a === 'scan') setShowScanModal(true);
                setShowAddMenu(false);
            }} />}
            {showScanModal && <AddDocumentModal onSave={onSave} onClose={() => setShowScanModal(false)} />}
            {previewMemory && <MediaPreviewModal memory={previewMemory} onClose={() => setPreviewMemory(null)} />}

            <header className="flex flex-col gap-4">
                <div className="relative">
                    <SearchIcon className="absolute left-5 top-1/2 -translate-y-1/2 w-6 h-6 text-gray-500" />
                    <input 
                        type="text" 
                        placeholder="SEARCH..." 
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="w-full bg-gray-800 p-5 pl-14 rounded-3xl border-4 border-gray-800 focus:border-blue-600 outline-none font-black uppercase text-xl tracking-tighter shadow-inner"
                    />
                </div>

                <button 
                    onClick={() => setShowAddMenu(true)}
                    className="w-full flex items-center justify-center gap-4 py-5 bg-blue-600 text-white rounded-3xl shadow-2xl hover:bg-blue-700 transition-all border-b-8 border-blue-800 active:border-b-0 active:translate-y-2 group"
                >
                    <PlusIcon className="w-8 h-8 group-hover:rotate-90 transition-transform" />
                    <span className="text-2xl font-black uppercase tracking-tighter">ADD NEW FILE</span>
                </button>
            </header>

            <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide shrink-0">
                {[
                    { id: 'all', label: 'All' },
                    { id: 'audio', label: 'Audio' },
                    { id: 'image', label: 'Media' },
                    { id: 'doc', label: 'Docs' }
                ].map(opt => (
                    <button 
                        key={opt.id}
                        onClick={() => setFilter(opt.id as any)}
                        className={`flex-1 min-w-[5rem] py-3 rounded-2xl font-black text-xs uppercase tracking-widest transition-all ${filter === opt.id ? 'bg-blue-600 text-white shadow-lg' : 'bg-gray-800 text-gray-500 border-2 border-gray-700'}`}
                    >
                        {opt.label}
                    </button>
                ))}
            </div>

            <main className="flex-grow min-h-0 overflow-y-auto space-y-4 pb-20 px-1 scroll-smooth">
                {filteredMemories.length === 0 ? (
                    <div className="text-center py-20 bg-gray-800/30 rounded-[3rem] border-4 border-dashed border-gray-800">
                        <FolderIcon className="w-20 h-20 mx-auto text-gray-800 mb-4" />
                        <p className="text-xl text-gray-600 font-black uppercase tracking-tighter">Vault Empty</p>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        {filteredMemories.map(mem => (
                            <FileItem 
                                key={mem.id} 
                                memory={mem} 
                                onDelete={onDelete} 
                                onShare={(m) => setPreviewMemory(m)}
                                onPreview={(m) => setPreviewMemory(m)}
                            />
                        ))}
                    </div>
                )}
            </main>
        </div>
    );
};

