      <div className="flex justify-between items-center mb-4 shrink-0">
          <div className="flex gap-2">
            {!isRecording && (
                <div className="flex bg-gray-900 rounded-2xl p-1 border-2 border-gray-700">
                    <button onClick={() => setTranscriptionMode('cloud')} className={`px-4 py-2 text-xs font-black rounded-xl transition-all ${transcriptionMode === 'cloud' ? 'bg-blue-600 text-white shadow-md' : 'text-gray-500'}`}>AI MODE</button>
                    <button onClick={() => setTranscriptionMode('device')} className={`px-4 py-2 text-xs font-black rounded-xl transition-all ${transcriptionMode === 'device' ? 'bg-green-600 text-white shadow-md' : 'text-gray-500'}`}>LOCAL</button>
                </div>
            )}
          </div>

          <div className="flex gap-2">
               {isRecording && (
                   <button 
                    onClick={() => setActiveView(activeView === 'transcript' ? 'notebook' : 'transcript')}
                    className={`flex items-center gap-2 px-5 py-3 rounded-2xl font-black uppercase text-xs border-2 transition-all ${activeView === 'notebook' ? 'bg-purple-600 border-purple-400 text-white shadow-lg' : 'bg-gray-700 border-gray-600 text-gray-400'}`}
                   >
                       {activeView === 'notebook' ? <BrainCircuitIcon className="w-5 h-5"/> : <BookOpenIcon className="w-5 h-5"/>}
