      <div className="flex-grow flex flex-col overflow-hidden gap-4">
        {activeView === 'transcript' ? (
            <div className="flex-grow flex flex-col">
                <div className="flex flex-col items-center space-y-4 py-6 shrink-0">
                    <button
                        onClick={isRecording ? () => stopRecording() : startRecording}
                        className={`flex items-center justify-center w-32 h-32 sm:w-40 sm:h-40 rounded-full shadow-2xl transition-all duration-300 ease-in-out border-8 ${
                            isRecording ? 'bg-red-600 animate-pulse border-red-500' : transcriptionMode === 'cloud' ? 'bg-blue-600 border-blue-500' : 'bg-green-600 border-green-500'
                        }`}
