            <LectureNotebook 
                onUpdate={setNotebookData} 
                initialData={notebookData} 
                startTime={recordingStartTimeRef.current} 
                isRecording={isRecording}
                courseMaterials={[]}
            />
        )}
      </div>

      <div className="mt-4 flex gap-3 shrink-0">
          {isRecording ? (
