        if (filter === 'doc') results = results.filter(m => m.type === 'document' || m.type === 'web');

        if (searchQuery.trim()) {
            const q = searchQuery.toLowerCase();
            results = results.filter(m => 
                m.title.toLowerCase().includes(q) || 
                (m.tags && m.tags.some(t => t.toLowerCase().includes(q)))
