const MediaPreviewModal: React.FC<{
    memory: AnyMemory;
    onClose: () => void;
}> = ({ memory, onClose }) => {
    const [isPlaying, setIsPlaying] = useState(false);
    const [isGenerating, setIsGenerating] = useState(false);
    const audioContextRef = useRef<AudioContext | null>(null);
    const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);

    useEffect(() => {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        return () => {
            audioSourceRef.current?.stop();
            audioContextRef.current?.close();
        };
    }, []);

    const toggleAudio = async () => {
        if (isPlaying) {
            audioSourceRef.current?.stop();
            setIsPlaying(false);
            return;
        }

        const textToRead = (memory as VoiceMemory).transcript || (memory as DocumentMemory).extractedText || memory.title;
        if (!textToRead) return;

        setIsGenerating(true);
        try {
            const audioB64 = await generateSpeechFromText(textToRead);
            if (audioB64 && audioContextRef.current) {
                const audioData = decode(audioB64);
                const audioBuffer = await decodeAudioData(audioData, audioContextRef.current, 24000, 1);

                const source = audioContextRef.current.createBufferSource();
                source.buffer = audioBuffer;
                source.connect(audioContextRef.current.destination);
                source.onended = () => setIsPlaying(false);
                source.start(0);
                audioSourceRef.current = source;
                setIsPlaying(true);
            }
        } catch (e) {
            console.error("Audio playback error", e);
        } finally {
            setIsGenerating(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black z-[100] flex flex-col p-4 animate-fade-in" style={{ paddingTop: 'calc(var(--sat) + 1rem)', paddingBottom: 'calc(var(--sab) + 1rem)' }}>
