                    <p className="text-xs font-bold text-blue-400 uppercase tracking-widest">{new Date(memory.date).toLocaleDateString()}</p>
                </div>
                <button onClick={onClose} className="p-3 bg-gray-800 rounded-xl text-white">
                    <XIcon className="w-8 h-8" />
                </button>
            </header>

            <div className="flex-grow flex flex-col items-center justify-center overflow-hidden bg-gray-900 rounded-3xl border-2 border-gray-800 p-4 relative">
                {memory.type === 'voice' && (
                    <div className="w-full max-w-md flex flex-col items-center gap-6">
                        <button 
                            onClick={toggleAudio}
                            disabled={isGenerating}
                            className={`w-24 h-24 rounded-full flex items-center justify-center shadow-2xl transition-all active:scale-90 ${isPlaying ? 'bg-red-600 animate-pulse' : 'bg-blue-600'}`}
                        >
                            {isGenerating ? <Loader2Icon className="w-12 h-12 animate-spin text-white" /> : 
                             isPlaying ? <StopCircleIcon className="w-12 h-12 text-white" /> : 
                             <PlayIcon className="w-12 h-12 text-white ml-1" />}
                        </button>

                        <div className="w-full bg-gray-800 p-5 rounded-2xl border-2 border-gray-700 max-h-60 overflow-y-auto">
                            <p className="text-lg text-white leading-relaxed font-bold">{(memory as VoiceMemory).transcript}</p>
                        </div>
                        <p className="text-blue-400 font-black text-xs uppercase tracking-widest">{isPlaying ? 'Reading Note Aloud...' : 'Tap to listen'}</p>
                    </div>
                )}

                {memory.type === 'video' && (
                    <video src={(memory as VideoItemMemory).videoDataUrl} controls autoPlay className="max-w-full max-h-full rounded-xl shadow-2xl" />
                )}

                {memory.type === 'item' && (
                    <img src={(memory as PhysicalItemMemory).imageDataUrl} className="max-w-full max-h-full object-contain rounded-xl shadow-2xl" alt={memory.title} />
                )}

                {memory.type === 'document' && (
                    <div className="flex flex-col gap-4 w-full h-full overflow-hidden">
                        <div className="h-1/2 bg-black rounded-xl overflow-hidden flex items-center justify-center">
                            <img src={(memory as DocumentMemory).imageDataUrl} className="max-w-full max-h-full object-contain" />
                        </div>
                        <div className="h-1/2 bg-gray-800 p-4 rounded-xl overflow-y-auto border-2 border-gray-700 relative">
                             <button 
                                onClick={toggleAudio}
                                className="absolute top-2 right-2 p-3 bg-teal-600 text-white rounded-xl shadow-lg"
                             >
                                {isPlaying ? <StopCircleIcon className="w-6 h-6"/> : <Volume2Icon className="w-6 h-6"/>}
                             </button>
                             <h4 className="text-blue-400 font-black uppercase text-xs mb-2">Extracted Text</h4>
                             <p className="text-white text-base leading-relaxed font-bold">{(memory as DocumentMemory).extractedText}</p>
                        </div>
                    </div>
                )}

                {memory.type === 'web' && (
                    <div className="text-center space-y-6">
                        <GlobeIcon className="w-16 h-16 text-teal-400 mx-auto" />
                        <a href={(memory as any).url} target="_blank" className="inline-block px-8 py-4 bg-teal-600 text-white font-black rounded-2xl text-xl">OPEN WEBSITE</a>
                    </div>
                )}
            </div>

            <div className="mt-4 grid grid-cols-2 gap-3 shrink-0">
                <button 
                    onClick={() => generatePDF(memory.title, (memory as any).transcript || (memory as any).extractedText || '', (memory as any).imageDataUrl || '')}
                    className="flex items-center justify-center gap-2 py-4 bg-gray-800 text-white font-black rounded-2xl text-sm"
                >
