                    >
                        {opt.label}
                    </button>
                ))}
            </div>

            <main className="flex-grow overflow-y-auto space-y-3 pb-24 px-1">
                {filteredMemories.length === 0 ? (
                    <div className="text-center py-16 bg-gray-800/30 rounded-3xl border-2 border-dashed border-gray-700">
                        <p className="text-lg text-gray-600 font-black uppercase tracking-tighter">No Files Found</p>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {filteredMemories.map(mem => (
                            <FileItem 
                                key={mem.id} 
                                memory={mem} 
                                onDelete={onDelete} 
                                onPreview={(m) => setPreviewMemory(m)}
                            />
                        ))}
                    </div>
                )}
            </main>
        </div>
    );
};

