// MediaPreviewDrawer: Slides up from bottom like a mobile sheet
const MediaPreviewDrawer: React.FC<{
    memory: AnyMemory;
    onClose: () => void;
}> = ({ memory, onClose }) => {
    const [isPlaying, setIsPlaying] = useState(false);
    const [isGenerating, setIsGenerating] = useState(false);
    const audioContextRef = useRef<AudioContext | null>(null);
    const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);
    const nativeAudioRef = useRef<HTMLAudioElement | null>(null);

    useEffect(() => {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        return () => {
            audioSourceRef.current?.stop();
            audioContextRef.current?.close();
        };
    }, []);

    const toggleAudio = async () => {
        if (isPlaying) {
            if (nativeAudioRef.current) { nativeAudioRef.current.pause(); nativeAudioRef.current.currentTime = 0; }
            audioSourceRef.current?.stop();
            setIsPlaying(false);
            return;
        }

        // 1. Try to play original recording if available
        const voiceMem = memory as VoiceMemory;
        if (voiceMem.audioDataUrl) {
            if (!nativeAudioRef.current) {
                nativeAudioRef.current = new Audio(voiceMem.audioDataUrl);
                nativeAudioRef.current.onended = () => setIsPlaying(false);
            }
            nativeAudioRef.current.play();
            setIsPlaying(true);
            return;
        }

        // 2. Fallback to AI TTS if no original recording
        const textToRead = (memory as VoiceMemory).transcript || (memory as DocumentMemory).extractedText || memory.title;
        if (!textToRead) return;

        setIsGenerating(true);
        try {
            const audioB64 = await generateSpeechFromText(textToRead);
            if (audioB64 && audioContextRef.current) {
                const audioData = decode(audioB64);
                const audioBuffer = await decodeAudioData(audioData, audioContextRef.current, 24000, 1);
                const source = audioContextRef.current.createBufferSource();
                source.buffer = audioBuffer;
                source.connect(audioContextRef.current.destination);
                source.onended = () => setIsPlaying(false);
                source.start(0);
                audioSourceRef.current = source;
                setIsPlaying(true);
            }
        } catch (e) {
            console.error("Playback error", e);
        } finally {
            setIsGenerating(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black/80 z-[110] flex flex-col justify-end animate-fade-in" onClick={onClose}>
            <div 
                className="bg-gray-800 rounded-t-[2rem] w-full max-h-[90vh] flex flex-col p-5 border-t-4 border-gray-600 animate-slide-up shadow-[0_-10px_50px_rgba(0,0,0,0.5)]"
                onClick={e => e.stopPropagation()}
            >
                <div className="w-12 h-1.5 bg-gray-600 rounded-full mx-auto mb-6 shrink-0" />

                <header className="flex justify-between items-start mb-6 shrink-0">
                    <div className="overflow-hidden">
                        <h2 className="text-xl font-black text-white uppercase truncate">{memory.title}</h2>
                        <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{new Date(memory.date).toLocaleDateString()}</span>
                    </div>
                    <button onClick={onClose} className="p-3 bg-gray-700 rounded-2xl"><XIcon className="w-6 h-6 text-white" /></button>
                </header>

                <div className="flex-grow overflow-y-auto space-y-6 pb-6 min-h-0">
                    {memory.type === 'voice' && (
                        <div className="flex flex-col items-center gap-6">
                            <button 
                                onClick={toggleAudio}
                                disabled={isGenerating}
                                className={`w-20 h-20 rounded-full flex items-center justify-center shadow-xl active:scale-90 transition-all ${isPlaying ? 'bg-red-600' : 'bg-blue-600'}`}
                            >
                                {isGenerating ? <Loader2Icon className="w-10 h-10 animate-spin text-white" /> : 
                                 isPlaying ? <StopCircleIcon className="w-10 h-10 text-white" /> : 
                                 <PlayIcon className="w-10 h-10 text-white ml-1" />}
                            </button>
                            <p className="text-blue-400 font-black text-[10px] uppercase tracking-widest">{isPlaying ? 'Playing original audio...' : (memory as VoiceMemory).audioDataUrl ? 'Listen to recording' : 'Read aloud with AI'}</p>

                            <div className="w-full bg-gray-900 p-4 rounded-2xl border border-gray-700">
                                <h4 className="text-gray-500 text-[10px] font-black uppercase mb-2">Transcript</h4>
                                <p className="text-base text-gray-200 leading-relaxed font-bold">{(memory as VoiceMemory).transcript}</p>
                            </div>
                        </div>
                    )}

                    {memory.type === 'video' && (
                        <div className="space-y-4">
                            <video src={(memory as VideoItemMemory).videoDataUrl} controls autoPlay className="w-full rounded-2xl shadow-xl border border-gray-700" />
                            {(memory as VideoItemMemory).transcript && (
                                <div className="bg-gray-900 p-4 rounded-2xl border border-gray-700">
                                    <p className="text-gray-300 text-sm leading-relaxed">{(memory as VideoItemMemory).transcript}</p>
                                </div>
                            )}
                        </div>
                    )}

                    {memory.type === 'item' && (
                        <div className="space-y-4">
                            <img src={(memory as PhysicalItemMemory).imageDataUrl} className="w-full max-h-64 object-contain rounded-2xl shadow-xl bg-black" alt={memory.title} />
                            {(memory as PhysicalItemMemory).description && (
                                <div className="bg-gray-900 p-4 rounded-2xl border border-gray-700">
                                    <p className="text-gray-300 text-sm">{(memory as PhysicalItemMemory).description}</p>
                                </div>
                            )}
                        </div>
                    )}

                    {memory.type === 'document' && (
                        <div className="space-y-4">
