                    <button 
                        key={id}
                        onClick={() => setFilter(id as any)}
                        className={`px-4 py-1.5 rounded-lg font-black text-[9px] uppercase tracking-widest transition-all ${filter === id ? 'bg-blue-600 text-white' : 'bg-gray-800 text-gray-500'}`}
