import React, { useState, useRef, useCallback, useEffect } from 'react';
import { LiveSession, Modality } from '@google/genai';
import { MicIcon, StopCircleIcon, SaveIcon, BrainCircuitIcon, EyeIcon, CheckIcon, BookOpenIcon, XIcon, Loader2Icon } from './Icons';
import type { VoiceMemory, TranscriptSegment, NotebookData } from '../types';
import { getCurrentLocation } from '../utils/location';
import { getGeminiInstance } from '../utils/gemini';
import { analyzeVoiceNote } from '../services/geminiService';

interface RecorderProps {
  onSave: (recording: Omit<VoiceMemory, 'id' | 'date'>) => void;
  onCancel: () => void;
  titlePlaceholder: string;
  saveButtonText: string;
  enableDiarization?: boolean;
}

interface IWindow extends Window {
  webkitSpeechRecognition: any;
  SpeechRecognition: any;
}

const Recorder: React.FC<RecorderProps> = ({ onSave, onCancel, titlePlaceholder, saveButtonText, enableDiarization }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [liveTranscript, setLiveTranscript] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [recordingTitle, setRecordingTitle] = useState('');
  const [extractedActionItems, setExtractedActionItems] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [transcriptionMode, setTranscriptionMode] = useState<'cloud' | 'device'>('cloud'); 
  const [audioDataUrl, setAudioDataUrl] = useState<string | undefined>(undefined);

  const finalTranscriptRef = useRef<string>('');
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  // Gemini Live Refs
  const sessionPromiseRef = useRef<Promise<LiveSession> | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  const recognitionRef = useRef<any>(null);
  const wakeLockRef = useRef<WakeLockSentinel | null>(null);

  const playBeep = useCallback((frequency: number, type: 'sine' | 'square' = 'sine', duration: number = 0.15) => {
    try {
        const Ctx = window.AudioContext || (window as any).webkitAudioContext;
        if (!Ctx) return;
        const ctx = new Ctx();
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.type = type;
        osc.frequency.setValueAtTime(frequency, ctx.currentTime);
        gain.gain.setValueAtTime(0.1, ctx.currentTime);
        gain.gain.exponentialRampToValueAtTime(0.00001, ctx.currentTime + duration);
        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.start();
        osc.stop(ctx.currentTime + duration);
    } catch (e) {}
  }, []);

  const requestWakeLock = async () => {
    if ('wakeLock' in navigator) {
      try { wakeLockRef.current = await navigator.wakeLock.request('screen'); } catch (err) {}
    }
  };

  const releaseWakeLock = async () => {
    if (wakeLockRef.current) {
      try { await wakeLockRef.current.release(); wakeLockRef.current = null; } catch (err) {}
    }
  };

  const startRecording = async () => {
    if (isRecording) return;
    setError(null);
    setLiveTranscript('');
    finalTranscriptRef.current = '';
    audioChunksRef.current = [];
    setAudioDataUrl(undefined);
    await requestWakeLock();
    playBeep(880, 'sine', 0.2);

    try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        // Capture original audio blob
        const mediaRecorder = new MediaRecorder(stream);
        mediaRecorderRef.current = mediaRecorder;
        mediaRecorder.ondataavailable = (e) => {
            if (e.data.size > 0) audioChunksRef.current.push(e.data);
        };
        mediaRecorder.onstop = () => {
            const blob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
            const reader = new FileReader();
            reader.onloadend = () => setAudioDataUrl(reader.result as string);
            reader.readAsDataURL(blob);
        };
        mediaRecorder.start();

        if (transcriptionMode === 'device') {
            startNativeRecording(stream);
        } else {
            startCloudRecording(stream);
        }
    } catch (err) {
        setError('Microphone access denied.');
        await releaseWakeLock();
    }
  };

  const startNativeRecording = (stream: MediaStream) => {
      const win = window as unknown as IWindow;
      const SpeechRecognition = win.SpeechRecognition || win.webkitSpeechRecognition;
      if (!SpeechRecognition) {
          setError("Device transcription not supported.");
          return;
      }
      const recognition = new SpeechRecognition();
      recognition.continuous = true;
      recognition.interimResults = true;
      recognition.onresult = (event: any) => {
          let interimTranscript = '';
          for (let i = event.resultIndex; i < event.results.length; ++i) {
              if (event.results[i].isFinal) finalTranscriptRef.current += event.results[i][0].transcript + ' ';
              else interimTranscript += event.results[i][0].transcript;
          }
          setLiveTranscript(finalTranscriptRef.current + interimTranscript);
      };
      recognition.start();
      recognitionRef.current = recognition;
      setIsRecording(true);
  };

  const startCloudRecording = async (stream: MediaStream) => {
    const ai = getGeminiInstance();
    if (!ai) { setError("AI unavailable."); return; }
    try {
      setIsRecording(true);
      const context = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextRef.current = context;
      sessionPromiseRef.current = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        callbacks: {
          onopen: () => {
            const source = context.createMediaStreamSource(stream);
            const scriptProcessor = context.createScriptProcessor(4096, 1, 1);
            scriptProcessorRef.current = scriptProcessor;
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                let s = Math.max(-1, Math.min(1, inputData[i]));
                int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
              }
              let binary = '';
              const bytes = new Uint8Array(int16.buffer);
              for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
              sessionPromiseRef.current?.then((s) => s.sendRealtimeInput({ media: { data: btoa(binary), mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(context.destination);
          },
          onmessage: (m) => {
            if (m.serverContent?.inputTranscription) {
              const text = m.serverContent.inputTranscription.text;
              finalTranscriptRef.current += text;
              setLiveTranscript(prev => prev + text);
            }
          },
          onerror: () => {},
          onclose: () => {},
        },
        config: { responseModalities: [Modality.AUDIO], inputAudioTranscription: {} },
      });
    } catch (err) { setIsRecording(false); }
  };

  const stopRecording = useCallback(async (shouldSave: boolean = true) => {
    if (!isRecording) return;
    setIsRecording(false); 
    playBeep(440, 'sine', 0.2);
    await releaseWakeLock();

    mediaRecorderRef.current?.stop();
    if (transcriptionMode === 'cloud') {
        mediaStreamRef.current?.getTracks().forEach(t => t.stop());
        scriptProcessorRef.current?.disconnect();
        audioContextRef.current?.close();
        sessionPromiseRef.current?.then(s => s.close());
    } else {
        recognitionRef.current?.stop();
    }

    if (shouldSave && finalTranscriptRef.current.trim()) {
      setIsSaving(true);
      setIsAnalyzing(true);
      try {
        const analysis = await analyzeVoiceNote(finalTranscriptRef.current);
        setRecordingTitle(analysis.title || titlePlaceholder);
        setExtractedActionItems(analysis.actionItems || []);
      } catch (error) {
        setRecordingTitle(titlePlaceholder);
      } finally {
        setIsAnalyzing(false);
      }
    } else if (!shouldSave) {
      onCancel();
    }
  }, [isRecording, onCancel, titlePlaceholder, playBeep, transcriptionMode]);

  const handleSave = async () => {
    if (!recordingTitle.trim() || !finalTranscriptRef.current.trim()) return;
    const location = await getCurrentLocation();
    onSave({
      type: 'voice',
      title: recordingTitle,
      transcript: finalTranscriptRef.current,
      audioDataUrl,
      actionItems: extractedActionItems.map(text => ({ text, done: false })),
      ...(location && { location }),
    } as Omit<VoiceMemory, 'id'|'date'>);
  };

  if (isSaving) {
    return (
      <div className="bg-gray-800 p-4 rounded-2xl shadow-2xl space-y-3 border-2 border-blue-500 h-full flex flex-col overflow-hidden">
        <h2 className="text-lg font-black text-white uppercase shrink-0">Review Note</h2>

        <div className="shrink-0 space-y-2">
          <input
              type="text"
              value={recordingTitle}
              onChange={(e) => setRecordingTitle(e.target.value)}
              className="w-full bg-gray-700 text-white text-base p-3 rounded-xl border-2 border-gray-600 outline-none font-bold"
              placeholder="Title"
          />
          {audioDataUrl && (
              <div className="bg-gray-900 p-2 rounded-xl border border-gray-700">
                  <audio src={audioDataUrl} controls className="w-full h-8" />
              </div>
          )}
        </div>

        <div className="flex-grow bg-gray-900 p-4 rounded-xl border border-gray-700 overflow-y-auto text-sm text-gray-300 whitespace-pre-wrap font-medium">
          {isAnalyzing ? (
            <div className="flex items-center gap-2 text-blue-400 font-bold">
                <Loader2Icon className="w-4 h-4 animate-spin"/>
                Analyzing your note...
            </div>
          ) : finalTranscriptRef.current}
        </div>

        <div className="flex flex-col gap-2 shrink-0 pt-2">
          <button 
            onClick={handleSave} 
            className="flex items-center justify-center gap-3 py-4 bg-blue-600 text-white font-black rounded-2xl uppercase shadow-lg active:scale-95 transition-transform"
          >
            <SaveIcon className="w-6 h-6"/> {saveButtonText}
          </button>
          <button 
            onClick={onCancel} 
            className="py-3 bg-gray-700 text-gray-400 font-black rounded-xl uppercase active:scale-95 transition-transform"
          >
            Discard
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-gray-800 p-4 rounded-2xl shadow-2xl border-2 border-gray-700 h-full flex flex-col overflow-hidden">
      <div className="flex justify-between items-center mb-4 shrink-0">
          <div className="flex bg-gray-900 rounded-xl p-1 border border-gray-700">
              <button onClick={() => setTranscriptionMode('cloud')} className={`px-3 py-1.5 text-[10px] font-black rounded-lg transition-all ${transcriptionMode === 'cloud' ? 'bg-blue-600 text-white' : 'text-gray-500'}`}>AI</button>
              <button onClick={() => setTranscriptionMode('device')} className={`px-3 py-1.5 text-[10px] font-black rounded-lg transition-all ${transcriptionMode === 'device' ? 'bg-green-600 text-white' : 'text-gray-500'}`}>LOCAL</button>
          </div>
      </div>
      <div className="flex-grow flex flex-col items-center justify-center gap-6 overflow-hidden">
        <button
            onClick={isRecording ? () => stopRecording() : startRecording}
            className={`flex items-center justify-center w-32 h-32 rounded-full shadow-2xl transition-all border-4 ${
                isRecording ? 'bg-red-600 animate-pulse border-red-500' : transcriptionMode === 'cloud' ? 'bg-blue-600 border-blue-500' : 'bg-green-600 border-green-500'
            }`}
        >
            {isRecording ? <StopCircleIcon className="w-14 h-14 text-white" /> : <MicIcon className="w-14 h-14 text-white" />}
        </button>
        <div className="w-full bg-gray-900 p-5 rounded-2xl border border-gray-700 overflow-y-auto max-h-48 shadow-inner">
            <p className="text-lg text-gray-200 whitespace-pre-wrap font-bold leading-snug">
                {liveTranscript || "Tap to start recording..."}
            </p>
        </div>
      </div>
      <div className="mt-4 flex gap-2 shrink-0">
          {isRecording ? (
             <button onClick={() => stopRecording()} className="flex-1 py-4 bg-red-600 text-white font-black rounded-2xl uppercase shadow-lg active:scale-95">FINISH</button>
          ) : (
             <button onClick={onCancel} className="flex-1 py-4 bg-gray-700 text-gray-400 font-bold rounded-2xl uppercase active:scale-95">Cancel</button>
          )}
      </div>
    </div>
  );
};

export default Recorder;

