    const [transcript, setTranscript] = useState(''); 
    const [imageDataUrl, setImageDataUrl] = useState<string | null>(null);
    const [videoDataUrl, setVideoDataUrl] = useState<string | null>(null);
    const [stream, setStream] = useState<MediaStream | null>(null);
    const [isRecording, setIsRecording] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);

    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const mediaRecorderRef = useRef<MediaRecorder | null>(null);
    const sessionPromiseRef = useRef<Promise<LiveSession> | null>(null);
    const liveTranscriptRef = useRef('');

    const stopCamera = useCallback(() => {
        if (stream) {
            stream.getTracks().forEach(track => track.stop());
            setStream(null);
        }
    }, [stream]);

    useEffect(() => {
        return () => { stopCamera(); };
    }, [stopCamera]);

    const startCamera = async () => {
        if (isRecording) await stopRecording();
        stopCamera();
        setImageDataUrl(null);
        setVideoDataUrl(null);
        setError(null);
        try {
            const mediaStream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' }, audio: true });
            setStream(mediaStream);
        } catch (err) {
            console.error("Camera access error:", err);
            setError("Could not access camera/mic. Please check permissions.");
        }
    };

    useEffect(() => {
        if (stream && videoRef.current) {
            videoRef.current.srcObject = stream;
        }
    }, [stream]);

    const takePicture = () => {
        if (videoRef.current && canvasRef.current) {
            const video = videoRef.current;
            const canvas = canvasRef.current;
            canvas.width = video.videoWidth;
            canvas.height = video.videoHeight;
            canvas.getContext('2d')?.drawImage(video, 0, 0, video.videoWidth, video.videoHeight);
            const dataUrl = canvas.toDataURL('image/jpeg');
            setImageDataUrl(dataUrl);
            stopCamera();
        }
    };

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (e) => {
                const result = e.target?.result as string;
                if (mode === 'photo') setImageDataUrl(result);
                else setVideoDataUrl(result);
                stopCamera();
            };
            if(mode === 'photo') reader.readAsDataURL(file);
            else if (file.type.startsWith('video/')) reader.readAsDataURL(file);
            else setError('Please select a valid video file.');
        }
    };

    const startRecording = async () => {
        if (!stream) return;

        const ai = getGeminiInstance();
        if (!ai) {
          setError("AI features are not available.");
          return;
        }

        setIsRecording(true);
        setVideoDataUrl(null);
        liveTranscriptRef.current = '';
        setTranscript('');

        const chunks: Blob[] = [];
        mediaRecorderRef.current = new MediaRecorder(stream);
        mediaRecorderRef.current.ondataavailable = (event) => chunks.push(event.data);
        mediaRecorderRef.current.onstop = () => {
            const blob = new Blob(chunks, { type: 'video/webm' });
            const reader = new FileReader();
            reader.onloadend = () => setVideoDataUrl(reader.result as string);
            reader.readAsDataURL(blob);
        };
        mediaRecorderRef.current.start();

        const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
        sessionPromiseRef.current = ai.live.connect({
            model: 'gemini-2.5-flash-native-audio-preview-09-2025',
            callbacks: {
              onopen: () => {
                const source = audioContext.createMediaStreamSource(stream);
                const scriptProcessor = audioContext.createScriptProcessor(4096, 1, 1);
                scriptProcessor.onaudioprocess = (e) => {
                  const inputData = e.inputBuffer.getChannelData(0);
                  const int16 = new Int16Array(inputData.length);
                  for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
                  let binary = '';
                  const bytes = new Uint8Array(int16.buffer);
                  for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
                  sessionPromiseRef.current?.then((s) => s.sendRealtimeInput({ media: { data: btoa(binary), mimeType: 'audio/pcm;rate=16000' } }));
                };
                source.connect(scriptProcessor);
                scriptProcessor.connect(audioContext.destination);
              },
              onmessage: (message) => {
                if (message.serverContent?.inputTranscription) {
                  const text = message.serverContent.inputTranscription.text;
                  liveTranscriptRef.current += text;
                  setTranscript(prev => prev + text);
                }
              },
              onerror: (e) => { console.error(e); setError('Transcription error.'); },
              onclose: () => {},
            },
            config: { responseModalities: [Modality.AUDIO], inputAudioTranscription: {} },
        });
    };

    const stopRecording = async () => {
        setIsRecording(false);
        mediaRecorderRef.current?.stop();
        if (sessionPromiseRef.current) {
            const session = await sessionPromiseRef.current;
            session.close();
        }
        stopCamera();
    };

    const handleGenerateTitle = async () => {
        const content = description || transcript;
        if (!content.trim()) return;
        setIsGeneratingTitle(true);
        setTitle(await generateTitleForContent(content));
        setIsGeneratingTitle(false);
    }

    const handleSave = async () => {
        const hasMedia = imageDataUrl || videoDataUrl;
        if (!hasMedia || !title.trim()) return;

        const location = await getCurrentLocation();
        const tagList = tags.split(',').map(t => t.trim()).filter(Boolean);

        if (mode === 'video' && videoDataUrl) {
            const newMemory: Omit<VideoItemMemory, 'id' | 'date' | 'category'> = {
                type: 'video', title, description,
                videoDataUrl, transcript, ...(location && { location }), tags: tagList,
            };
            onSave(newMemory);
        } else if (mode === 'photo' && imageDataUrl) {
            const newMemory: Omit<PhysicalItemMemory, 'id' | 'date' | 'category'> = {
                type: 'item', title, description,
                imageDataUrl, ...(location && { location }),
                ...(voiceNote.trim() && { voiceNote: { transcript: voiceNote.trim() } }),
                tags: tagList,
            };
            onSave(newMemory);
        }
        onClose();
    };

    const isSaveDisabled = !title.trim() || (mode === 'photo' && !imageDataUrl) || (mode === 'video' && !videoDataUrl);

    return (
        <div className="fixed inset-0 bg-black/90 flex flex-col justify-center items-center z-[120] p-4">
            <div className="bg-gray-800 rounded-[2.5rem] shadow-2xl w-full max-w-2xl max-h-[95vh] flex flex-col border-4 border-gray-600 overflow-hidden">
                <header className="flex justify-between items-center p-6 border-b-4 border-gray-700 shrink-0">
                    <h2 className="text-xl font-black text-white flex items-center gap-3 uppercase"><CameraIcon className="w-8 h-8"/> Item Memory</h2>
                    <button onClick={onClose} className="p-3 rounded-2xl bg-gray-700 active:scale-90 transition-transform"><XIcon className="w-6 h-6"/></button>
                </header>

                <main className="flex-grow p-6 space-y-6 overflow-y-auto scroll-smooth">
                    <div className="flex justify-center bg-gray-900 p-1.5 rounded-2xl border border-gray-700">
                        <button onClick={() => { setMode('photo'); stopCamera(); }} className={`flex-1 py-3 font-black rounded-xl text-xs uppercase tracking-widest transition-all ${mode === 'photo' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500'}`}>Photo</button>
                        <button onClick={() => { setMode('video'); stopCamera(); }} className={`flex-1 py-3 font-black rounded-xl text-xs uppercase tracking-widest transition-all ${mode === 'video' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500'}`}>Video</button>
                    </div>

                    <div className="w-full aspect-square bg-gray-900 rounded-[2rem] flex items-center justify-center relative overflow-hidden border-2 border-gray-700 shadow-inner">
                        <canvas ref={canvasRef} className="hidden" />
                        {imageDataUrl && mode === 'photo' ? <img src={imageDataUrl} alt="Item" className="w-full h-full object-contain" />
                        : videoDataUrl && mode === 'video' ? <video src={videoDataUrl} controls className="w-full h-full object-contain" />
                        : stream ? <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
                        : (
                            <div className="text-center text-gray-700">
                                {mode === 'photo' ? <CameraIcon className="w-20 h-20 mx-auto" /> : <VideoIcon className="w-20 h-20 mx-auto" />}
                                <p className="mt-4 font-black uppercase text-xs tracking-tighter">Capture a {mode}</p>
                            </div>
                        )}
                    </div>

                    <div className="flex gap-3 justify-center">
                        {isRecording ? (
                            <button onClick={stopRecording} className="px-8 py-4 bg-red-600 text-white font-black rounded-2xl shadow-lg active:scale-95 flex items-center gap-3 uppercase text-sm">
                                <StopCircleIcon className="w-6 h-6"/> STOP
                            </button>
                        ) : stream ? (
                            mode === 'photo' ? (
                                <button onClick={takePicture} className="px-8 py-4 bg-blue-600 text-white font-black rounded-2xl shadow-lg active:scale-95 flex items-center gap-3 uppercase text-sm">
                                    <CameraIcon className="w-6 h-6"/> CAPTURE
                                </button>
                            ) : (
                                <button onClick={startRecording} className="px-8 py-4 bg-blue-600 text-white font-black rounded-2xl shadow-lg active:scale-95 flex items-center gap-3 uppercase text-sm">
                                    <VideoIcon className="w-6 h-6"/> RECORD
                                </button>
                            )
                        ) : (
                            <>
                                <button onClick={startCamera} className="flex-1 py-4 bg-gray-700 text-white font-black rounded-2xl flex items-center justify-center gap-3 uppercase text-xs">
                                    <CameraIcon className="w-5 h-5"/> Camera
                                </button>
                                <button onClick={() => fileInputRef.current?.click()} className="flex-1 py-4 bg-gray-700 text-white font-black rounded-2xl flex items-center justify-center gap-3 uppercase text-xs">
                                    <UploadIcon className="w-5 h-5"/> File
                                </button>
                                <input type="file" ref={fileInputRef} onChange={handleFileChange} accept={mode === 'photo' ? "image/*" : "video/*"} className="hidden" />
                            </>
                        )}
                    </div>

                    {error && <p className="text-center text-red-400 font-bold bg-red-900/20 p-3 rounded-xl">{error}</p>}

                    <div className="space-y-4">
                        <div>
                            <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Details</label>
                            <textarea value={description} onChange={e => setDescription(e.target.value)} rows={3} placeholder="What is this? Where is it located?" className="w-full bg-gray-900 text-white text-base p-4 rounded-2xl border-2 border-gray-700 outline-none focus:border-blue-600 font-bold shadow-inner"/>
                        </div>

                        <div>
                            <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Title</label>
                             <div className="flex gap-2">
                               <input type="text" value={title} onChange={e => setTitle(e.target.value)} placeholder="Title" className="flex-grow bg-gray-900 text-white text-base p-4 rounded-2xl border-2 border-gray-700 outline-none focus:border-blue-600 font-bold shadow-inner"/>
                               <button onClick={handleGenerateTitle} disabled={isGeneratingTitle || (!description.trim() && !transcript.trim())} className="p-4 bg-purple-600 text-white rounded-2xl disabled:bg-gray-700 shadow-lg active:scale-95 transition-all">
                                   {isGeneratingTitle ? <Loader2Icon className="w-6 h-6 animate-spin"/> : <BrainCircuitIcon className="w-6 h-6"/>}
                               </button>
                            </div>
                        </div>

                        <div>
                            <MiniRecorder onTranscriptChange={setVoiceNote} />
                            {(voiceNote || transcript) && (
                                <div className="mt-3 bg-gray-900 p-4 rounded-2xl border border-gray-700 shadow-inner">
                                    <p className="text-xs text-gray-400 leading-relaxed font-medium">{voiceNote || transcript}</p>
                                </div>
                            )}
                        </div>
                    </div>
                </main>

                <footer className="p-6 flex flex-col gap-3 border-t-4 border-gray-700 bg-gray-800 shrink-0">
                    <button onClick={handleSave} disabled={isSaveDisabled} className="flex items-center justify-center gap-3 py-5 bg-blue-600 text-white font-black rounded-2xl text-lg uppercase shadow-xl disabled:bg-gray-700 active:scale-95 transition-all">
                        <SaveIcon className="w-7 h-7"/> SAVE
                    </button>
                    <button onClick={onClose} className="py-4 text-gray-500 font-black uppercase text-xs tracking-widest active:scale-95">Cancel</button>
                </footer>
            </div>
        </div>
    );
};

export default AddPhysicalItemModal;

import React, { useState, useEffect, useRef } from 'react';
import type { DocumentMemory } from '../types';
import { generateTitleForContent, extractTextFromImage } from '../services/geminiService';
import { getCurrentLocation } from '../utils/location';
import { generatePDF } from '../services/pdfService';
import { CameraIcon, UploadIcon, SaveIcon, XIcon, BrainCircuitIcon, Loader2Icon, FileTextIcon, CheckIcon } from './Icons';

interface AddDocumentModalProps {
    course?: string; 
    onSave: (memory: Omit<DocumentMemory, 'id'|'date'>) => void;
    onClose: () => void;
}

const AddDocumentModal: React.FC<AddDocumentModalProps> = ({ course, onSave, onClose }) => {
    const [title, setTitle] = useState('');
    const [imageDataUrl, setImageDataUrl] = useState<string | null>(null);
    const [extractedText, setExtractedText] = useState('');
    const [isLoading, setIsLoading] = useState<'camera'|'ocr'|'title'|null>(null);
    const [error, setError] = useState<string|null>(null);
    const [stream, setStream] = useState<MediaStream | null>(null);
    const [statusMessage, setStatusMessage] = useState(''); 

    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const titleInputRef = useRef<HTMLInputElement>(null);

    const stopCamera = React.useCallback(() => {
        if (stream) {
            stream.getTracks().forEach(track => track.stop());
            setStream(null);
        }
    }, [stream]);

    useEffect(() => { return () => { stopCamera(); }; }, [stopCamera]);

    useEffect(() => {
        if (extractedText && titleInputRef.current) {
            titleInputRef.current.focus();
        }
    }, [extractedText]);

    const startCamera = async () => {
        stopCamera();
        setImageDataUrl(null);
        setError(null);
        setIsLoading('camera');
        setStatusMessage("Starting camera...");
        try {
            const mediaStream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
            setStream(mediaStream);
            setStatusMessage("Camera started.");
        } catch (err) { 
            setError("Could not access camera."); 
            setStatusMessage("Error: Could not access camera.");
        }
        finally { setIsLoading(null); }
    };

    useEffect(() => { if (stream && videoRef.current) { videoRef.current.srcObject = stream; } }, [stream]);

    const takePicture = () => {
        if (videoRef.current && canvasRef.current) {
            const video = videoRef.current;
            const canvas = canvasRef.current;
            canvas.width = video.videoWidth;
            canvas.height = video.videoHeight;
            canvas.getContext('2d')?.drawImage(video, 0, 0, video.videoWidth, video.videoHeight);
            const dataUrl = canvas.toDataURL('image/jpeg');
            setImageDataUrl(dataUrl);
            stopCamera();
            setStatusMessage("Picture taken.");
        }
    };

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file && file.type.startsWith('image/')) {
            const reader = new FileReader();
            reader.onload = (e) => {
                setImageDataUrl(e.target?.result as string);
                stopCamera();
                setStatusMessage("Image uploaded.");
            };
            reader.readAsDataURL(file);
        } else {
            setError('Please select a valid image file.');
        }
    };

    const handleExtractText = async () => {
        if (!imageDataUrl) return;
        setIsLoading('ocr');
        setError(null);
        setStatusMessage("Extracting text...");
        try {
            const base64Data = imageDataUrl.split(',')[1];
            const mimeType = imageDataUrl.match(/data:([^;]+);/)?.[1] || 'image/jpeg';
            const text = await extractTextFromImage(base64Data, mimeType);
            setExtractedText(text);
            setStatusMessage("Text extracted.");
        } catch (e) { 
            setError("OCR Failed."); 
            setStatusMessage("Error.");
        }
        finally { setIsLoading(null); }
    };

    const handleGenerateTitle = async () => {
        if (!extractedText.trim()) return;
        setIsLoading('title');
        setTitle(await generateTitleForContent(extractedText));
        setIsLoading(null);
        setStatusMessage("Title generated.");
    };

    const handleSave = async () => {
        if (!imageDataUrl || !title.trim() || !extractedText.trim()) return;
        const location = await getCurrentLocation();
        onSave({ 
            type: 'document', 
            title, 
            imageDataUrl, 
            extractedText, 
            category: course ? 'college' : 'personal',
            course, 
            ...(location && { location }) 
        });
        onClose();
    };

    return (
        <div className="fixed inset-0 bg-black/90 flex flex-col justify-center items-center z-[130] p-4">
             <div className="bg-gray-800 rounded-[2.5rem] shadow-2xl w-full max-w-2xl max-h-[95vh] flex flex-col border-4 border-gray-600 overflow-hidden">
                <header className="flex justify-between items-center p-6 border-b-4 border-gray-700 shrink-0">
                    <h2 className="text-xl font-black text-white flex items-center gap-3 uppercase">
                        <FileTextIcon className="w-8 h-8"/> SCAN
                    </h2>
                    <button onClick={onClose} className="p-3 bg-gray-700 rounded-2xl active:scale-90 transition-transform"><XIcon className="w-6 h-6"/></button>
                </header>

                <div role="status" aria-live="polite" className="sr-only">
                    {statusMessage}
                </div>

                <div className="flex-grow overflow-y-auto p-6 space-y-6 scroll-smooth">
                    {extractedText ? (
                        <div className="space-y-6">
                            <div className="w-full bg-gray-900 rounded-2xl p-2 border border-gray-700 flex justify-center items-center shadow-inner">
                                <img src={imageDataUrl || ''} className="max-h-48 object-contain rounded-xl"/>
                            </div>

                            <div className="space-y-3">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Document Name</label>
                                <div className="flex gap-2">
                                    <input 
                                        ref={titleInputRef}
                                        type="text" 
                                        value={title} 
                                        onChange={e => setTitle(e.target.value)} 
                                        placeholder="Enter Title" 
                                        className="flex-grow bg-gray-900 text-white text-base p-4 rounded-2xl border-2 border-gray-700 outline-none focus:border-blue-600 font-bold shadow-inner"
                                    />
                                    <button onClick={handleGenerateTitle} className="p-4 bg-purple-600 text-white rounded-2xl shadow-lg active:scale-95">
                                        {isLoading === 'title' ? <Loader2Icon className="w-6 h-6 animate-spin"/> : <BrainCircuitIcon className="w-6 h-6"/>}
                                    </button>
                                </div>
                            </div>

                            <div className="space-y-3">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Text Content</label>
                                <textarea 
                                    value={extractedText} 
                                    onChange={e => setExtractedText(e.target.value)} 
                                    rows={8} 
                                    className="w-full bg-gray-900 text-white text-sm p-5 rounded-2xl border-2 border-gray-700 outline-none focus:border-blue-600 font-medium leading-relaxed shadow-inner"
                                />
                            </div>
                        </div>
                    ) : imageDataUrl ? (
                        <div className="space-y-6 text-center">
                            <div className="rounded-[2rem] overflow-hidden border-2 border-gray-700 shadow-2xl">
                                <img src={imageDataUrl} className="w-full max-h-80 object-contain bg-black" />
                            </div>
                            <div className="flex gap-3 justify-center">
                                <button onClick={() => setImageDataUrl(null)} className="flex-1 py-4 bg-gray-700 text-white font-black rounded-2xl uppercase text-xs">Retake</button>
                                <button onClick={handleExtractText} disabled={isLoading === 'ocr'} className="flex-grow py-4 bg-blue-600 text-white font-black rounded-2xl uppercase text-xs shadow-lg flex items-center justify-center gap-3">
                                     {isLoading === 'ocr' ? <Loader2Icon className="animate-spin w-5 h-5"/> : <BrainCircuitIcon className="w-5 h-5"/>}
                                     Extract Text
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="space-y-6 text-center">
                            <div className="w-full aspect-square bg-gray-900 rounded-[2.5rem] flex items-center justify-center relative overflow-hidden border-2 border-gray-700 shadow-inner">
                                <canvas ref={canvasRef} className="hidden" />
                                {stream ? <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
                                    : <CameraIcon className="w-24 h-24 mx-auto text-gray-700" />
                                }
                            </div>
                            {stream ? (
                                <button onClick={takePicture} className="px-10 py-5 bg-blue-600 text-white font-black rounded-2xl uppercase text-sm shadow-xl active:scale-95 transition-all">
                                    CAPTURE
                                </button>
                            ) : (
                                 <div className="flex gap-3">
                                    <button onClick={startCamera} className="flex-1 py-4 bg-gray-700 text-white font-black rounded-2xl uppercase text-xs flex items-center justify-center gap-2">
                                       <CameraIcon className="w-5 h-5"/> Camera
                                    </button>
                                     <button onClick={() => fileInputRef.current?.click()} className="flex-1 py-4 bg-gray-700 text-white font-black rounded-2xl uppercase text-xs flex items-center justify-center gap-2">
                                        <UploadIcon className="w-5 h-5"/> File
                                    </button>
                                     <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
                                </div>
                            )}
                        </div>
                    )}
                    {error && <p className="text-center text-red-400 font-bold p-3 bg-red-900/20 rounded-xl">{error}</p>}
                </div>

                <footer className="p-6 bg-gray-800 border-t-4 border-gray-700 shrink-0">
                    <button onClick={handleSave} disabled={!extractedText || !title} className="w-full flex items-center justify-center gap-3 py-5 bg-blue-600 text-white font-black rounded-2xl text-lg uppercase shadow-xl disabled:bg-gray-700 active:scale-95 transition-all">
                        <SaveIcon className="w-7 h-7"/> SAVE TO {course ? course : 'VAULT'}
                    </button>
                </footer>
            </div>
        </div>
    );
};

export default AddDocumentModal;

import React, { useState, useEffect } from 'react';
import { generateTitleForContent } from '../services/geminiService';
import type { WebMemory } from '../types';
import { BrainCircuitIcon, XIcon, SaveIcon, LinkIcon } from './Icons';
import MiniRecorder from './MiniRecorder';
import { getCurrentLocation } from '../utils/location';

interface AddWebMemoryModalProps {
    onClose: () => void;
    onSave: (memory: Omit<WebMemory, 'id' | 'date' | 'category'>) => void;
    initialUrl?: string;
    initialTitle?: string;
}

const AddWebMemoryModal: React.FC<AddWebMemoryModalProps> = ({ onClose, onSave, initialUrl, initialTitle }) => {
    const [url, setUrl] = useState(initialUrl || '');
    const [title, setTitle] = useState(initialTitle || '');
    const [content, setContent] = useState('');
    const [tags, setTags] = useState('');
    const [voiceNote, setVoiceNote] = useState('');
    const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);

    useEffect(() => {
        if (!url && title.includes('http')) {
            const match = title.match(/(https?:\/\/[^\s]+)/);
            if (match) {
                setUrl(match[0]);
            }
        }
    }, [title, url]);

    const handleGenerateTitle = async () => {
        if (!content.trim()) return;
        setIsGeneratingTitle(true);
        try {
            const generatedTitle = await generateTitleForContent(content);
            setTitle(generatedTitle);
        } catch (error) {
            console.error("Title generation failed:", error);
        } finally {
            setIsGeneratingTitle(false);
        }
    };

    const handleSave = async () => {
        if (!title.trim() && !url.trim()) return;
        const location = await getCurrentLocation();
        const newMemory: Omit<WebMemory, 'id' | 'date' | 'category'> = {
            type: 'web',
            url,
            title: title || 'Shared Link',
            content: content || `Shared URL: ${url}`,
            tags: tags.split(',').map(tag => tag.trim()).filter(Boolean),
            ...(voiceNote.trim() && { voiceNote: { transcript: voiceNote } }),
            ...(location && { location }),
        };
        onSave(newMemory);
        onClose();
    };

    const isSaveDisabled = (!title.trim() && !url.trim());

    return (
        <div className="fixed inset-0 bg-black/90 flex flex-col justify-center items-center z-[140] p-4">
            <div className="bg-gray-800 rounded-[2.5rem] shadow-2xl w-full max-w-2xl max-h-[95vh] flex flex-col border-4 border-gray-600 overflow-hidden">
                <header className="flex justify-between items-center p-6 border-b-4 border-gray-700 shrink-0">
                    <h2 className="text-xl font-black text-white flex items-center gap-4 uppercase"><LinkIcon className="w-8 h-8"/> Save Web Clip</h2>
                    <button onClick={onClose} className="p-3 bg-gray-700 rounded-2xl active:scale-90 transition-transform"><XIcon className="w-6 h-6 text-gray-400"/></button>
                </header>

                <main className="flex-grow p-6 space-y-6 overflow-y-auto scroll-smooth">
                    <div>
                        <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Link URL</label>
                        <input type="url" value={url} onChange={e => setUrl(e.target.value)} placeholder="https://..." className="w-full bg-gray-900 text-white text-base p-4 rounded-2xl border-2 border-gray-700 outline-none focus:border-blue-600 font-bold shadow-inner"/>
                    </div>

                    <div>
                        <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Title</label>
                         <div className="flex gap-2">
                           <input type="text" value={title} onChange={e => setTitle(e.target.value)} placeholder="Name your link" className="flex-grow bg-gray-900 text-white text-base p-4 rounded-2xl border-2 border-gray-700 outline-none focus:border-blue-600 font-bold shadow-inner"/>
                           <button onClick={handleGenerateTitle} className="p-4 bg-purple-600 text-white rounded-2xl shadow-lg active:scale-95 transition-all">
                               <BrainCircuitIcon className="w-6 h-6"/>
                           </button>
                        </div>
