import React, { useEffect, useState } from 'react';
import { 
    XIcon, LogOutIcon, CheckIcon, CalendarIcon, GraduationCapIcon, 
    LinkIcon, Loader2Icon, BrainCircuitIcon, Volume2Icon, UserIcon 
} from './Icons';
import type { StoredData } from '../hooks/useRecordings';
import { auth, googleProvider } from '../utils/firebase';
import { signOut, linkWithPopup } from 'firebase/auth';
import { generateSpeechFromText } from '../services/geminiService';
import { decode, decodeAudioData } from '../utils/audio';

interface SettingsModalProps {
    syncId: string;
    onClose: () => void;
    onReset: () => void;
    data: StoredData;
    onImport: (data: StoredData) => void;
    moodleToken: string | null;
    onSaveMoodleToken: (token: string) => void;
}

const ConnectionItem: React.FC<{
    label: string;
    icon: React.ReactNode;
    status: 'connected' | 'available' | 'disconnected';
    onClick: () => void;
    buttonText?: string;
    subtitle?: string;
}> = ({ label, icon, status, onClick, buttonText, subtitle }) => (
    <button 
        onClick={onClick}
        className={`w-full flex items-center justify-between p-5 bg-gray-900 border-4 rounded-[2rem] transition-all group ${status === 'connected' ? 'border-green-800' : 'border-gray-700 hover:border-blue-500 shadow-lg'}`}
    >
        <div className="flex items-center gap-3">
            <div className={`transition-transform ${status === 'connected' ? 'text-green-400' : 'text-blue-400'}`}>
                {icon}
            </div>
            <div className="text-left">
                <p className="text-lg font-black text-white leading-tight uppercase tracking-tight">{label}</p>
                <p className={`text-xs font-bold ${status === 'connected' ? 'text-green-400' : 'text-gray-500'} uppercase tracking-widest mt-0.5`}>
                    {status === 'connected' ? 'CONNECTED' : subtitle || 'READY'}
                </p>
            </div>
        </div>
        <div className={`px-4 py-2 rounded-xl font-black text-[10px] uppercase transition-all shadow-md ${status === 'connected' ? 'bg-green-900 text-green-200' : 'bg-blue-600 text-white group-hover:bg-blue-500'}`}>
            {buttonText || (status === 'connected' ? 'Edit' : 'Connect')}
        </div>
    </button>
);

const SettingsModal: React.FC<SettingsModalProps> = ({ syncId, onClose, moodleToken, onSaveMoodleToken }) => {
    const [moodleInputOpen, setMoodleInputOpen] = useState(false);
    const [tempMoodleToken, setTempMoodleToken] = useState('');
    const [isConnecting, setIsConnecting] = useState(false);
    const [isReading, setIsReading] = useState(false);

    const currentUser = auth.currentUser;
    const isGoogleUser = currentUser?.providerData.some(p => p.providerId === 'google.com');
    const userPhoto = currentUser?.photoURL;
    const userName = currentUser?.displayName || syncId;

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose(); };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [onClose]);

    const speakInstructions = async (text: string) => {
        if (isReading) return;
        setIsReading(true);
        try {
            const audioB64 = await generateSpeechFromText(text);
            if (audioB64) {
                const ctx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
                const audioData = decode(audioB64);
                const buffer = await decodeAudioData(audioData, ctx, 24000, 1);
                const source = ctx.createBufferSource();
                source.buffer = buffer;
                source.connect(ctx.destination);
                source.onended = () => setIsReading(false);
                source.start(0);
            }
        } catch (e) { console.error(e); setIsReading(false); }
    };

    const handleSignOut = async () => {
        if(window.confirm("Sign out of your brain?")) {
            await signOut(auth);
            onClose();
        }
    };

    const handleGoogleConnect = async () => {
        if (!currentUser || isGoogleUser) return;
        try {
            googleProvider.addScope('https://www.googleapis.com/auth/calendar.readonly');
            await linkWithPopup(currentUser, googleProvider);
        } catch (error: any) {
            console.error("Link error", error);
        }
    };

    const handleMoodleConnect = async () => {
        if (!tempMoodleToken.trim()) return;
        setIsConnecting(true);
        await new Promise(r => setTimeout(r, 1000));
        onSaveMoodleToken(tempMoodleToken);
        setIsConnecting(false);
        setMoodleInputOpen(false);
        setTempMoodleToken('');
    };

    return (
         <div className="fixed inset-0 bg-black/90 flex flex-col justify-center items-center z-[150] p-4">
            <div className="bg-gray-800 rounded-[2.5rem] shadow-2xl w-full max-w-lg max-h-[95vh] border-4 border-gray-600 flex flex-col overflow-hidden" onClick={(e) => e.stopPropagation()}>
                <header className="flex justify-between items-center p-6 border-b-4 border-gray-700 shrink-0">
                    <h2 className="text-xl font-black text-white uppercase tracking-tight">Settings</h2>
                    <button onClick={onClose} className="p-3 rounded-2xl bg-gray-700 active:scale-90 transition-transform"><XIcon className="w-6 h-6 text-gray-300"/></button>
                </header>

                <div className="flex-grow p-6 space-y-8 overflow-y-auto scroll-smooth">
                    <div className="bg-gray-900 p-5 rounded-[2rem] border-4 border-blue-600 shadow-2xl flex items-center gap-5">
                        <div className="relative shrink-0">
                            {userPhoto ? <img src={userPhoto} alt="" className="w-16 h-16 rounded-full border-4 border-blue-400" />
                            : <div className="w-16 h-16 rounded-full bg-blue-600 flex items-center justify-center border-4 border-blue-400 shadow-lg"><UserIcon className="w-8 h-8 text-white" /></div>}
                        </div>
                        <div className="flex-grow overflow-hidden">
                            <p className="text-blue-400 font-black text-[9px] uppercase tracking-widest mb-1">Authenticated</p>
                            <p className="text-white text-xl font-black truncate leading-none uppercase tracking-tighter">{userName}</p>
                        </div>
                    </div>

                    <div className="space-y-6">
                        <div className="flex flex-col gap-2">
                            <h3 className="text-purple-400 font-black text-sm uppercase tracking-widest">Connect Services</h3>
                            <p className="text-gray-400 text-xs font-bold leading-relaxed uppercase tracking-tighter opacity-70">Linking accounts keeps your brain synced across devices.</p>
                        </div>

                        <div className="space-y-4">
                            <ConnectionItem 
                                label="Google Calendar" icon={<CalendarIcon className="w-10 h-10" />}
                                status={isGoogleUser ? 'connected' : 'available'}
                                onClick={handleGoogleConnect}
                                subtitle={isGoogleUser ? 'SYNCING SCHEDULE' : 'TAP TO LINK'} />

                            {!moodleToken && !moodleInputOpen && <ConnectionItem label="Moodle Folder" icon={<GraduationCapIcon className="w-10 h-10" />} status="disconnected" onClick={() => setMoodleInputOpen(true)} />}
                            {moodleToken && !moodleInputOpen && <ConnectionItem label="Moodle Folder" icon={<GraduationCapIcon className="w-10 h-10" />} status="connected" onClick={() => onSaveMoodleToken('')} buttonText="Disconnect" />}

                            {moodleInputOpen && (
                                <div className="p-6 bg-gray-900 border-4 border-blue-500 rounded-[2.5rem] space-y-4 shadow-inner">
                                    <div className="flex justify-between items-center mb-2">
                                        <div className="flex items-center gap-2 text-blue-400"><LinkIcon className="w-6 h-6"/><h4 className="text-lg font-black uppercase tracking-tight">Moodle Key</h4></div>
                                        <button onClick={() => speakInstructions("Find your security key in Moodle Profile Preferences Security Keys. Paste it below.")} className="p-2 bg-gray-800 rounded-xl text-blue-400 active:scale-90 transition-transform"><Volume2Icon className={`w-6 h-6 ${isReading ? 'animate-pulse' : ''}`} /></button>
                                    </div>
                                    <div className="space-y-3">
                                        <input type="text" value={tempMoodleToken} onChange={(e) => setTempMoodleToken(e.target.value)} placeholder="Paste token here..." className="w-full bg-gray-800 text-white p-4 rounded-xl border-2 border-gray-700 outline-none focus:border-blue-500 font-mono text-xs shadow-inner" />
                                        <div className="flex gap-2">
                                            <button onClick={handleMoodleConnect} disabled={!tempMoodleToken.trim() || isConnecting} className="flex-grow py-4 bg-blue-600 text-white font-black rounded-xl shadow-lg flex items-center justify-center gap-2 uppercase text-xs active:scale-95 transition-all">{isConnecting ? <Loader2Icon className="w-4 h-4 animate-spin"/> : <CheckIcon className="w-4 h-4"/>} SAVE</button>
                                            <button onClick={() => setMoodleInputOpen(false)} className="px-5 py-4 bg-gray-700 text-gray-400 font-black rounded-xl uppercase text-xs active:scale-95 transition-all">CLOSE</button>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                <footer className="p-6 bg-gray-800 border-t-4 border-gray-700 shrink-0 flex flex-col gap-4">
                    <button onClick={handleSignOut} className="w-full py-5 bg-red-600 text-white font-black text-2xl rounded-2xl shadow-xl border-b-8 border-red-800 active:border-b-0 active:translate-y-2 transition-all uppercase tracking-tighter">
                        <LogOutIcon className="w-8 h-8 inline mr-3"/> SIGN OUT
                    </button>
                    <p className="text-center text-[10px] text-gray-500 font-black uppercase tracking-widest">Version 2.0 • Secured by Firebase</p>
                </footer>
            </div>
        </div>
    );
};

export default SettingsModal;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { generateTitleForContent } from '../services/geminiService';
import type { PhysicalItemMemory, VideoItemMemory, AnyMemory } from '../types';
// Add missing Loader2Icon import
import { BrainCircuitIcon, CameraIcon, XIcon, SaveIcon, UploadIcon, VideoIcon, StopCircleIcon, Loader2Icon } from './Icons';
import MiniRecorder from './MiniRecorder';
import { getCurrentLocation } from '../utils/location';
import { Modality, LiveSession } from '@google/genai';
import { getGeminiInstance } from '../utils/gemini';


interface AddPhysicalItemModalProps {
    onClose: () => void;
    onSave: (memory: Omit<PhysicalItemMemory | VideoItemMemory, 'id' | 'date' | 'category'>) => void;
}

const AddPhysicalItemModal: React.FC<AddPhysicalItemModalProps> = ({ onClose, onSave }) => {
    const [mode, setMode] = useState<'photo' | 'video'>('photo');
    const [title, setTitle] = useState('');
    const [description, setDescription] = useState('');
    const [tags, setTags] = useState('');
    const [voiceNote, setVoiceNote] = useState(''); 
    const [transcript, setTranscript] = useState(''); 
    const [imageDataUrl, setImageDataUrl] = useState<string | null>(null);
    const [videoDataUrl, setVideoDataUrl] = useState<string | null>(null);
    const [stream, setStream] = useState<MediaStream | null>(null);
    const [isRecording, setIsRecording] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);

    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const mediaRecorderRef = useRef<MediaRecorder | null>(null);
    const sessionPromiseRef = useRef<Promise<LiveSession> | null>(null);
    const liveTranscriptRef = useRef('');

    const stopCamera = useCallback(() => {
        if (stream) {
            stream.getTracks().forEach(track => track.stop());
            setStream(null);
        }
    }, [stream]);

    useEffect(() => {
        return () => { stopCamera(); };
    }, [stopCamera]);

    const startCamera = async () => {
        if (isRecording) await stopRecording();
        stopCamera();
        setImageDataUrl(null);
        setVideoDataUrl(null);
        setError(null);
        try {
            const mediaStream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' }, audio: true });
            setStream(mediaStream);
        } catch (err) {
            console.error("Camera access error:", err);
            setError("Could not access camera/mic. Please check permissions.");
        }
    };

    useEffect(() => {
        if (stream && videoRef.current) {
            videoRef.current.srcObject = stream;
        }
    }, [stream]);

    const takePicture = () => {
        if (videoRef.current && canvasRef.current) {
            const video = videoRef.current;
            const canvas = canvasRef.current;
            canvas.width = video.videoWidth;
            canvas.height = video.videoHeight;
            canvas.getContext('2d')?.drawImage(video, 0, 0, video.videoWidth, video.videoHeight);
            const dataUrl = canvas.toDataURL('image/jpeg');
            setImageDataUrl(dataUrl);
            stopCamera();
        }
    };

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (e) => {
                const result = e.target?.result as string;
                if (mode === 'photo') setImageDataUrl(result);
                else setVideoDataUrl(result);
                stopCamera();
            };
            if(mode === 'photo') reader.readAsDataURL(file);
            else if (file.type.startsWith('video/')) reader.readAsDataURL(file);
            else setError('Please select a valid video file.');
        }
    };

    const startRecording = async () => {
        if (!stream) return;

        const ai = getGeminiInstance();
        if (!ai) {
          setError("AI features are not available.");
          return;
        }

        setIsRecording(true);
        setVideoDataUrl(null);
        liveTranscriptRef.current = '';
        setTranscript('');

        const chunks: Blob[] = [];
        mediaRecorderRef.current = new MediaRecorder(stream);
        mediaRecorderRef.current.ondataavailable = (event) => chunks.push(event.data);
        mediaRecorderRef.current.onstop = () => {
            const blob = new Blob(chunks, { type: 'video/webm' });
            const reader = new FileReader();
            reader.onloadend = () => setVideoDataUrl(reader.result as string);
            reader.readAsDataURL(blob);
        };
        mediaRecorderRef.current.start();

        const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
        sessionPromiseRef.current = ai.live.connect({
            model: 'gemini-2.5-flash-native-audio-preview-09-2025',
            callbacks: {
              onopen: () => {
                const source = audioContext.createMediaStreamSource(stream);
                const scriptProcessor = audioContext.createScriptProcessor(4096, 1, 1);
                scriptProcessorRef.current = scriptProcessor;
                scriptProcessor.onaudioprocess = (e) => {
                  const inputData = e.inputBuffer.getChannelData(0);
                  const int16 = new Int16Array(inputData.length);
                  for (let i = 0; i < inputData.length; i++) {
                    let s = Math.max(-1, Math.min(1, inputData[i]));
                    int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
                  }
                  let binary = '';
                  const bytes = new Uint8Array(int16.buffer);
                  for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
                  sessionPromiseRef.current?.then((s) => s.sendRealtimeInput({ media: { data: btoa(binary), mimeType: 'audio/pcm;rate=16000' } }));
                };
                source.connect(scriptProcessor);
                scriptProcessor.connect(audioContext.destination);
              },
              onmessage: (message) => {
                if (message.serverContent?.inputTranscription) {
                  const text = message.serverContent.inputTranscription.text;
                  liveTranscriptRef.current += text;
                  setTranscript(prev => prev + text);
                }
              },
              onerror: (e) => { console.error(e); setError('Transcription error.'); },
              onclose: () => {},
            },
            config: { responseModalities: [Modality.AUDIO], inputAudioTranscription: {} },
        });
    };

    const stopRecording = async () => {
        setIsRecording(false);
        mediaRecorderRef.current?.stop();
        if (sessionPromiseRef.current) {
            const session = await sessionPromiseRef.current;
            session.close();
        }
        stopCamera();
    };

    const handleGenerateTitle = async () => {
        const content = description || transcript;
        if (!content.trim()) return;
        setIsGeneratingTitle(true);
        setTitle(await generateTitleForContent(content));
        setIsGeneratingTitle(false);
    }

    const handleSave = async () => {
        const hasMedia = imageDataUrl || videoDataUrl;
        if (!hasMedia || !title.trim()) return;

        const location = await getCurrentLocation();
        const tagList = tags.split(',').map(t => t.trim()).filter(Boolean);

        if (mode === 'video' && videoDataUrl) {
            const newMemory: Omit<VideoItemMemory, 'id' | 'date' | 'category'> = {
                type: 'video', title, description,
                videoDataUrl, transcript, ...(location && { location }), tags: tagList,
            };
            onSave(newMemory);
        } else if (mode === 'photo' && imageDataUrl) {
            const newMemory: Omit<PhysicalItemMemory, 'id' | 'date' | 'category'> = {
                type: 'item', title, description,
                imageDataUrl, ...(location && { location }),
                ...(voiceNote.trim() && { voiceNote: { transcript: voiceNote.trim() } }),
                tags: tagList,
            };
            onSave(newMemory);
        }
        onClose();
    };

    const isSaveDisabled = !title.trim() || (mode === 'photo' && !imageDataUrl) || (mode === 'video' && !videoDataUrl);

    return (
        <div className="fixed inset-0 bg-black/90 flex flex-col justify-center items-center z-[120] p-4">
            <div className="bg-gray-800 rounded-[2.5rem] shadow-2xl w-full max-w-2xl max-h-[95vh] flex flex-col border-4 border-gray-600 overflow-hidden">
                <header className="flex justify-between items-center p-6 border-b-4 border-gray-700 shrink-0">
                    <h2 className="text-xl font-black text-white flex items-center gap-3 uppercase"><CameraIcon className="w-8 h-8"/> Item Memory</h2>
                    <button onClick={onClose} className="p-3 rounded-2xl bg-gray-700 active:scale-90 transition-transform"><XIcon className="w-6 h-6"/></button>
                </header>

                <main className="flex-grow p-6 space-y-6 overflow-y-auto scroll-smooth">
                    <div className="flex justify-center bg-gray-900 p-1.5 rounded-2xl border border-gray-700">
                        <button onClick={() => { setMode('photo'); stopCamera(); }} className={`flex-1 py-3 font-black rounded-xl text-xs uppercase tracking-widest transition-all ${mode === 'photo' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500'}`}>Photo</button>
                        <button onClick={() => { setMode('video'); stopCamera(); }} className={`flex-1 py-3 font-black rounded-xl text-xs uppercase tracking-widest transition-all ${mode === 'video' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500'}`}>Video</button>
                    </div>

                    <div className="w-full aspect-square bg-gray-900 rounded-[2rem] flex items-center justify-center relative overflow-hidden border-2 border-gray-700 shadow-inner">
                        <canvas ref={canvasRef} className="hidden" />
                        {imageDataUrl && mode === 'photo' ? <img src={imageDataUrl} alt="Item" className="w-full h-full object-contain" />
                        : videoDataUrl && mode === 'video' ? <video src={videoDataUrl} controls className="w-full h-full object-contain" />
                        : stream ? <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
                        : (
                            <div className="text-center text-gray-700">
                                {mode === 'photo' ? <CameraIcon className="w-20 h-20 mx-auto" /> : <VideoIcon className="w-20 h-20 mx-auto" />}
                                <p className="mt-4 font-black uppercase text-xs tracking-tighter">Capture a {mode}</p>
                            </div>
                        )}
                    </div>

                    <div className="flex gap-3 justify-center">
                        {isRecording ? (
                            <button onClick={stopRecording} className="px-8 py-4 bg-red-600 text-white font-black rounded-2xl shadow-lg active:scale-95 flex items-center gap-3 uppercase text-sm">
                                <StopCircleIcon className="w-6 h-6"/> STOP
                            </button>
                        ) : stream ? (
                            mode === 'photo' ? (
                                <button onClick={takePicture} className="px-8 py-4 bg-blue-600 text-white font-black rounded-2xl shadow-lg active:scale-95 flex items-center gap-3 uppercase text-sm">
                                    <CameraIcon className="w-6 h-6"/> CAPTURE
                                </button>
                            ) : (
                                <button onClick={startRecording} className="px-8 py-4 bg-blue-600 text-white font-black rounded-2xl shadow-lg active:scale-95 flex items-center gap-3 uppercase text-sm">
                                    <VideoIcon className="w-6 h-6"/> RECORD
                                </button>
                            )
                        ) : (
                            <>
                                <button onClick={startCamera} className="flex-1 py-4 bg-gray-700 text-white font-black rounded-2xl flex items-center justify-center gap-3 uppercase text-xs">
                                    <CameraIcon className="w-5 h-5"/> Camera
                                </button>
                                <button onClick={() => fileInputRef.current?.click()} className="flex-1 py-4 bg-gray-700 text-white font-black rounded-2xl flex items-center justify-center gap-3 uppercase text-xs">
                                    <UploadIcon className="w-5 h-5"/> File
                                </button>
                                <input type="file" ref={fileInputRef} onChange={handleFileChange} accept={mode === 'photo' ? "image/*" : "video/*"} className="hidden" />
                            </>
                        )}
                    </div>

                    {error && <p className="text-center text-red-400 font-bold bg-red-900/20 p-3 rounded-xl">{error}</p>}

                    <div className="space-y-4">
                        <div>
                            <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Details</label>
                            <textarea value={description} onChange={e => setDescription(e.target.value)} rows={3} placeholder="What is this? Where is it located?" className="w-full bg-gray-900 text-white text-base p-4 rounded-2xl border-2 border-gray-700 outline-none focus:border-blue-600 font-bold shadow-inner"/>
                        </div>

                        <div>
                            <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Title</label>
                             <div className="flex gap-2">
                               <input type="text" value={title} onChange={e => setTitle(e.target.value)} placeholder="Title" className="flex-grow bg-gray-900 text-white text-base p-4 rounded-2xl border-2 border-gray-700 outline-none focus:border-blue-600 font-bold shadow-inner"/>
                               <button onClick={handleGenerateTitle} disabled={isGeneratingTitle || (!description.trim() && !transcript.trim())} className="p-4 bg-purple-600 text-white rounded-2xl disabled:bg-gray-700 shadow-lg active:scale-95 transition-all">
                                   {isGeneratingTitle ? <Loader2Icon className="w-6 h-6 animate-spin"/> : <BrainCircuitIcon className="w-6 h-6"/>}
                               </button>
                            </div>
                        </div>

                        <div>
                            <MiniRecorder onTranscriptChange={setVoiceNote} />
                            {(voiceNote || transcript) && (
                                <div className="mt-3 bg-gray-900 p-4 rounded-2xl border border-gray-700 shadow-inner">
                                    <p className="text-xs text-gray-400 leading-relaxed font-medium">{voiceNote || transcript}</p>
                                </div>
                            )}
                        </div>
                    </div>
                </main>

                <footer className="p-6 flex flex-col gap-3 border-t-4 border-gray-700 bg-gray-800 shrink-0">
                    <button onClick={handleSave} disabled={isSaveDisabled} className="flex items-center justify-center gap-3 py-5 bg-blue-600 text-white font-black rounded-2xl text-lg uppercase shadow-xl disabled:bg-gray-700 active:scale-95 transition-all">
                        <SaveIcon className="w-7 h-7"/> SAVE
                    </button>
                    <button onClick={onClose} className="py-4 text-gray-500 font-black uppercase text-xs tracking-widest active:scale-95">Cancel</button>
                </footer>
            </div>
        </div>
    );
};

export default AddPhysicalItemModal;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { LiveSession, Modality } from '@google/genai';
import { MicIcon, StopCircleIcon, SaveIcon, XIcon, Loader2Icon, CheckIcon, PlayIcon, Volume2Icon } from './Icons';
import type { VoiceMemory } from '../types';
import { getCurrentLocation } from '../utils/location';
import { getGeminiInstance } from '../utils/gemini';
import { analyzeVoiceNote } from '../services/geminiService';

interface RecorderProps {
  onSave: (recording: Omit<VoiceMemory, 'id' | 'date'>) => void;
  onCancel: () => void;
  titlePlaceholder: string;
  saveButtonText: string;
  enableDiarization?: boolean;
}

interface IWindow extends Window {
  webkitSpeechRecognition: any;
  SpeechRecognition: any;
}

const Recorder: React.FC<RecorderProps> = ({ onSave, onCancel, titlePlaceholder, saveButtonText }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [liveTranscript, setLiveTranscript] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [recordingTitle, setRecordingTitle] = useState('');
  const [extractedActionItems, setExtractedActionItems] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [transcriptionMode, setTranscriptionMode] = useState<'cloud' | 'device'>('cloud'); 
  const [audioDataUrl, setAudioDataUrl] = useState<string | undefined>(undefined);

  const finalTranscriptRef = useRef<string>('');
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  // Gemini Live Refs
  const sessionPromiseRef = useRef<Promise<LiveSession> | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  const recognitionRef = useRef<any>(null);
  const wakeLockRef = useRef<WakeLockSentinel | null>(null);

  const playBeep = useCallback((frequency: number, type: 'sine' | 'square' = 'sine', duration: number = 0.15) => {
    try {
        const Ctx = window.AudioContext || (window as any).webkitAudioContext;
        if (!Ctx) return;
        const ctx = new Ctx();
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.type = type;
        osc.frequency.setValueAtTime(frequency, ctx.currentTime);
        gain.gain.setValueAtTime(0.1, ctx.currentTime);
        gain.gain.exponentialRampToValueAtTime(0.00001, ctx.currentTime + duration);
        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.start();
        osc.stop(ctx.currentTime + duration);
    } catch (e) {}
  }, []);

  const requestWakeLock = async () => {
    if ('wakeLock' in navigator) {
      try { wakeLockRef.current = await navigator.wakeLock.request('screen'); } catch (err) {}
    }
  };

  const releaseWakeLock = async () => {
    if (wakeLockRef.current) {
      try { await wakeLockRef.current.release(); wakeLockRef.current = null; } catch (err) {}
    }
  };

  const startRecording = async () => {
    if (isRecording) return;
    setError(null);
    setLiveTranscript('');
    finalTranscriptRef.current = '';
    audioChunksRef.current = [];
    setAudioDataUrl(undefined);
    await requestWakeLock();
    playBeep(880, 'sine', 0.2);

    try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const mediaRecorder = new MediaRecorder(stream);
        mediaRecorderRef.current = mediaRecorder;
        mediaRecorder.ondataavailable = (e) => {
            if (e.data.size > 0) audioChunksRef.current.push(e.data);
        };
        mediaRecorder.onstop = () => {
            const blob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
            const reader = new FileReader();
            reader.onloadend = () => setAudioDataUrl(reader.result as string);
            reader.readAsDataURL(blob);
        };
        mediaRecorder.start();

        if (transcriptionMode === 'device') {
            const win = window as unknown as IWindow;
            const SpeechRecognition = win.SpeechRecognition || win.webkitSpeechRecognition;
            if (!SpeechRecognition) {
                setError("Device transcription not supported.");
                return;
            }
            const recognition = new SpeechRecognition();
            recognition.continuous = true;
            recognition.interimResults = true;
            recognition.onresult = (event: any) => {
                let interimTranscript = '';
                for (let i = event.resultIndex; i < event.results.length; ++i) {
                    if (event.results[i].isFinal) finalTranscriptRef.current += event.results[i][0].transcript + ' ';
                    else interimTranscript += event.results[i][0].transcript;
                }
                setLiveTranscript(finalTranscriptRef.current + interimTranscript);
            };
            recognition.start();
            recognitionRef.current = recognition;
            setIsRecording(true);
        } else {
            const ai = getGeminiInstance();
            if (!ai) { setError("AI unavailable."); return; }
            setIsRecording(true);
            const context = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
            audioContextRef.current = context;
            sessionPromiseRef.current = ai.live.connect({
              model: 'gemini-2.5-flash-native-audio-preview-09-2025',
              callbacks: {
                onopen: () => {
                  const source = context.createMediaStreamSource(stream);
                  const scriptProcessor = context.createScriptProcessor(4096, 1, 1);
                  scriptProcessorRef.current = scriptProcessor;
                  scriptProcessor.onaudioprocess = (e) => {
                    const inputData = e.inputBuffer.getChannelData(0);
                    const int16 = new Int16Array(inputData.length);
                    for (let i = 0; i < inputData.length; i++) {
                      let s = Math.max(-1, Math.min(1, inputData[i]));
                      int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
                    }
                    let binary = '';
                    const bytes = new Uint8Array(int16.buffer);
                    for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
                    sessionPromiseRef.current?.then((s) => s.sendRealtimeInput({ media: { data: btoa(binary), mimeType: 'audio/pcm;rate=16000' } }));
                  };
                  source.connect(scriptProcessor);
                  scriptProcessor.connect(context.destination);
                },
                onmessage: (m) => {
                  if (m.serverContent?.inputTranscription) {
                    const text = m.serverContent.inputTranscription.text;
                    finalTranscriptRef.current += text;
                    setLiveTranscript(prev => prev + text);
                  }
                },
                onerror: () => {},
                onclose: () => {},
              },
              config: { responseModalities: [Modality.AUDIO], inputAudioTranscription: {} },
            });
        }
    } catch (err) {
        setError('Microphone access denied.');
        await releaseWakeLock();
    }
  };

  const stopRecording = useCallback(async () => {
    if (!isRecording) return;
    setIsRecording(false); 
    playBeep(440, 'sine', 0.2);
    await releaseWakeLock();

    mediaRecorderRef.current?.stop();
    if (transcriptionMode === 'cloud') {
        mediaStreamRef.current?.getTracks().forEach(t => t.stop());
        scriptProcessorRef.current?.disconnect();
        audioContextRef.current?.close();
        sessionPromiseRef.current?.then(s => s.close());
    } else {
        recognitionRef.current?.stop();
    }

    if (finalTranscriptRef.current.trim()) {
      setIsSaving(true);
      setIsAnalyzing(true);
      try {
        const analysis = await analyzeVoiceNote(finalTranscriptRef.current);
        setRecordingTitle(analysis.title || titlePlaceholder);
        setExtractedActionItems(analysis.actionItems || []);
      } catch (error) {
        setRecordingTitle(titlePlaceholder);
      } finally {
        setIsAnalyzing(false);
      }
    } else {
      onCancel();
    }
  }, [isRecording, onCancel, titlePlaceholder, playBeep, transcriptionMode]);

  const handleSave = useCallback(async () => {
    // Only save if there is content
    const finalTitle = recordingTitle.trim() || titlePlaceholder;
    const finalTranscript = finalTranscriptRef.current.trim();
    if (!finalTranscript) {
        onCancel();
        return;
    }

    const location = await getCurrentLocation();
    onSave({
      type: 'voice',
      title: finalTitle,
      transcript: finalTranscript,
      audioDataUrl,
      actionItems: extractedActionItems.map(text => ({ text, done: false })),
      ...(location && { location }),
    } as Omit<VoiceMemory, 'id'|'date'>);
  }, [recordingTitle, audioDataUrl, extractedActionItems, onSave, onCancel, titlePlaceholder]);

  // Handle "Cancel" by auto-saving instead of discarding, as requested.
  const handleAutoSaveAndClose = () => {
    if (isSaving) {
        handleSave();
    } else {
        onCancel();
    }
  };

  if (isSaving) {
    return (
      <div 
        className="fixed inset-0 bg-black/80 flex flex-col items-center justify-center z-[100] p-4"
        onClick={handleAutoSaveAndClose}
      >
        <div 
          className="bg-gray-800 rounded-[2.5rem] shadow-2xl w-full max-w-lg max-h-[95vh] border-4 border-gray-600 flex flex-col overflow-hidden"
          onClick={e => e.stopPropagation()}
        >
          {/* Header with Save Button at Top */}
          <header className="flex justify-between items-center p-6 border-b-4 border-gray-700 shrink-0 bg-gray-800">
            <h2 className="text-xl font-black text-white uppercase tracking-tight">Review Note</h2>
            <button 
                onClick={handleSave}
                className="flex items-center gap-2 px-5 py-3 bg-blue-600 text-white font-black rounded-xl text-sm uppercase shadow-xl active:scale-95 transition-all"
            >
                <CheckIcon className="w-5 h-5"/> {saveButtonText}
            </button>
          </header>

          <main className="flex-grow overflow-y-auto p-6 space-y-6 scroll-smooth">
            <div className="space-y-4">
                <div>
                    <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Note Title</label>
                    <input
                        type="text"
                        value={recordingTitle}
                        onChange={(e) => setRecordingTitle(e.target.value)}
                        className="w-full bg-gray-900 text-white text-base p-4 rounded-2xl border-2 border-gray-700 outline-none focus:border-blue-600 font-bold shadow-inner"
                        placeholder="Note Title"
                    />
                </div>

                {audioDataUrl && (
                    <div className="bg-gray-900 p-4 rounded-2xl border border-gray-700 shadow-inner flex items-center gap-4">
                        <div className="bg-blue-900/30 p-2 rounded-full"><Volume2Icon className="w-6 h-6 text-blue-400"/></div>
                        <audio src={audioDataUrl} controls className="flex-grow h-8" />
                    </div>
                )}

                <div className="space-y-2">
                    <label className="block text-[10px] font-black text-gray-500 uppercase mb-1 tracking-widest">Transcript</label>
                    <div className="w-full bg-gray-900 p-5 rounded-2xl border-2 border-gray-700 text-sm text-gray-200 leading-relaxed font-medium shadow-inner min-h-[150px]">
                        {isAnalyzing ? (
                            <div className="flex items-center gap-3 text-blue-400 font-black animate-pulse">
                                <Loader2Icon className="w-5 h-5 animate-spin"/>
                                ANALYZING NOTE...
                            </div>
                        ) : (
                            <div className="whitespace-pre-wrap">{finalTranscriptRef.current}</div>
                        )}
                    </div>
                </div>

                {extractedActionItems.length > 0 && (
                    <div className="space-y-3">
                        <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest">Detected Tasks</label>
                        <div className="space-y-2">
                            {extractedActionItems.map((item, i) => (
                                <div key={i} className="bg-gray-700/50 p-3 rounded-xl border border-gray-600 text-xs font-bold text-gray-300 flex items-center gap-3">
                                    <div className="w-2 h-2 rounded-full bg-blue-500 shrink-0"/> {item}
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>
          </main>

          <footer className="p-6 border-t-4 border-gray-700 bg-gray-800 shrink-0 flex flex-col gap-3">
            <button 
              onClick={handleSave}
              className="w-full py-5 bg-blue-600 text-white font-black rounded-2xl text-lg uppercase shadow-xl active:scale-95 transition-all"
            >
              FINISH & SAVE
            </button>
            <button 
              onClick={onCancel}
              className="py-3 text-gray-500 font-black uppercase text-xs tracking-widest hover:text-red-400 transition-colors"
            >
              Discard Note
            </button>
          </footer>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-gray-800 p-6 rounded-[2.5rem] shadow-2xl border-4 border-gray-700 h-full flex flex-col overflow-hidden">
      <div className="flex justify-between items-center mb-6 shrink-0">
          <div className="flex bg-gray-900 rounded-2xl p-1.5 border-2 border-gray-700">
              <button onClick={() => setTranscriptionMode('cloud')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${transcriptionMode === 'cloud' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500'}`}>AI</button>
              <button onClick={() => setTranscriptionMode('device')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${transcriptionMode === 'device' ? 'bg-green-600 text-white shadow-lg' : 'text-gray-500'}`}>LOCAL</button>
          </div>
          <button onClick={onCancel} className="p-3 bg-gray-700 rounded-2xl text-gray-400"><XIcon className="w-6 h-6"/></button>
      </div>

      <div className="flex-grow flex flex-col items-center justify-center gap-8 overflow-hidden">
        <button
            onClick={isRecording ? stopRecording : startRecording}
            className={`flex items-center justify-center w-40 h-40 rounded-full shadow-[0_0_50px_rgba(37,99,235,0.2)] transition-all border-8 ${
                isRecording ? 'bg-red-600 animate-pulse border-red-500 scale-110 shadow-[0_0_60px_rgba(220,38,38,0.4)]' : transcriptionMode === 'cloud' ? 'bg-blue-600 border-blue-500 hover:scale-105 shadow-[0_0_60px_rgba(37,99,235,0.3)]' : 'bg-green-600 border-green-500 shadow-[0_0_60px_rgba(22,163,74,0.3)]'
            }`}
        >
            {isRecording ? <StopCircleIcon className="w-20 h-20 text-white" /> : <MicIcon className="w-20 h-20 text-white" />}
        </button>

        <div className="w-full bg-gray-900 p-6 rounded-3xl border-2 border-gray-700 overflow-y-auto max-h-60 shadow-inner flex-grow relative">
            {!liveTranscript && !isRecording && (
                <div className="absolute inset-0 flex items-center justify-center text-gray-600 font-black uppercase text-sm tracking-widest pointer-events-none">
                    Tap Mic to Record
                </div>
            )}
            <p className="text-xl text-gray-200 whitespace-pre-wrap font-bold leading-relaxed">
                {liveTranscript}
            </p>
        </div>
      </div>

      <div className="mt-8 flex gap-4 shrink-0">
          {isRecording ? (
             <button onClick={stopRecording} className="flex-1 py-5 bg-red-600 text-white font-black rounded-2xl text-xl uppercase shadow-2xl active:scale-95 transition-all">FINISH RECORDING</button>
          ) : (
             <button onClick={onCancel} className="flex-1 py-5 bg-gray-700 text-gray-400 font-black rounded-2xl text-lg uppercase active:scale-95 transition-all">Cancel</button>
          )}
      </div>
    </div>
  );
};

