                  <button onClick={() => setTranscriptionMode('device')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${transcriptionMode === 'device' ? 'bg-green-600 text-white shadow-lg' : 'text-gray-500'}`}>LOCAL</button>
              </div>
              <button onClick={onCancel} className="p-3 bg-gray-700 rounded-2xl text-gray-400 active:scale-90 transition-transform"><XIcon className="w-6 h-6"/></button>
          </header>

          <main className="flex-grow flex flex-col items-center justify-center gap-8 overflow-hidden px-2">
            <button
                onClick={isRecording ? stopRecording : startRecording}
                className={`flex items-center justify-center w-40 h-40 rounded-full shadow-[0_0_50px_rgba(37,99,235,0.2)] transition-all border-8 ${
                    isRecording ? 'bg-red-600 animate-pulse border-red-500 scale-110 shadow-[0_0_60px_rgba(220,38,38,0.4)]' : transcriptionMode === 'cloud' ? 'bg-blue-600 border-blue-500 hover:scale-105 shadow-[0_0_60px_rgba(37,99,235,0.3)]' : 'bg-green-600 border-green-500 shadow-[0_0_60px_rgba(22,163,74,0.3)]'
                }`}
            >
                {isRecording ? <StopCircleIcon className="w-20 h-20 text-white" /> : <MicIcon className="w-20 h-20 text-white" />}
            </button>

            <div className="w-full bg-gray-900 p-6 rounded-3xl border-2 border-gray-700 overflow-y-auto max-h-64 shadow-inner relative min-h-[150px]">
                {!liveTranscript && !isRecording && (
                    <div className="absolute inset-0 flex items-center justify-center text-gray-600 font-black uppercase text-sm tracking-widest pointer-events-none text-center p-6">
                        Tap Microphone to Start Recording
                    </div>
                )}
                <p className="text-xl text-gray-200 whitespace-pre-wrap font-bold leading-relaxed">
                    {liveTranscript}
                </p>
            </div>
          </main>

          <footer className="mt-8 flex gap-4 shrink-0">
              {isRecording ? (
                 <button onClick={stopRecording} className="flex-1 py-5 bg-red-600 text-white font-black rounded-2xl text-xl uppercase shadow-2xl active:scale-95 transition-all">FINISH RECORDING</button>
              ) : (
