import React, { useState, useRef, useCallback, useEffect } from 'react';
import { LiveSession, Modality } from '@google/genai';
import { MicIcon, StopCircleIcon, SaveIcon, XIcon, Loader2Icon, CheckIcon, PlayIcon, Volume2Icon } from './Icons';
import type { VoiceMemory } from '../types';
import { getCurrentLocation } from '../utils/location';
import { getGeminiInstance } from '../utils/gemini';
import { analyzeVoiceNote } from '../services/geminiService';

interface RecorderProps {
  onSave: (recording: Omit<VoiceMemory, 'id' | 'date'>) => void;
  onCancel: () => void;
  titlePlaceholder: string;
  saveButtonText: string;
  enableDiarization?: boolean;
}

interface IWindow extends Window {
  webkitSpeechRecognition: any;
  SpeechRecognition: any;
}

const Recorder: React.FC<RecorderProps> = ({ onSave, onCancel, titlePlaceholder, saveButtonText }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [liveTranscript, setLiveTranscript] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [recordingTitle, setRecordingTitle] = useState('');
  const [extractedActionItems, setExtractedActionItems] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [transcriptionMode, setTranscriptionMode] = useState<'cloud' | 'device'>('cloud'); 
  const [audioDataUrl, setAudioDataUrl] = useState<string | undefined>(undefined);

  const finalTranscriptRef = useRef<string>('');
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const sessionPromiseRef = useRef<Promise<LiveSession> | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  const recognitionRef = useRef<any>(null);
  const wakeLockRef = useRef<WakeLockSentinel | null>(null);

  const playBeep = useCallback((frequency: number, type: 'sine' | 'square' = 'sine', duration: number = 0.15) => {
    try {
        const Ctx = window.AudioContext || (window as any).webkitAudioContext;
        if (!Ctx) return;
        const ctx = new Ctx();
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.type = type;
        osc.frequency.setValueAtTime(frequency, ctx.currentTime);
        gain.gain.setValueAtTime(0.1, ctx.currentTime);
        gain.gain.exponentialRampToValueAtTime(0.00001, ctx.currentTime + duration);
        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.start();
        osc.stop(ctx.currentTime + duration);
    } catch (e) {}
  }, []);

  const requestWakeLock = async () => {
    if ('wakeLock' in navigator) {
      try { wakeLockRef.current = await navigator.wakeLock.request('screen'); } catch (err) {}
    }
  };

  const releaseWakeLock = async () => {
    if (wakeLockRef.current) {
      try { await wakeLockRef.current.release(); wakeLockRef.current = null; } catch (err) {}
    }
  };

  const startRecording = async () => {
    if (isRecording) return;
    setError(null);
    setLiveTranscript('');
    finalTranscriptRef.current = '';
    audioChunksRef.current = [];
    setAudioDataUrl(undefined);
    await requestWakeLock();
    playBeep(880, 'sine', 0.2);

    try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const mediaRecorder = new MediaRecorder(stream);
        mediaRecorderRef.current = mediaRecorder;
        mediaRecorder.ondataavailable = (e) => {
            if (e.data.size > 0) audioChunksRef.current.push(e.data);
        };
        mediaRecorder.onstop = () => {
            const blob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
            const reader = new FileReader();
            reader.onloadend = () => setAudioDataUrl(reader.result as string);
            reader.readAsDataURL(blob);
        };
        mediaRecorder.start();

        if (transcriptionMode === 'device') {
            const win = window as unknown as IWindow;
            const SpeechRecognition = win.SpeechRecognition || win.webkitSpeechRecognition;
            if (!SpeechRecognition) {
                setError("Device transcription not supported.");
                return;
            }
            const recognition = new SpeechRecognition();
            recognition.continuous = true;
            recognition.interimResults = true;
            // Native recognition is poor at bilingual. We default to 'he-IL' or 'en-US' 
            // but for this user, Cloud mode (Gemini) is the fix.
            recognition.lang = 'he-IL'; 
            recognition.onresult = (event: any) => {
                let interimTranscript = '';
                for (let i = event.resultIndex; i < event.results.length; ++i) {
                    if (event.results[i].isFinal) finalTranscriptRef.current += event.results[i][0].transcript + ' ';
                    else interimTranscript += event.results[i][0].transcript;
                }
                setLiveTranscript(finalTranscriptRef.current + interimTranscript);
            };
            recognition.start();
            recognitionRef.current = recognition;
            setIsRecording(true);
        } else {
            const ai = getGeminiInstance();
            if (!ai) { setError("AI unavailable."); return; }
            setIsRecording(true);
            const context = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
            audioContextRef.current = context;
            sessionPromiseRef.current = ai.live.connect({
              model: 'gemini-2.5-flash-native-audio-preview-09-2025',
              callbacks: {
                onopen: () => {
                  const source = context.createMediaStreamSource(stream);
                  const scriptProcessor = context.createScriptProcessor(4096, 1, 1);
                  scriptProcessorRef.current = scriptProcessor;
                  scriptProcessor.onaudioprocess = (e) => {
                    const inputData = e.inputBuffer.getChannelData(0);
                    const int16 = new Int16Array(inputData.length);
                    for (let i = 0; i < inputData.length; i++) {
                      let s = Math.max(-1, Math.min(1, inputData[i]));
                      int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
                    }
                    let binary = '';
                    const bytes = new Uint8Array(int16.buffer);
                    for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
                    sessionPromiseRef.current?.then((s) => s.sendRealtimeInput({ media: { data: btoa(binary), mimeType: 'audio/pcm;rate=16000' } }));
                  };
                  source.connect(scriptProcessor);
                  scriptProcessor.connect(context.destination);
                },
                onmessage: (m) => {
                  if (m.serverContent?.inputTranscription) {
                    const text = m.serverContent.inputTranscription.text;
                    finalTranscriptRef.current += text;
                    setLiveTranscript(prev => prev + text);
                  }
                },
                onerror: () => {},
                onclose: () => {},
              },
              config: { 
                responseModalities: [Modality.AUDIO], 
                inputAudioTranscription: {},
                // CRITICAL: Instruct the model explicitly about code-switching between Hebrew and English.
                systemInstruction: "You are a specialized transcription assistant for a student who speaks both Hebrew and English. Code-switching is very frequent. Transcribe everything exactly as spoken. If the speaker switches to Hebrew, transcribe in Hebrew characters. If they switch to English, transcribe in English characters. Do not attempt to translate Hebrew to English or vice versa; keep the original language of the speech. Maintain high accuracy for both languages even when they occur in the same sentence."
              },
            });
        }
    } catch (err) {
        setError('Microphone access denied.');
        await releaseWakeLock();
    }
  };

  const stopRecording = useCallback(async () => {
    if (!isRecording) return;
    setIsRecording(false); 
    playBeep(440, 'sine', 0.2);
    await releaseWakeLock();

    mediaRecorderRef.current?.stop();
    if (transcriptionMode === 'cloud') {
        mediaStreamRef.current?.getTracks().forEach(t => t.stop());
        scriptProcessorRef.current?.disconnect();
        audioContextRef.current?.close();
        sessionPromiseRef.current?.then(s => s.close());
    } else {
        recognitionRef.current?.stop();
    }

    if (finalTranscriptRef.current.trim()) {
      setIsSaving(true);
      setIsAnalyzing(true);
      try {
        const analysis = await analyzeVoiceNote(finalTranscriptRef.current);
        setRecordingTitle(analysis.title || titlePlaceholder);
        setExtractedActionItems(analysis.actionItems || []);
      } catch (error) {
        setRecordingTitle(titlePlaceholder);
      } finally {
        setIsAnalyzing(false);
      }
    } else {
      onCancel();
    }
  }, [isRecording, onCancel, titlePlaceholder, playBeep, transcriptionMode]);

  const handleSave = useCallback(async () => {
    const finalTranscript = finalTranscriptRef.current.trim();
    if (!finalTranscript) {
        onCancel();
        return;
    }

    const finalTitle = recordingTitle.trim() || titlePlaceholder;
    const location = await getCurrentLocation();
    onSave({
      type: 'voice',
      title: finalTitle,
      transcript: finalTranscript,
      audioDataUrl,
      actionItems: extractedActionItems.map(text => ({ text, done: false })),
      ...(location && { location }),
    } as Omit<VoiceMemory, 'id'|'date'>);
  }, [recordingTitle, audioDataUrl, extractedActionItems, onSave, onCancel, titlePlaceholder]);

  const handleBackgroundTap = () => {
    if (isSaving) {
        handleSave();
    } else if (!isRecording) {
        onCancel();
    }
  };

  const renderContent = () => {
    if (isSaving) {
        return (
          <div 
            className="bg-gray-800 rounded-[2.5rem] shadow-2xl w-full max-w-lg max-h-[95vh] border-4 border-gray-600 flex flex-col overflow-hidden"
            onClick={e => e.stopPropagation()}
          >
            <header className="flex justify-between items-center p-6 border-b-4 border-gray-700 shrink-0 bg-gray-800">
              <h2 className="text-xl font-black text-white uppercase tracking-tight">Review</h2>
              <button 
                  onClick={handleSave}
                  className="flex items-center gap-2 px-6 py-4 bg-blue-600 text-white font-black rounded-2xl text-base uppercase shadow-xl active:scale-95 transition-all"
              >
                  <CheckIcon className="w-6 h-6"/> {saveButtonText}
              </button>
            </header>

            <main className="flex-grow overflow-y-auto p-6 space-y-6 scroll-smooth">
              <div className="space-y-4">
                  <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Note Title</label>
                      <input
                          type="text"
                          value={recordingTitle}
                          onChange={(e) => setRecordingTitle(e.target.value)}
                          className="w-full bg-gray-900 text-white text-base p-4 rounded-2xl border-2 border-gray-700 outline-none focus:border-blue-600 font-bold shadow-inner"
                          placeholder="Enter Title"
                      />
                  </div>

                  {audioDataUrl && (
                      <div className="bg-gray-900 p-4 rounded-2xl border border-gray-700 shadow-inner flex items-center gap-4">
                          <div className="bg-blue-900/30 p-2 rounded-full"><Volume2Icon className="w-6 h-6 text-blue-400"/></div>
                          <audio src={audioDataUrl} controls className="flex-grow h-10" />
                      </div>
                  )}

                  <div className="space-y-2">
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-1 tracking-widest">Transcript</label>
                      <div className="w-full bg-gray-900 p-5 rounded-2xl border-2 border-gray-700 text-sm text-gray-200 leading-relaxed font-medium shadow-inner min-h-[200px]">
                          {isAnalyzing ? (
                              <div className="flex items-center gap-3 text-blue-400 font-black animate-pulse">
                                  <Loader2Icon className="w-5 h-5 animate-spin"/>
                                  ANALYZING NOTE...
                              </div>
                          ) : (
                              <div className="whitespace-pre-wrap">{finalTranscriptRef.current}</div>
                          )}
                      </div>
                  </div>

                  {extractedActionItems.length > 0 && (
                      <div className="space-y-3 pb-4">
                          <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest">Detected Tasks</label>
                          <div className="space-y-2">
                              {extractedActionItems.map((item, i) => (
                                  <div key={i} className="bg-gray-700/50 p-4 rounded-xl border border-gray-600 text-xs font-bold text-gray-300 flex items-center gap-3">
                                      <div className="w-2.5 h-2.5 rounded-full bg-blue-500 shrink-0"/> {item}
                                  </div>
                              ))}
                          </div>
                      </div>
                  )}
              </div>
            </main>

            <footer className="p-4 border-t-2 border-gray-700 bg-gray-800 shrink-0 text-center">
              <button 
                onClick={onCancel}
                className="px-6 py-2 text-gray-500 font-black uppercase text-xs tracking-widest hover:text-red-400 transition-colors"
              >
                Discard and Close
              </button>
            </footer>
          </div>
        );
    }

    return (
        <div 
            className="bg-gray-800 p-6 rounded-[2.5rem] shadow-2xl border-4 border-gray-700 w-full max-w-lg h-full max-h-[90vh] flex flex-col overflow-hidden"
            onClick={e => e.stopPropagation()}
        >
          <header className="flex justify-between items-center mb-6 shrink-0">
              <div className="flex bg-gray-900 rounded-2xl p-1.5 border-2 border-gray-700">
                  <button onClick={() => setTranscriptionMode('cloud')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${transcriptionMode === 'cloud' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500'}`}>AI</button>
                  <button onClick={() => setTranscriptionMode('device')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${transcriptionMode === 'device' ? 'bg-green-600 text-white shadow-lg' : 'text-gray-500'}`}>LOCAL</button>
              </div>
              <button onClick={onCancel} className="p-3 bg-gray-700 rounded-2xl text-gray-400 active:scale-90 transition-transform"><XIcon className="w-6 h-6"/></button>
          </header>

          <main className="flex-grow flex flex-col items-center justify-center gap-8 overflow-hidden px-2">
            <button
                onClick={isRecording ? stopRecording : startRecording}
                className={`flex items-center justify-center w-40 h-40 rounded-full shadow-[0_0_50px_rgba(37,99,235,0.2)] transition-all border-8 ${
                    isRecording ? 'bg-red-600 animate-pulse border-red-500 scale-110 shadow-[0_0_60px_rgba(220,38,38,0.4)]' : transcriptionMode === 'cloud' ? 'bg-blue-600 border-blue-500 hover:scale-105 shadow-[0_0_60px_rgba(37,99,235,0.3)]' : 'bg-green-600 border-green-500 shadow-[0_0_60px_rgba(22,163,74,0.3)]'
                }`}
            >
                {isRecording ? <StopCircleIcon className="w-20 h-20 text-white" /> : <MicIcon className="w-20 h-20 text-white" />}
            </button>

            <div className="w-full bg-gray-900 p-6 rounded-3xl border-2 border-gray-700 overflow-y-auto max-h-64 shadow-inner relative min-h-[150px]">
                {!liveTranscript && !isRecording && (
                    <div className="absolute inset-0 flex items-center justify-center text-gray-600 font-black uppercase text-sm tracking-widest pointer-events-none text-center p-6">
                        Tap Microphone to Start Recording
                    </div>
                )}
                <p className="text-xl text-gray-200 whitespace-pre-wrap font-bold leading-relaxed">
                    {liveTranscript}
                </p>
            </div>
          </main>

          <footer className="mt-8 flex gap-4 shrink-0">
              {isRecording ? (
                 <button onClick={stopRecording} className="flex-1 py-5 bg-red-600 text-white font-black rounded-2xl text-xl uppercase shadow-2xl active:scale-95 transition-all">FINISH RECORDING</button>
              ) : (
                 <button onClick={onCancel} className="flex-1 py-5 bg-gray-700 text-gray-400 font-black rounded-2xl text-lg uppercase active:scale-95 transition-all">Cancel</button>
              )}
          </footer>
        </div>
    );
  };

  return (
    <div 
        className="fixed inset-0 bg-black/90 flex flex-col items-center justify-center z-[100] p-4 animate-fade-in"
        onClick={handleBackgroundTap}
    >
      {renderContent()}
    </div>
  );
};

