export default Recorder;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { LiveSession, Modality } from '@google/genai';
import { MicIcon, StopCircleIcon, SaveIcon, XIcon, Loader2Icon, CheckIcon, PlayIcon, Volume2Icon } from './Icons';
import type { VoiceMemory } from '../types';
import { getCurrentLocation } from '../utils/location';
import { getGeminiInstance } from '../utils/gemini';
import { analyzeVoiceNote } from '../services/geminiService';

interface RecorderProps {
  onSave: (recording: Omit<VoiceMemory, 'id' | 'date'>) => void;
  onCancel: () => void;
  titlePlaceholder: string;
  saveButtonText: string;
  enableDiarization?: boolean;
}

const Recorder: React.FC<RecorderProps> = ({ onSave, onCancel, titlePlaceholder, saveButtonText }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [liveTranscript, setLiveTranscript] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [recordingTitle, setRecordingTitle] = useState('');
  const [extractedActionItems, setExtractedActionItems] = useState<string[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [audioDataUrl, setAudioDataUrl] = useState<string | undefined>(undefined);

  const finalTranscriptRef = useRef<string>('');
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const sessionPromiseRef = useRef<Promise<LiveSession> | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  const wakeLockRef = useRef<WakeLockSentinel | null>(null);

  const playBeep = useCallback((frequency: number, type: 'sine' | 'square' = 'sine', duration: number = 0.15) => {
    try {
        const Ctx = window.AudioContext || (window as any).webkitAudioContext;
        if (!Ctx) return;
        const ctx = new Ctx();
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.type = type;
        osc.frequency.setValueAtTime(frequency, ctx.currentTime);
        gain.gain.setValueAtTime(0.1, ctx.currentTime);
        gain.gain.exponentialRampToValueAtTime(0.00001, ctx.currentTime + duration);
        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.start();
        osc.stop(ctx.currentTime + duration);
    } catch (e) {}
  }, []);

  const requestWakeLock = async () => {
    if ('wakeLock' in navigator) {
      try { wakeLockRef.current = await navigator.wakeLock.request('screen'); } catch (err) {}
    }
  };

  const releaseWakeLock = async () => {
    if (wakeLockRef.current) {
      try { await wakeLockRef.current.release(); wakeLockRef.current = null; } catch (err) {}
    }
  };

  const startRecording = async () => {
    if (isRecording) return;
    setError(null);
    setLiveTranscript('');
    finalTranscriptRef.current = '';
    audioChunksRef.current = [];
    setAudioDataUrl(undefined);
    await requestWakeLock();
    playBeep(880, 'sine', 0.2);

    try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;

        const mediaRecorder = new MediaRecorder(stream);
        mediaRecorderRef.current = mediaRecorder;
        mediaRecorder.ondataavailable = (e) => {
            if (e.data.size > 0) audioChunksRef.current.push(e.data);
        };
        mediaRecorder.onstop = () => {
            const blob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
            const reader = new FileReader();
            reader.onloadend = () => setAudioDataUrl(reader.result as string);
            reader.readAsDataURL(blob);
        };
        mediaRecorder.start();

        const ai = getGeminiInstance();
        if (!ai) { setError("AI unavailable."); return; }
        setIsRecording(true);
        const context = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
        audioContextRef.current = context;
        sessionPromiseRef.current = ai.live.connect({
          model: 'gemini-2.5-flash-native-audio-preview-09-2025',
          callbacks: {
            onopen: () => {
              const source = context.createMediaStreamSource(stream);
              const scriptProcessor = context.createScriptProcessor(4096, 1, 1);
              scriptProcessorRef.current = scriptProcessor;
              scriptProcessor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);
                const int16 = new Int16Array(inputData.length);
                for (let i = 0; i < inputData.length; i++) {
                  let s = Math.max(-1, Math.min(1, inputData[i]));
                  int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
                }
                let binary = '';
                const bytes = new Uint8Array(int16.buffer);
                for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
                sessionPromiseRef.current?.then((s) => s.sendRealtimeInput({ media: { data: btoa(binary), mimeType: 'audio/pcm;rate=16000' } }));
              };
              source.connect(scriptProcessor);
              scriptProcessor.connect(context.destination);
            },
            onmessage: (m) => {
              if (m.serverContent?.inputTranscription) {
                const text = m.serverContent.inputTranscription.text;
                finalTranscriptRef.current += text;
                setLiveTranscript(prev => prev + text);
              }
            },
            onerror: () => {},
            onclose: () => {},
          },
          config: { 
            responseModalities: [Modality.AUDIO], 
            inputAudioTranscription: {},
            systemInstruction: `You are a professional, high-accuracy transcriptionist for a student who frequently switches between Hebrew and English (code-switching). 
            Rules:
            1. Transcribe EXACTLY what is said. 
            2. If the speaker uses Hebrew, transcribe using Hebrew characters. 
            3. If the speaker uses English, transcribe using English characters.
            4. NEVER translate. If they say a Hebrew word in an English sentence, keep the Hebrew word in Hebrew.
            5. Be extremely sensitive to language switches; do not try to "force" Hebrew sounds into English words or vice versa.`
          },
        });
    } catch (err) {
        setError('Microphone access denied.');
        await releaseWakeLock();
    }
  };

  const stopRecording = useCallback(async () => {
    if (!isRecording) return;
    setIsRecording(false); 
    playBeep(440, 'sine', 0.2);
    await releaseWakeLock();

    mediaRecorderRef.current?.stop();
    mediaStreamRef.current?.getTracks().forEach(t => t.stop());
    scriptProcessorRef.current?.disconnect();
    audioContextRef.current?.close();
    sessionPromiseRef.current?.then(s => s.close());

    if (finalTranscriptRef.current.trim()) {
      setIsSaving(true);
      setIsAnalyzing(true);
      try {
        const analysis = await analyzeVoiceNote(finalTranscriptRef.current);
        setRecordingTitle(analysis.title || titlePlaceholder);
        setExtractedActionItems(analysis.actionItems || []);
      } catch (error) {
        setRecordingTitle(titlePlaceholder);
      } finally {
        setIsAnalyzing(false);
      }
    } else {
      onCancel();
    }
  }, [isRecording, onCancel, titlePlaceholder, playBeep]);

  const handleSave = useCallback(async () => {
    const finalTranscript = finalTranscriptRef.current.trim();
    if (!finalTranscript) {
        onCancel();
        return;
    }

    const finalTitle = recordingTitle.trim() || titlePlaceholder;
    const location = await getCurrentLocation();
    onSave({
      type: 'voice',
      title: finalTitle,
      transcript: finalTranscript,
      audioDataUrl,
      actionItems: extractedActionItems.map(text => ({ text, done: false })),
      ...(location && { location }),
    } as Omit<VoiceMemory, 'id'|'date'>);
  }, [recordingTitle, audioDataUrl, extractedActionItems, onSave, onCancel, titlePlaceholder]);

  const handleBackgroundTap = () => {
    if (isSaving) {
        handleSave();
    } else if (!isRecording) {
        onCancel();
    }
  };

  const renderContent = () => {
    if (isSaving) {
        return (
          <div 
            className="bg-gray-800 rounded-[2.5rem] shadow-2xl w-full max-w-lg max-h-[95vh] border-4 border-gray-600 flex flex-col overflow-hidden"
            onClick={e => e.stopPropagation()}
          >
            <header className="flex justify-between items-center p-5 border-b-4 border-gray-700 shrink-0 bg-gray-800">
              <h2 className="text-lg font-black text-white uppercase tracking-tight">Review</h2>
              <button 
                  onClick={handleSave}
                  className="flex items-center gap-2 px-5 py-3 bg-blue-600 text-white font-black rounded-2xl text-sm uppercase shadow-xl active:scale-95 transition-all"
              >
                  <CheckIcon className="w-5 h-5"/> {saveButtonText}
              </button>
            </header>

            <main className="flex-grow overflow-y-auto p-5 space-y-5 scroll-smooth">
              <div className="space-y-4">
                  <div>
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-1.5 tracking-widest">Note Title</label>
                      <input
                          type="text"
                          value={recordingTitle}
                          onChange={(e) => setRecordingTitle(e.target.value)}
                          className="w-full bg-gray-900 text-white text-base p-4 rounded-2xl border-2 border-gray-700 outline-none focus:border-blue-600 font-bold shadow-inner"
                          placeholder="Enter Title"
                      />
                  </div>

                  {audioDataUrl && (
                      <div className="bg-gray-900 p-4 rounded-2xl border border-gray-700 shadow-inner flex items-center gap-4">
                          <div className="bg-blue-900/30 p-2 rounded-full"><Volume2Icon className="w-6 h-6 text-blue-400"/></div>
                          <audio src={audioDataUrl} controls className="flex-grow h-10" />
                      </div>
                  )}

                  <div className="space-y-2">
                      <label className="block text-[10px] font-black text-gray-500 uppercase mb-1 tracking-widest">Transcript</label>
                      <div className="w-full bg-gray-900 p-5 rounded-2xl border-2 border-gray-700 text-sm text-gray-200 leading-relaxed font-medium shadow-inner min-h-[150px]">
                          {isAnalyzing ? (
                              <div className="flex items-center gap-3 text-blue-400 font-black animate-pulse">
                                  <Loader2Icon className="w-5 h-5 animate-spin"/>
                                  ANALYZING NOTE...
                              </div>
                          ) : (
                              <div className="whitespace-pre-wrap">{finalTranscriptRef.current}</div>
                          )}
                      </div>
                  </div>

                  {extractedActionItems.length > 0 && (
                      <div className="space-y-2.5 pb-4">
                          <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest">Detected Tasks</label>
                          <div className="space-y-1.5">
                              {extractedActionItems.map((item, i) => (
                                  <div key={i} className="bg-gray-700/50 p-3 rounded-xl border border-gray-600 text-xs font-bold text-gray-300 flex items-center gap-3">
                                      <div className="w-2 h-2 rounded-full bg-blue-500 shrink-0"/> {item}
                                  </div>
                              ))}
                          </div>
                      </div>
                  )}
              </div>
            </main>

            <footer className="p-3 border-t-2 border-gray-700 bg-gray-800 shrink-0 text-center">
              <button 
                onClick={onCancel}
                className="px-6 py-2 text-gray-500 font-black uppercase text-[10px] tracking-widest hover:text-red-400 transition-colors"
              >
                Discard and Close
              </button>
            </footer>
          </div>
        );
    }

    return (
        <div 
            className="bg-gray-800 p-4 rounded-[2.5rem] shadow-2xl border-4 border-gray-700 w-full max-w-lg h-full max-h-[85vh] flex flex-col overflow-hidden"
            onClick={e => e.stopPropagation()}
        >
          <header className="flex justify-between items-center mb-3 shrink-0">
              <div className="flex items-center gap-2">
                  <div className="bg-blue-600/20 px-3 py-1.5 rounded-xl border border-blue-500/30">
                      <span className="text-blue-400 font-black text-[9px] uppercase tracking-widest">AI Mode Active</span>
                  </div>
              </div>
              <button onClick={onCancel} className="p-2.5 bg-gray-700 rounded-xl text-gray-400 active:scale-90 transition-transform"><XIcon className="w-5 h-5"/></button>
          </header>

          <main className="flex-grow flex flex-col items-center justify-center gap-4 overflow-hidden px-1">
            <button
                onClick={isRecording ? stopRecording : startRecording}
                className={`flex items-center justify-center w-32 h-32 rounded-full shadow-[0_0_40px_rgba(37,99,235,0.2)] transition-all border-8 shrink-0 ${
                    isRecording ? 'bg-red-600 animate-pulse border-red-500 scale-105 shadow-[0_0_50px_rgba(220,38,38,0.4)]' : 'bg-blue-600 border-blue-500 hover:scale-105 shadow-[0_0_50px_rgba(37,99,235,0.3)]'
                }`}
            >
                {isRecording ? <StopCircleIcon className="w-14 h-14 text-white" /> : <MicIcon className="w-14 h-14 text-white" />}
            </button>

            <div className="w-full bg-gray-900 p-5 rounded-3xl border-2 border-gray-700 overflow-y-auto flex-grow max-h-48 shadow-inner relative">
                {!liveTranscript && !isRecording && (
                    <div className="absolute inset-0 flex items-center justify-center text-gray-600 font-black uppercase text-xs tracking-widest pointer-events-none text-center p-4">
                        Tap Microphone to Start Recording
                    </div>
                )}
                <p className="text-lg text-gray-200 whitespace-pre-wrap font-bold leading-relaxed">
                    {liveTranscript}
                </p>
            </div>
          </main>

          <footer className="mt-4 flex gap-3 shrink-0">
              {isRecording ? (
                 <button onClick={stopRecording} className="flex-1 py-4 bg-red-600 text-white font-black rounded-2xl text-lg uppercase shadow-2xl active:scale-95 transition-all">FINISH RECORDING</button>
              ) : (
                 <button onClick={onCancel} className="flex-1 py-4 bg-gray-700 text-gray-400 font-black rounded-2xl text-base uppercase active:scale-95 transition-all">Cancel</button>
              )}
          </footer>
        </div>
    );
  };

  return (
    <div 
        className="fixed inset-0 bg-black/90 flex flex-col items-center justify-center z-[100] p-4 animate-fade-in"
        onClick={handleBackgroundTap}
    >
      {renderContent()}
    </div>
  );
};

export default Recorder;

import { GoogleGenAI, Modality, Type, FunctionDeclaration } from "@google/genai";
import { getGeminiInstance } from '../utils/gemini';
import type { AnyMemory, Task, CalendarEvent } from '../types';

const model = "gemini-3-pro-preview";
const UNAVAILABLE_ERROR_MESSAGE = "AI features are unavailable. Please check your API key configuration.";

// --- Tool Definitions ---

const createCalendarEventTool: FunctionDeclaration = {
  name: "createCalendarEvent",
  description: "Schedules a time slot or event in the user's calendar.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING, description: "The title of the event" },
      startTime: { type: Type.STRING, description: "ISO 8601 formatted start time" },
      endTime: { type: Type.STRING, description: "ISO 8601 formatted end time" },
      category: { type: Type.STRING, enum: ["college", "personal"], description: "The category of the event" },
      description: { type: Type.STRING, description: "Optional details about the event" }
    },
    required: ["title", "startTime", "endTime", "category"]
  }
};

const listCalendarEventsTool: FunctionDeclaration = {
  name: "listCalendarEvents",
  description: "Lists existing calendar events for a specific date range.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      startDate: { type: Type.STRING, description: "ISO 8601 formatted start date" },
      endDate: { type: Type.STRING, description: "ISO 8601 formatted end date" }
    },
    required: ["startDate"]
  }
};

export async function answerQuestionFromContext(
    memories: AnyMemory[], 
    tasks: Task[], 
    question: string,
    calendarEvents: CalendarEvent[] = [],
    onToolCall?: (toolCall: any) => Promise<any>
): Promise<string> {
  const ai = getGeminiInstance();
  if (!ai) return UNAVAILABLE_ERROR_MESSAGE;

  const memoryContext = memories.map(mem => `[NOTE] ${mem.title}: ${mem.type === 'voice' ? mem.transcript : ''}`).join('\n');
  const taskContext = tasks.map(t => `[TASK] ${t.title} (${t.status})`).join('\n');
  const calendarContext = calendarEvents.map(e => `[CALENDAR] ${e.startTime} - ${e.endTime}: ${e.title}`).join('\n');

  const systemInstruction = `You are a bilingual (EN/HE) personal assistant for a visually impaired student.
  You have access to their Memories, Tasks, and Calendar.
  The user speaks a mix of Hebrew and English. Always reply in the language the user used for their question, or use both if appropriate.
  If the user asks to schedule something, use the 'createCalendarEvent' tool.
  If the user asks about their schedule, use 'listCalendarEvents' or refer to the context.
  Current Date/Time: ${new Date().toLocaleString()}`;

  try {
    const response = await ai.models.generateContent({
        model,
        contents: `CONTEXT:\n${memoryContext}\n${taskContext}\n${calendarContext}\n\nUSER:\n${question}`,
        config: {
            systemInstruction,
            tools: [{ functionDeclarations: [createCalendarEventTool, listCalendarEventsTool] }]
        },
    });

    if (response.functionCalls && onToolCall) {
        let finalResponse = "";
        for (const call of response.functionCalls) {
            const result = await onToolCall(call);
            // Send result back for final text generation
            const finalResult = await ai.models.generateContent({
                model,
                contents: [
                    { role: 'user', parts: [{ text: question }] },
                    { role: 'model', parts: [{ functionCall: call }] },
                    { role: 'user', parts: [{ functionResponse: { name: call.name, response: { result } } }] }
                ]
            });
            finalResponse += finalResult.text;
        }
        return finalResponse || "I've processed that for you.";
    }

    return response.text ?? "I'm not sure how to help with that.";
  } catch (error) {
    console.error(error);
    return "Error processing request.";
  }
}

export async function analyzeVoiceNote(content: string): Promise<{ title: string; actionItems: string[] }> {
    const ai = getGeminiInstance();
    if (!ai) return { title: "Untitled", actionItems: [] };
    try {
        const response = await ai.models.generateContent({
            model,
            contents: `Analyze the following voice note transcript. It may contain a mix of Hebrew and English.
            Provide a concise title and a list of specific action items.
            The title and tasks should be in the language that makes the most sense based on the content (Hebrew or English).
            If the note is mostly Hebrew, keep the output in Hebrew. If it's mixed, provide the most clear summary possible.
            Transcript: ${content.substring(0, 4000)}`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING, description: "A summary title in English or Hebrew" },
                        actionItems: { type: Type.ARRAY, items: { type: Type.STRING }, description: "List of tasks found in the note" }
                    },
                    required: ["title", "actionItems"]
                }
            }
        });
        return JSON.parse(response.text || "{}");
    } catch (error) {
        return { title: "Voice Note", actionItems: [] };
    }
}

export async function generateSummaryForContent(content: string): Promise<string> {
    const ai = getGeminiInstance();
    if (!ai || !content.trim()) return "";
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Summarize the following content in a concise way for a student. The text might be in English, Hebrew, or both. Preserve the language context: ${content.substring(0, 4000)}`,
            config: { 
                systemInstruction: "You are a helpful student assistant. Provide a one-sentence summary. Maintain the language of the source text."
            },
        });
        return (response.text ?? "").trim();
    } catch (error) { 
        return ""; 
    }
}

export async function generateTitleForContent(content: string): Promise<string> {
    const ai = getGeminiInstance();
    if (!ai || !content.trim()) return "Untitled";
    try {
        const response = await ai.models.generateContent({
            model,
            contents: `Generate a short title for this text (may be HE/EN mix): ${content.substring(0, 1000)}`,
            config: { systemInstruction: "Generate a short title. Keep it in the dominant language of the text.", stopSequences: ['\n'] },
        });
        return (response.text ?? "Untitled").trim().replace(/"/g, ''); 
    } catch (error) { return "Untitled"; }
}

export async function generateSpeechFromText(text: string): Promise<string | null> {
    const ai = getGeminiInstance();
    if (!ai) return null;
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text }] }],
            config: { responseModalities: [Modality.AUDIO], speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } } },
        });
        return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || null;
    } catch (error) { return null; }
}

export async function extractTextFromImage(base64Data: string, mimeType: string): Promise<string> {
    const ai = getGeminiInstance();
    if (!ai) return UNAVAILABLE_ERROR_MESSAGE;
    try {
        const response = await ai.models.generateContent({
            model,
            contents: { 
                parts: [
                    { inlineData: { mimeType, data: base64Data } }, 
                    { text: `You are an expert OCR system. Extract ALL text from this image with extreme precision. 
                             The text is in Hebrew and potentially English.
                             If the document contains a table, schedule, or timetable, preserve its structure using Markdown table format. 
                             Maintain the correct reading order (Right-to-Left for Hebrew).
                             Output ONLY the extracted content.` 
                    }
                ] 
            },
        });
        return response.text ?? "No text found.";
    } catch (error) { 
        console.error("OCR Error:", error);
        return "Error extracting text. Please check the image quality."; 
    }
}

import React, { useState, useEffect, useRef } from 'react';
import type { DocumentMemory } from '../types';
import { generateTitleForContent, extractTextFromImage } from '../services/geminiService';
import { getCurrentLocation } from '../utils/location';
import { generatePDF } from '../services/pdfService';
import { CameraIcon, UploadIcon, SaveIcon, XIcon, BrainCircuitIcon, Loader2Icon, FileTextIcon, CheckIcon } from './Icons';

interface AddDocumentModalProps {
    course?: string; 
    onSave: (memory: Omit<DocumentMemory, 'id'|'date'>) => void;
    onClose: () => void;
}

const AddDocumentModal: React.FC<AddDocumentModalProps> = ({ course, onSave, onClose }) => {
    const [title, setTitle] = useState('');
    const [imageDataUrl, setImageDataUrl] = useState<string | null>(null);
    const [extractedText, setExtractedText] = useState('');
    const [isLoading, setIsLoading] = useState<'camera'|'ocr'|'title'|null>(null);
    const [error, setError] = useState<string|null>(null);
    const [stream, setStream] = useState<MediaStream | null>(null);
    const [statusMessage, setStatusMessage] = useState(''); 

    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const titleInputRef = useRef<HTMLInputElement>(null);

    const stopCamera = React.useCallback(() => {
        if (stream) {
            stream.getTracks().forEach(track => track.stop());
            setStream(null);
        }
    }, [stream]);

    useEffect(() => { return () => { stopCamera(); }; }, [stopCamera]);

    useEffect(() => {
        if (extractedText && titleInputRef.current) {
            titleInputRef.current.focus();
        }
    }, [extractedText]);

    const startCamera = async () => {
        stopCamera();
        setImageDataUrl(null);
        setError(null);
        setIsLoading('camera');
        setStatusMessage("Starting camera...");
        try {
            const mediaStream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
            setStream(mediaStream);
            setStatusMessage("Camera started.");
        } catch (err) { 
            setError("Could not access camera."); 
            setStatusMessage("Error: Could not access camera.");
        }
        finally { setIsLoading(null); }
    };

    useEffect(() => { if (stream && videoRef.current) { videoRef.current.srcObject = stream; } }, [stream]);

    const takePicture = () => {
        if (videoRef.current && canvasRef.current) {
            const video = videoRef.current;
            const canvas = canvasRef.current;
            canvas.width = video.videoWidth;
            canvas.height = video.videoHeight;
            canvas.getContext('2d')?.drawImage(video, 0, 0, video.videoWidth, video.videoHeight);
            const dataUrl = canvas.toDataURL('image/jpeg');
            setImageDataUrl(dataUrl);
            stopCamera();
            setStatusMessage("Picture taken.");
        }
    };

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file && file.type.startsWith('image/')) {
            const reader = new FileReader();
            reader.onload = (e) => {
                setImageDataUrl(e.target?.result as string);
                stopCamera();
                setStatusMessage("Image uploaded.");
            };
            reader.readAsDataURL(file);
        } else {
            setError('Please select a valid image file.');
        }
    };

    const handleExtractText = async () => {
        if (!imageDataUrl) return;
        setIsLoading('ocr');
        setError(null);
        setStatusMessage("Extracting Hebrew and English text from image...");
        try {
            const base64Data = imageDataUrl.split(',')[1];
            const mimeType = imageDataUrl.match(/data:([^;]+);/)?.[1] || 'image/jpeg';
            const text = await extractTextFromImage(base64Data, mimeType);
            setExtractedText(text);
            setStatusMessage("Text extracted successfully.");

            // Auto-generate title if empty
            if (!title) {
                const generatedTitle = await generateTitleForContent(text);
                setTitle(generatedTitle);
            }
        } catch (e) { 
            setError("Text extraction failed. You can still save the image or try again."); 
            setStatusMessage("Error extracting text.");
        }
        finally { setIsLoading(null); }
    };

    const handleGenerateTitle = async () => {
        if (!extractedText.trim()) return;
        setIsLoading('title');
        setTitle(await generateTitleForContent(extractedText));
        setIsLoading(null);
        setStatusMessage("Title generated.");
    };

    const handleSave = async () => {
        if (!imageDataUrl) return;

        // Use default title if none provided
        const finalTitle = title.trim() || `Scanned Doc - ${new Date().toLocaleDateString()}`;
        const finalContent = extractedText.trim() || "No text extracted yet.";

        const location = await getCurrentLocation();
        onSave({ 
            type: 'document', 
            title: finalTitle, 
            imageDataUrl, 
            extractedText: finalContent, 
            category: course ? 'college' : 'personal',
            course, 
            ...(location && { location }) 
        });
        onClose();
    };

    const isSaveDisabled = !imageDataUrl;

    return (
        <div className="fixed inset-0 bg-black/90 flex flex-col justify-center items-center z-[130] p-4">
             <div className="bg-gray-800 rounded-[2.5rem] shadow-2xl w-full max-w-2xl max-h-[95vh] flex flex-col border-4 border-gray-600 overflow-hidden">
                <header className="flex justify-between items-center p-6 border-b-4 border-gray-700 shrink-0 bg-gray-800">
                    <h2 className="text-xl font-black text-white flex items-center gap-3 uppercase">
                        <FileTextIcon className="w-8 h-8"/> SCAN DOCUMENT
                    </h2>
                    <div className="flex items-center gap-3">
                        <button 
                            onClick={handleSave} 
                            disabled={isSaveDisabled} 
                            className="flex items-center gap-2 px-5 py-3 bg-blue-600 text-white font-black rounded-xl text-sm uppercase shadow-xl disabled:bg-gray-700 active:scale-95 transition-all"
                        >
                            <SaveIcon className="w-5 h-5"/> SAVE
                        </button>
                        <button onClick={onClose} className="p-3 bg-gray-700 rounded-2xl active:scale-90 transition-transform"><XIcon className="w-6 h-6"/></button>
                    </div>
                </header>

                <div role="status" aria-live="polite" className="sr-only">
                    {statusMessage}
                </div>

                <div className="flex-grow overflow-y-auto p-6 space-y-6 scroll-smooth">
                    {extractedText || isLoading === 'ocr' ? (
                        <div className="space-y-6">
                            <div className="w-full bg-gray-900 rounded-2xl p-2 border border-gray-700 flex justify-center items-center shadow-inner">
                                <img src={imageDataUrl || ''} className="max-h-48 object-contain rounded-xl"/>
                            </div>

                            <div className="space-y-3">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Document Name</label>
                                <div className="flex gap-2">
                                    <input 
                                        ref={titleInputRef}
                                        type="text" 
                                        value={title} 
                                        onChange={e => setTitle(e.target.value)} 
                                        placeholder="Enter Title" 
                                        className="flex-grow bg-gray-900 text-white text-base p-4 rounded-2xl border-2 border-gray-700 outline-none focus:border-blue-600 font-bold shadow-inner"
                                    />
                                    <button onClick={handleGenerateTitle} className="p-4 bg-purple-600 text-white rounded-2xl shadow-lg active:scale-95">
                                        {isLoading === 'title' ? <Loader2Icon className="w-6 h-6 animate-spin"/> : <BrainCircuitIcon className="w-6 h-6"/>}
                                    </button>
                                </div>
                            </div>

                            <div className="space-y-3">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Extracted Content</label>
                                {isLoading === 'ocr' ? (
                                    <div className="w-full bg-gray-900 p-10 rounded-2xl border-2 border-gray-700 flex flex-col items-center justify-center gap-4 text-blue-400">
                                        <Loader2Icon className="w-10 h-10 animate-spin" />
                                        <p className="font-black uppercase tracking-widest text-xs">Analyzing Layout & Hebrew Text...</p>
                                    </div>
                                ) : (
                                    <textarea 
                                        value={extractedText} 
                                        onChange={e => setExtractedText(e.target.value)} 
                                        rows={8} 
                                        className="w-full bg-gray-900 text-white text-sm p-5 rounded-2xl border-2 border-gray-700 outline-none focus:border-blue-600 font-medium leading-relaxed shadow-inner"
                                    />
                                )}
                            </div>
                        </div>
                    ) : imageDataUrl ? (
                        <div className="space-y-6 text-center">
                            <div className="rounded-[2rem] overflow-hidden border-2 border-gray-700 shadow-2xl">
                                <img src={imageDataUrl} className="w-full max-h-80 object-contain bg-black" />
                            </div>
                            <div className="flex gap-3 justify-center">
                                <button onClick={() => setImageDataUrl(null)} className="flex-1 py-4 bg-gray-700 text-white font-black rounded-2xl uppercase text-xs">Retake</button>
                                <button onClick={handleExtractText} disabled={isLoading === 'ocr'} className="flex-grow py-4 bg-blue-600 text-white font-black rounded-2xl uppercase text-xs shadow-lg flex items-center justify-center gap-3">
                                     {isLoading === 'ocr' ? <Loader2Icon className="animate-spin w-5 h-5"/> : <BrainCircuitIcon className="w-5 h-5"/>}
                                     Extract Text
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="space-y-6 text-center">
                            <div className="w-full aspect-square bg-gray-900 rounded-[2.5rem] flex items-center justify-center relative overflow-hidden border-2 border-gray-700 shadow-inner">
                                <canvas ref={canvasRef} className="hidden" />
                                {stream ? <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
                                    : <CameraIcon className="w-24 h-24 mx-auto text-gray-500" />
                                }
                            </div>
                            {stream ? (
                                <button onClick={takePicture} className="px-10 py-5 bg-blue-600 text-white font-black rounded-2xl uppercase text-sm shadow-xl active:scale-95 transition-all">
                                    CAPTURE
                                </button>
                            ) : (
                                 <div className="flex gap-3">
                                    <button onClick={startCamera} className="flex-1 py-4 bg-gray-700 text-white font-black rounded-2xl uppercase text-xs flex items-center justify-center gap-2">
                                       <CameraIcon className="w-5 h-5"/> Camera
                                    </button>
                                     <button onClick={() => fileInputRef.current?.click()} className="flex-1 py-4 bg-gray-700 text-white font-black rounded-2xl uppercase text-xs flex items-center justify-center gap-2">
                                        <UploadIcon className="w-5 h-5"/> File
                                    </button>
                                     <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
                                </div>
                            )}
                        </div>
                    )}
                    {error && <p className="text-center text-red-400 font-bold p-3 bg-red-900/20 rounded-xl">{error}</p>}
                </div>

                <footer className="p-4 bg-gray-800 border-t-2 border-gray-700 shrink-0 text-center">
                    <button onClick={onClose} className="text-gray-500 font-black uppercase text-xs tracking-widest">Cancel Scan</button>
                </footer>
            </div>
        </div>
    );
};

export default AddDocumentModal;

