import { GoogleGenAI, Modality, Type, FunctionDeclaration } from "@google/genai";
import { getGeminiInstance } from '../utils/gemini';
import type { AnyMemory, Task, CalendarEvent } from '../types';

const model = "gemini-3-pro-preview";
const UNAVAILABLE_ERROR_MESSAGE = "AI features are unavailable. Please check your API key configuration.";

// --- Tool Definitions ---

const createCalendarEventTool: FunctionDeclaration = {
  name: "createCalendarEvent",
  description: "Schedules a time slot or event in the user's calendar.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING, description: "The title of the event" },
      startTime: { type: Type.STRING, description: "ISO 8601 formatted start time" },
      endTime: { type: Type.STRING, description: "ISO 8601 formatted end time" },
      category: { type: Type.STRING, enum: ["college", "personal"], description: "The category of the event" },
      description: { type: Type.STRING, description: "Optional details about the event" }
    },
    required: ["title", "startTime", "endTime", "category"]
  }
};

const listCalendarEventsTool: FunctionDeclaration = {
  name: "listCalendarEvents",
  description: "Lists existing calendar events for a specific date range.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      startDate: { type: Type.STRING, description: "ISO 8601 formatted start date" },
      endDate: { type: Type.STRING, description: "ISO 8601 formatted end date" }
    },
    required: ["startDate"]
  }
};

export async function answerQuestionFromContext(
    memories: AnyMemory[], 
    tasks: Task[], 
    question: string,
    calendarEvents: CalendarEvent[] = [],
    onToolCall?: (toolCall: any) => Promise<any>
): Promise<string> {
  const ai = getGeminiInstance();
  if (!ai) return UNAVAILABLE_ERROR_MESSAGE;

  const memoryContext = memories.map(mem => `[NOTE] ${mem.title}: ${mem.type === 'voice' ? (mem as any).transcript || '' : (mem as any).content || ''}`).join('\n');
  const taskContext = tasks.map(t => `[TASK] ${t.title} (${t.status})`).join('\n');
  const calendarContext = calendarEvents.map(e => `[CALENDAR] ${e.startTime} - ${e.endTime}: ${e.title}`).join('\n');

  const systemInstruction = `You are a bilingual (EN/HE) personal assistant for a visually impaired student.
  You have access to their Memories, Tasks, and Calendar.
  The user speaks a mix of Hebrew and English. Always reply in the language the user used for their question, or use both if appropriate.
  If the user asks to schedule something, use the 'createCalendarEvent' tool.
  If the user asks about their schedule, use 'listCalendarEvents' or refer to the context.
  Current Date/Time: ${new Date().toLocaleString()}`;

  try {
    const response = await ai.models.generateContent({
        model,
        contents: `CONTEXT:\n${memoryContext}\n${taskContext}\n${calendarContext}\n\nUSER:\n${question}`,
        config: {
            systemInstruction,
            tools: [{ functionDeclarations: [createCalendarEventTool, listCalendarEventsTool] }]
        },
    });

    if (response.functionCalls && onToolCall) {
        let finalResponse = "";
        for (const call of response.functionCalls) {
            const result = await onToolCall(call);
            // Send result back for final text generation
            const finalResult = await ai.models.generateContent({
                model,
                contents: [
                    { role: 'user', parts: [{ text: question }] },
                    { role: 'model', parts: [{ functionCall: call }] },
                    { role: 'user', parts: [{ functionResponse: { name: call.name, response: { result } } }] }
                ]
            });
            finalResponse += finalResult.text;
        }
        return finalResponse || "I've processed that for you.";
    }

    return response.text ?? "I'm not sure how to help with that.";
  } catch (error) {
    console.error(error);
    return "Error processing request.";
  }
}

export async function processSharedUrl(url: string, title: string, text: string): Promise<{ 
    title: string; 
    summary: string; 
    type: 'Article' | 'Video'; 
    takeaways: string[] 
}> {
    const ai = getGeminiInstance();
    if (!ai) throw new Error("AI Unavailable");

    const isYoutube = url.includes('youtube.com') || url.includes('youtu.be');
    const contentType = isYoutube ? 'Video' : 'Article';

    try {
        const response = await ai.models.generateContent({
            model,
            contents: `Analyze this shared link. 
            URL: ${url}
            Shared Title: ${title}
            Shared Text: ${text}

            Based on this information, summarize what this content likely is. 
            Identify if it is a Video or an Article. 
            Provide 3 key takeaways based on the shared context.
            Respond in the language of the shared title/text (Hebrew or English).`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        summary: { type: Type.STRING },
                        type: { type: Type.STRING, enum: ['Article', 'Video'] },
                        takeaways: { type: Type.ARRAY, items: { type: Type.STRING } }
                    },
                    required: ["title", "summary", "type", "takeaways"]
                }
            }
        });
        return JSON.parse(response.text || "{}");
    } catch (error) {
        return { 
            title: title || "Shared Content", 
            summary: text || "A link shared from another app.", 
            type: contentType, 
            takeaways: ["Shared for later review"] 
        };
    }
}

export async function analyzeVoiceNote(content: string): Promise<{ title: string; actionItems: string[] }> {
    const ai = getGeminiInstance();
    if (!ai) return { title: "Untitled", actionItems: [] };
    try {
        const response = await ai.models.generateContent({
            model,
            contents: `Analyze the following voice note transcript. It may contain a mix of Hebrew and English.
            Provide a concise title and a list of specific action items.
            The title and tasks should be in the language that makes the most sense based on the content (Hebrew or English).
            If the note is mostly Hebrew, keep the output in Hebrew. If it's mixed, provide the most clear summary possible.
            Transcript: ${content.substring(0, 4000)}`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING, description: "A summary title in English or Hebrew" },
                        actionItems: { type: Type.ARRAY, items: { type: Type.STRING }, description: "List of tasks found in the note" }
                    },
                    required: ["title", "actionItems"]
                }
            }
        });
        return JSON.parse(response.text || "{}");
    } catch (error) {
        return { title: "Voice Note", actionItems: [] };
    }
}

export async function generateSummaryForContent(content: string): Promise<string> {
    const ai = getGeminiInstance();
    if (!ai || !content.trim()) return "";
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Summarize the following content in a concise way for a student. The text might be in English, Hebrew, or both. Preserve the language context: ${content.substring(0, 4000)}`,
            config: { 
                systemInstruction: "You are a helpful student assistant. Provide a one-sentence summary. Maintain the language of the source text."
            },
        });
        return (response.text ?? "").trim();
    } catch (error) { 
        return ""; 
    }
}

export async function generateTitleForContent(content: string): Promise<string> {
    const ai = getGeminiInstance();
    if (!ai || !content.trim()) return "Untitled";
    try {
        const response = await ai.models.generateContent({
            model,
            contents: `Generate a short title for this text (may be HE/EN mix): ${content.substring(0, 1000)}`,
            config: { systemInstruction: "Generate a short title. Keep it in the dominant language of the text.", stopSequences: ['\n'] },
        });
        return (response.text ?? "Untitled").trim().replace(/"/g, ''); 
    } catch (error) { return "Untitled"; }
}

export async function generateSpeechFromText(text: string): Promise<string | null> {
    const ai = getGeminiInstance();
    if (!ai) return null;
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text }] }],
            config: { responseModalities: [Modality.AUDIO], speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } } },
        });
        return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || null;
    } catch (error) { return null; }
}

export async function extractTextFromImage(base64Data: string, mimeType: string): Promise<string> {
    const ai = getGeminiInstance();
    if (!ai) return UNAVAILABLE_ERROR_MESSAGE;
    try {
        const response = await ai.models.generateContent({
            model,
            contents: { 
                parts: [
                    { inlineData: { mimeType, data: base64Data } }, 
                    { text: `You are an expert OCR system. Extract ALL text from this image with extreme precision. 
                             The text is in Hebrew and potentially English.
                             If the document contains a table, schedule, or timetable, preserve its structure using Markdown table format. 
                             Maintain the correct reading order (Right-to-Left for Hebrew).
                             Output ONLY the extracted content.` 
                    }
                ] 
            },
        });
        return response.text ?? "No text found.";
    } catch (error) { 
        console.error("OCR Error:", error);
        return "Error extracting text. Please check the image quality."; 
    }
}

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import BottomNavBar from './components/BottomNavBar';
import Sidebar from './components/Sidebar';
import CollegeView from './components/CollegeView';
import QASession from './components/QASession';
import VisionView from './components/VisionView';
import WebClipsView from './components/WebClipsView';
import PersonalView from './components/PersonalView';
import ScheduleView from './components/ScheduleView';
import FilesView from './components/FilesView';
import UpdateNotification from './components/UpdateNotification';
import SyncSetup from './components/SyncSetup';
import SettingsModal from './components/SettingsModal';
import AddWebMemoryModal from './components/AddWebMemoryModal';
import TopInstallBanner from './components/TopInstallBanner';
import { useRecordings } from './hooks/useRecordings';
import { useServiceWorker } from './hooks/useServiceWorker';
import { fetchMoodleEvents } from './services/moodleService';
import { processSharedUrl } from './services/geminiService';
import type { AnyMemory, WebMemory, CalendarEvent, Task } from './types';
import { SettingsIcon, Loader2Icon, BrainCircuitIcon, CalendarIcon } from './components/Icons';

export type View = 'physical' | 'college' | 'webclips' | 'askai' | 'voicenotes' | 'files';

const viewTitles: Record<View, string> = {
    physical: 'Items',
    college: 'College',
    webclips: 'Web Clips',
    askai: 'Ask AI',
    voicenotes: 'Personal',
    files: 'Files',
};

function App() {
  const [view, setView] = useState<View>('college');
  const [showSettings, setShowSettings] = useState(false);
  const [showSchedule, setShowSchedule] = useState(false);
  const [calendarEvents, setCalendarEvents] = useState<CalendarEvent[]>([]);
  const [moodleEvents, setMoodleEvents] = useState<CalendarEvent[]>([]);
  const [sharedContent, setSharedContent] = useState<{ url: string; title: string } | null>(null);
  const [isProcessingShare, setIsProcessingShare] = useState(false);

  const { 
    memories, addMemory, deleteMemory, updateMemory, bulkDeleteMemories,
    tasks, addTask, updateTask, deleteTask, 
    courses, addCourse, user, loading,
    moodleToken, saveMoodleToken,
  } = useRecordings();

  const { updateAvailable, updateServiceWorker } = useServiceWorker();

  const allCalendarEvents = useMemo(() => [...calendarEvents, ...moodleEvents], [calendarEvents, moodleEvents]);

  const handleProcessShare = useCallback(async (url: string, title: string, text: string) => {
    setIsProcessingShare(true);
    try {
      const analysis = await processSharedUrl(url, title, text);
      await addMemory({
        type: 'web',
        url: url,
        title: analysis.title,
        content: analysis.summary,
        contentType: analysis.type,
        category: 'personal',
        tags: analysis.takeaways
      } as Omit<WebMemory, 'id' | 'date'>);

      setView('webclips');
    } catch (error) {
      console.error("Failed to process share automatically", error);
      // Fallback: show the manual modal if AI fails
      setSharedContent({ url, title: title || text || 'Shared Link' });
    } finally {
      setIsProcessingShare(false);
    }
  }, [addMemory]);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const hasSharedParam = params.has('shared') || params.has('url') || params.has('text') || params.has('title');

    if (hasSharedParam) {
      const title = params.get('title') || '';
      const text = params.get('text') || '';
      const url = params.get('url') || '';

      let detectedUrl = url;
      let detectedTitle = title;
      let detectedText = text;

      // Extract URL from text if needed
      if (!detectedUrl && text.includes('http')) {
        const urlMatch = text.match(/(https?:\/\/[^\s]+)/);
        if (urlMatch) {
          detectedUrl = urlMatch[0];
          if (!detectedTitle) detectedTitle = text.replace(detectedUrl, '').trim();
        }
      }

      if (detectedUrl) {
        handleProcessShare(detectedUrl, detectedTitle, detectedText);
      } else if (detectedTitle || detectedText) {
        // Just text shared, show manual modal
        setSharedContent({ url: '', title: detectedTitle || detectedText || 'Shared Text' });
        setView('webclips');
      }

      // Clean URL to prevent re-triggering on refresh
      window.history.replaceState({}, document.title, window.location.pathname);
    }
  }, [handleProcessShare]);

  useEffect(() => {
    const getMoodleEvents = async () => {
      if (moodleToken) {
        const events = await fetchMoodleEvents(moodleToken);
        setMoodleEvents(events);
      } else {
        setMoodleEvents([]);
      }
    };
    getMoodleEvents();
  }, [moodleToken]);

  const addCalendarEvent = (event: Omit<CalendarEvent, 'id'>) => {
    const newEvent = { ...event, id: Date.now().toString(), source: 'manual' as const };
    setCalendarEvents(prev => [...prev, newEvent].sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime()));
  };

  const deleteCalendarEvent = (eventId: string) => {
      if (window.confirm('Are you sure you want to delete this event?')) {
          setCalendarEvents(prev => prev.filter(e => e.id !== eventId));
      }
  };

  const handleSaveSharedClip = (memory: Omit<WebMemory, 'id' | 'date' | 'category'>) => {
    addMemory({ ...memory, category: 'personal' });
    setSharedContent(null);
  };

  if (loading) return <div className="flex h-screen items-center justify-center bg-gray-900"><Loader2Icon className="w-20 h-20 animate-spin text-blue-500" /></div>;
  if (!user) return <SyncSetup onSyncIdSet={() => {}} />;

  const renderView = () => {
    switch (view) {
      case 'physical': return <VisionView memories={memories.filter(m => m.type === 'item' || m.type === 'video')} onDelete={deleteMemory} onUpdate={updateMemory} onSave={addMemory} bulkDelete={bulkDeleteMemories} />;
      case 'college': return <CollegeView lectures={memories.filter(m => m.category === 'college')} onDelete={deleteMemory} onUpdate={updateMemory} onSave={addMemory} bulkDelete={bulkDeleteMemories} courses={courses} addCourse={addCourse} tasks={tasks} addTask={addTask} updateTask={updateTask} deleteTask={deleteTask} />;
      case 'webclips': return <WebClipsView memories={memories.filter(m => m.type === 'web')} onDelete={deleteMemory} onUpdate={updateMemory} onSave={addMemory} syncSharedClips={async()=>0} pendingClipsCount={0} bulkDelete={bulkDeleteMemories}/>;
      case 'askai': return <QASession memories={memories} tasks={tasks} calendarEvents={allCalendarEvents} onAddCalendarEvent={addCalendarEvent} />;
      case 'voicenotes': return <PersonalView memories={memories.filter(m => m.category === 'personal')} tasks={tasks} onSaveMemory={addMemory} onDeleteMemory={deleteMemory} onUpdateMemory={updateMemory} bulkDeleteMemories={bulkDeleteMemories} onAddTask={addTask} onUpdateTask={updateTask} onDeleteTask={deleteTask} />;
      case 'files': return <FilesView memories={memories} onSave={addMemory} onDelete={deleteMemory} onUpdate={updateMemory} />;
      default: return <QASession memories={memories} tasks={tasks} />;
    }
  };

  return (
    <div className="fixed inset-0 bg-[#0b0f1a] text-white flex flex-col md:flex-row overflow-hidden overscroll-none">
      {isProcessingShare && (
        <div className="fixed inset-0 z-[300] bg-black/90 flex flex-col items-center justify-center p-10 text-center animate-fade-in">
          <div className="bg-blue-600/20 p-10 rounded-[3rem] border-4 border-blue-500 shadow-[0_0_50px_rgba(37,99,235,0.3)] flex flex-col items-center gap-8">
            <BrainCircuitIcon className="w-24 h-24 text-blue-400 animate-pulse" />
            <div className="space-y-4">
              <h2 className="text-4xl font-black uppercase tracking-tighter text-white">AI Processing Clip</h2>
              <p className="text-xl font-bold text-blue-300">Summarizing your shared link for your second brain...</p>
            </div>
            <Loader2Icon className="w-12 h-12 animate-spin text-white" />
          </div>
        </div>
      )}

      <TopInstallBanner />
      <div className="hidden md:block flex-shrink-0">
        <Sidebar view={view} setView={setView} onOpenSettings={() => setShowSettings(true)} onOpenSchedule={() => setShowSchedule(true)} />
      </div>

      <div className="flex-grow flex flex-col min-w-0 bg-[#111827] md:rounded-l-[2rem] md:my-3 md:mr-3 shadow-2xl border-l border-t border-b border-gray-800/50 relative overflow-hidden">
        {showSchedule && (
          <ScheduleView 
            events={allCalendarEvents} 
            onClose={() => setShowSchedule(false)} 
            onAddEvent={addCalendarEvent}
            onDeleteEvent={deleteCalendarEvent}
          />
        )}

        {showSettings && (
          <SettingsModal 
            syncId={user.email || user.uid} 
            onClose={() => setShowSettings(false)} 
            onReset={() => {}} 
            data={{ memories, courses, tasks }}
            onImport={() => {}} 
            moodleToken={moodleToken}
            onSaveMoodleToken={saveMoodleToken}
          />
        )}

        {sharedContent && (
          <AddWebMemoryModal 
            initialUrl={sharedContent.url}
            initialTitle={sharedContent.title}
            onClose={() => setSharedContent(null)}
            onSave={handleSaveSharedClip}
          />
        )}

        <header className="flex-shrink-0 bg-gray-800 border-b-2 border-gray-700 shadow-md z-20 md:hidden" style={{ paddingTop: 'var(--sat)' }}>
          <div className="flex justify-between items-center px-4 py-3">
              <button onClick={() => setShowSchedule(true)} className="p-3 bg-gray-900 rounded-xl border-2 border-gray-700 text-blue-400 active:scale-90 transition-transform">
                  <CalendarIcon className="w-8 h-8" />
              </button>

              <div className="flex items-center gap-3">
                  <BrainCircuitIcon className="w-8 h-8 text-blue-400" />
                  <h1 className="text-xl font-black uppercase tracking-tight">{viewTitles[view]}</h1>
              </div>

              <button onClick={() => setShowSettings(true)} className="p-3 rounded-xl bg-gray-900 border-2 border-gray-700 active:scale-90 transition-transform">
                  <SettingsIcon className="w-8 h-8 text-gray-400" />
              </button>
          </div>
        </header>

        <main className="flex-grow min-h-0 relative z-10 flex flex-col">
          <div className="flex-grow overflow-y-auto p-4 sm:p-6 lg:p-10 scroll-smooth pb-10">
            <div className="max-w-7xl mx-auto h-full">
              {renderView()}
            </div>
          </div>
        </main>

        <footer className="flex-shrink-0 bg-gray-900 border-t-2 border-gray-800 shadow-[0_-4px_10px_rgba(0,0,0,0.3)] z-20 md:hidden" style={{ paddingBottom: 'max(var(--sab), 0.5rem)' }}>
          <BottomNavBar view={view} setView={setView} />
        </footer>
      </div>

      {updateAvailable && <UpdateNotification onUpdate={updateServiceWorker} />}
    </div>
  );
}

export default App;

