                <footer className="p-6 bg-gray-800 border-t-4 border-gray-700 shrink-0 flex flex-col gap-4">
                    <button onClick={handleSignOut} className="w-full py-5 bg-red-600 text-white font-black text-2xl rounded-2xl shadow-xl border-b-8 border-red-800 active:border-b-0 active:translate-y-2 transition-all uppercase tracking-tighter">
