const MoodleBrowser: React.FC<{
    token: string;
    courseName: string;
    onImport: (content: MoodleContent) => void;
    onClose: () => void;
}> = ({ token, courseName, onImport, onClose }) => {
    const [courses, setCourses] = useState<MoodleCourse[]>([]);
    const [contents, setContents] = useState<MoodleContent[]>([]);
    const [loading, setLoading] = useState(true);
    const [activeCourseId, setActiveCourseId] = useState<number | null>(null);

    useEffect(() => {
        const load = async () => {
            const mc = await fetchMoodleCourses(token);
            setCourses(mc);
            // Auto-select course if name matches
            const match = mc.find(c => c.fullname.toLowerCase().includes(courseName.toLowerCase()) || courseName.toLowerCase().includes(c.shortname.toLowerCase()));
            if (match) setActiveCourseId(match.id);
            setLoading(false);
        };
        load();
    }, [token, courseName]);

    useEffect(() => {
        if (activeCourseId) {
            setLoading(true);
            fetchCourseContents(token, activeCourseId).then(c => {
                setContents(c);
                setLoading(false);
            });
        }
    }, [activeCourseId, token]);

    return (
        <div className="fixed inset-0 z-[200] bg-black/90 flex flex-col p-4 animate-fade-in" onClick={onClose}>
            <div className="bg-gray-800 w-full max-w-2xl mx-auto my-auto rounded-[3rem] border-4 border-gray-700 flex flex-col max-h-[85vh] overflow-hidden" onClick={e => e.stopPropagation()}>
                <header className="p-6 border-b-4 border-gray-700 flex justify-between items-center bg-gray-800">
                    <h2 className="text-xl font-black text-white uppercase tracking-tighter flex items-center gap-3">
                        <GlobeIcon className="w-8 h-8 text-green-400"/> Moodle Browser
                    </h2>
                    <button onClick={onClose} className="p-3 bg-gray-700 rounded-2xl active:scale-90"><XIcon className="w-6 h-6"/></button>
                </header>

                <div className="flex-grow overflow-y-auto p-6 space-y-6">
                    {!activeCourseId ? (
                        <div className="space-y-4">
                            <p className="text-gray-400 font-black uppercase text-xs tracking-widest">Select Moodle Course</p>
                            {courses.map(c => (
                                <button key={c.id} onClick={() => setActiveCourseId(c.id)} className="w-full text-left p-5 bg-gray-900 rounded-2xl border-2 border-gray-700 hover:border-green-500 transition-all font-black text-white uppercase tracking-tight truncate">
                                    {c.fullname}
                                </button>
                            ))}
                        </div>
                    ) : (
                        <div className="space-y-4">
                            <div className="flex items-center gap-3 mb-2">
                                <button onClick={() => setActiveCourseId(null)} className="text-green-400 font-black text-xs uppercase tracking-widest flex items-center gap-1 hover:underline">
                                    <ArrowLeftIcon className="w-4 h-4"/> Back to Courses
                                </button>
                            </div>
                            {loading ? (
                                <div className="py-20 flex flex-col items-center gap-4">
                                    <Loader2Icon className="w-12 h-12 animate-spin text-green-500" />
                                    <span className="font-black text-gray-500 uppercase tracking-widest">Fetching Materials...</span>
                                </div>
                            ) : contents.length === 0 ? (
                                <div className="py-20 text-center opacity-50">
                                    <p className="font-black text-gray-400 uppercase">No files found for this course.</p>
                                </div>
                            ) : (
                                contents.map(item => (
                                    <button 
                                        key={item.id} 
                                        onClick={() => { onImport(item); onClose(); }} 
                                        className="w-full flex items-center justify-between p-5 bg-gray-900 rounded-2xl border-2 border-gray-700 hover:border-blue-500 group transition-all"
                                    >
                                        <div className="flex items-center gap-4 text-left overflow-hidden">
                                            {item.type === 'url' ? <GlobeIcon className="w-6 h-6 text-teal-400"/> : <FileTextIcon className="w-6 h-6 text-indigo-400"/>}
                                            <span className="font-black text-white uppercase tracking-tight truncate">{item.name}</span>
                                        </div>
                                        <PlusIcon className="w-6 h-6 text-gray-600 group-hover:text-white group-hover:scale-110 transition-all"/>
                                    </button>
                                ))
                            )}
                        </div>
                    )}
                </div>

                <footer className="p-4 bg-gray-900 border-t-2 border-gray-700 text-center">
                    <button onClick={onClose} className="text-gray-500 font-black uppercase text-xs tracking-widest">Close Browser</button>
                </footer>
            </div>
        </div>
    );
};

const CollegeView: React.FC<CollegeViewProps> = ({ lectures, onSave, onDelete, onUpdate, bulkDelete, courses, addCourse, tasks, addTask, updateTask, deleteTask, moodleToken }) => {
    type View = 'courses' | 'lectures' | 'lectureDetail' | 'documentDetail' | 'qa' | 'record' | 'temporaryScan';
    const [view, setView] = useState<View>('courses');
    const [showAddDocModal, setShowAddDocModal] = useState(false);
    const [showMoodleBrowser, setShowMoodleBrowser] = useState(false);
    const [selectedCourse, setSelectedCourse] = useState<string | null>(null);
    const [selectedLecture, setSelectedLecture] = useState<VoiceMemory | null>(null);
    const [selectedDocument, setSelectedDocument] = useState<DocumentMemory | FileMemory | null>(null);
    const [newCourseName, setNewCourseName] = useState('');
    const [activeTab, setActiveTab] = useState<'lectures' | 'resources' | 'tasks'>('lectures'); 

    const memoriesByCourse = useMemo(() => {
        const grouped: { [key: string]: AnyMemory[] } = {};
        lectures.forEach(l => {
            if (l.category === 'college' && l.course) {
                if (!grouped[l.course]) grouped[l.course] = [];
                grouped[l.course].push(l);
            }
        });
        Object.values(grouped).forEach(arr => arr.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
        return grouped;
    }, [lectures]);

    const handleMoodleImport = async (content: MoodleContent) => {
        if (!selectedCourse) return;
        const memory: Omit<FileMemory, 'id' | 'date'> = {
            type: 'file',
            title: content.name,
            fileUrl: content.fileurl || '',
            mimeType: content.mimetype || 'application/pdf',
            sourceType: 'moodle',
            moodleId: content.id.toString(),
            category: 'college',
            course: selectedCourse
        };
        onSave(memory);
    };

    const handleSelectItem = (item: AnyMemory) => {
        if (item.type === 'voice') {
            setSelectedLecture(item as VoiceMemory);
            setView('lectureDetail');
        } else if (item.type === 'document' || item.type === 'file') {
            setSelectedDocument(item as DocumentMemory);
            setView('documentDetail');
        }
    };

    if (view === 'temporaryScan') return <TemporaryScanView onClose={() => setView('courses')} />;
    if (view === 'record') return <Recorder onSave={(mem) => onSave({ ...mem, category: 'college', course: selectedCourse || 'General' })} onCancel={() => setView('lectures')} titlePlaceholder={`${selectedCourse} - ${new Date().toLocaleDateString()}`} saveButtonText="Save Lecture" />;
    if (view === 'lectureDetail' && selectedLecture) return <LectureDetailView lecture={selectedLecture} onBack={() => setView('lectures')} onUpdate={onUpdate} />;
    if (view === 'documentDetail' && selectedDocument) {
        // Shared rendering for DocumentMemory and FileMemory
        return <DocumentDetailView doc={selectedDocument as any} onBack={() => setView('lectures')} />;
    }

    if (view === 'lectures' && selectedCourse) {
        const courseMemories = memoriesByCourse[selectedCourse] || [];
        const resourceMemories = courseMemories.filter(m => m.type === 'file' || m.type === 'document');
        const lectureMemories = courseMemories.filter(m => m.type === 'voice');

        return (
            <div className="flex flex-col h-full max-w-7xl mx-auto">
                 {showAddDocModal && <AddDocumentModal course={selectedCourse} onSave={(m) => { onSave(m); setShowAddDocModal(false); }} onClose={() => setShowAddDocModal(false)} />}
                 {showMoodleBrowser && moodleToken && <MoodleBrowser token={moodleToken} courseName={selectedCourse} onImport={handleMoodleImport} onClose={() => setShowMoodleBrowser(false)} />}

                 <header className="flex items-center justify-between mb-6 flex-shrink-0">
                    <div className="flex items-center">
                        <button onClick={() => setView('courses')} className="p-3 mr-4 rounded-xl bg-gray-800 hover:bg-gray-700 text-white transition-colors"><ArrowLeftIcon className="w-8 h-8" /></button>
                        <h2 className="text-3xl md:text-4xl font-black truncate">{selectedCourse}</h2>
                    </div>
                 </header>

                 <div className="flex mb-8 bg-gray-800/50 p-1.5 rounded-2xl flex-shrink-0 max-w-2xl overflow-x-auto scrollbar-hide">
                    <button onClick={() => setActiveTab('lectures')} className={`flex-1 py-3 px-6 rounded-xl font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'lectures' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}>
                        Lectures
                    </button>
                    <button onClick={() => setActiveTab('resources')} className={`flex-1 py-3 px-6 rounded-xl font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'resources' ? 'bg-indigo-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}>
                        Resources
                    </button>
                    <button onClick={() => setActiveTab('tasks')} className={`flex-1 py-3 px-6 rounded-xl font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'tasks' ? 'bg-purple-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}>
                        Kanban
                    </button>
                 </div>

                {activeTab === 'lectures' ? (
                    <div className="flex-1 min-h-0 space-y-6 overflow-y-auto pr-1">
                        <button onClick={() => setView('record')} className="w-full flex items-center justify-center gap-4 p-8 bg-blue-600 rounded-[2rem] hover:bg-blue-700 shadow-xl transition-all hover:-translate-y-1 active:scale-95 group">
                            <MicIcon className="w-10 h-10 text-white group-hover:scale-110 transition-transform"/>
                            <span className="text-2xl font-black text-white uppercase">New Recording</span>
                        </button>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-20">
                            {lectureMemories.map(mem => (
                                <div key={mem.id} onClick={() => handleSelectItem(mem)} className="bg-gray-800 p-6 rounded-[2rem] border-4 border-gray-800 cursor-pointer hover:border-blue-500 hover:-translate-y-1 transition-all group">
                                    <h3 className="text-xl font-black text-white truncate mb-1 uppercase tracking-tight">{mem.title}</h3>
                                    <p className="text-sm text-gray-500 font-bold mb-4">{new Date(mem.date).toLocaleDateString()}</p>
                                    <div className="flex items-center gap-2">
                                        <div className="p-3 bg-gray-900 rounded-xl"><MicIcon className="w-6 h-6 text-blue-400"/></div>
                                        {(mem as VoiceMemory).summary && <p className="text-xs text-gray-400 italic line-clamp-1">{(mem as VoiceMemory).summary}</p>}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                ) : activeTab === 'resources' ? (
                    <div className="flex-1 min-h-0 space-y-6 overflow-y-auto pr-1">
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                            <button onClick={() => setShowAddDocModal(true)} className="flex items-center justify-center gap-4 p-6 bg-indigo-600 rounded-[2rem] text-white shadow-xl hover:-translate-y-1 transition-all active:scale-95">
                                <FileTextIcon className="w-8 h-8" /> <span className="text-xl font-black uppercase">Scan Document</span>
                            </button>
                            <button onClick={() => setShowMoodleBrowser(true)} disabled={!moodleToken} className="flex items-center justify-center gap-4 p-6 bg-green-600 rounded-[2rem] text-white shadow-xl hover:-translate-y-1 transition-all active:scale-95 disabled:opacity-50 disabled:grayscale disabled:hover:translate-y-0">
                                <GlobeIcon className="w-8 h-8" /> <span className="text-xl font-black uppercase">{moodleToken ? 'Browse Moodle' : 'Connect Moodle in Settings'}</span>
                            </button>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-20">
                            {resourceMemories.map(mem => (
                                <ResourceItem key={mem.id} resource={mem as FileMemory} onSelect={() => handleSelectItem(mem)} />
                            ))}
                        </div>
                    </div>
                ) : (
                    <div className="flex-grow min-h-0 overflow-hidden">
                        <KanbanBoard tasks={tasks} category="college" courseFilter={selectedCourse} onUpdateTask={updateTask} onDeleteTask={deleteTask} onAddTask={addTask} memories={lectures} onOpenMemory={handleSelectItem} />
                    </div>
                )}
            </div>
        );
    }

    return (
        <div className="flex flex-col h-full">
             <div className="flex mb-6 bg-gray-800/50 p-1.5 rounded-2xl shrink-0 max-w-lg">
                <button onClick={() => setActiveTab('lectures')} className={`flex-1 py-3 rounded-xl font-black uppercase tracking-widest transition-all ${activeTab === 'lectures' ? 'bg-gray-600 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}>
                    Folders
                </button>
                <button onClick={() => setActiveTab('tasks')} className={`flex-1 py-3 rounded-xl font-black uppercase tracking-widest transition-all ${activeTab === 'tasks' ? 'bg-gray-600 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}>
                    All Tasks
                </button>
             </div>

             {activeTab === 'tasks' ? (
                 <div className="flex-grow min-h-0 overflow-hidden">
                    <KanbanBoard tasks={tasks} category="college" courseFilter={null} onUpdateTask={updateTask} onDeleteTask={deleteTask} onAddTask={addTask} memories={lectures} onOpenMemory={handleSelectItem} />
                 </div>
             ) : (
                <div className="flex-1 min-h-0 flex flex-col overflow-hidden">
                    <div className="flex gap-4 mb-8 flex-shrink-0">
                        <input type="text" value={newCourseName} onChange={(e) => setNewCourseName(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleAddCourse()} placeholder="New Course Folder..." className="flex-grow bg-gray-800 text-white text-xl p-5 rounded-2xl border-4 border-gray-800 focus:border-blue-500 outline-none shadow-inner"/>
                        <button onClick={handleAddCourse} className="p-5 bg-blue-600 text-white rounded-2xl hover:bg-blue-700 disabled:opacity-50 shadow-xl transition-all active:scale-95" disabled={!newCourseName.trim()}><PlusCircleIcon className="w-10 h-10" /></button>
                    </div>

                    <div className="flex-1 min-h-0 overflow-y-auto space-y-10 pr-1 pb-10">
                        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
                            {courses.map(course => (
                                <div key={course} onClick={() => handleSelectCourse(course)} className="bg-gray-800 p-8 rounded-[2.5rem] shadow-xl border-4 border-gray-800 cursor-pointer hover:border-blue-500 hover:-translate-y-2 transition-all flex flex-col items-center justify-center aspect-square group">
                                    <FolderIcon className="w-16 h-16 text-blue-400 mb-4 group-hover:scale-110 transition-transform"/>
                                    <span className="text-xl font-black text-center text-white truncate w-full px-2 uppercase tracking-tight">{course}</span>
                                    <span className="text-sm text-gray-500 font-black mt-1">{(memoriesByCourse[course]?.length || 0)} ITEMS</span>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
             )}
        </div>
    );
};

