const SettingsModal: React.FC<SettingsModalProps> = ({ syncId, onClose, moodleToken, onSaveMoodleToken }) => {
    const [wizardStep, setWizardStep] = useState<0 | 1 | 2>(0); 
    const [tempMoodleToken, setTempMoodleToken] = useState('');
    const [isConnecting, setIsConnecting] = useState(false);
    const { isInstallable, installApp } = useInstallPrompt();
    const [showManualInstall, setShowManualInstall] = useState(false);

    const currentUser = auth.currentUser;
    const isGoogleUser = currentUser?.providerData.some(p => p.providerId === 'google.com');
    const userPhoto = currentUser?.photoURL;
    const userName = currentUser?.displayName || syncId;

    const speak = useCallback(async (text: string) => {
        try {
            const audioB64 = await generateSpeechFromText(text);
            if (audioB64) {
                const ctx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
                const audioData = decode(audioB64);
                const buffer = await decodeAudioData(audioData, ctx, 24000, 1);
                const source = ctx.createBufferSource();
                source.buffer = buffer;
                source.connect(ctx.destination);
                source.start(0);
            }
        } catch (e) { console.error(e); }
    }, []);

    useEffect(() => {
        if (wizardStep !== 1) return;
        const checkClipboard = async () => {
            try {
                const text = await navigator.clipboard.readText();
                if (text.length === 32 && /^[a-f0-9]+$/i.test(text) && text !== tempMoodleToken) {
                    setTempMoodleToken(text);
                    setWizardStep(2);
                    speak("I found your Moodle key. Please tap the blue connect button.");
                }
            } catch (e) {}
        };
        const interval = setInterval(checkClipboard, 1500);
        window.addEventListener('focus', checkClipboard);
        return () => { clearInterval(interval); window.removeEventListener('focus', checkClipboard); };
    }, [wizardStep, tempMoodleToken, speak]);

    const handleMoodleStart = () => {
        setWizardStep(1);
        speak("Step 1: I am opening the college login page. Step 2: Log in and find the Mobile Web Service token. Step 3: Copy it and come back here.");
        setTimeout(() => { window.open("https://online.dyellin.ac.il/user/managetoken.php", "_blank"); }, 3000);
    };

    const handleMoodleConnect = async () => {
        setIsConnecting(true);
        onSaveMoodleToken(tempMoodleToken);
        await new Promise(r => setTimeout(r, 800));
        setIsConnecting(false);
        setWizardStep(0);
        setTempMoodleToken('');
        speak("Moodle is connected.");
    };

    const handleSignOut = async () => {
        if(window.confirm("Sign out of your Second Brain?")) {
            await signOut(auth);
            onClose();
        }
    };

    const handleGoogleConnect = async () => {
        if (!currentUser || isGoogleUser) return;
        try {
            googleProvider.addScope('https://www.googleapis.com/auth/calendar.readonly');
            await linkWithPopup(currentUser, googleProvider);
            speak("Calendar connected.");
        } catch (error: any) { console.error(error); }
    };

    return (
         <div className="fixed inset-0 bg-black/95 flex flex-col justify-center items-center z-[150] p-2 sm:p-4 animate-fade-in">
            <div className="bg-gray-800 rounded-[3rem] shadow-2xl w-full max-w-2xl h-full max-h-[95vh] border-4 border-gray-600 flex flex-col overflow-hidden" onClick={(e) => e.stopPropagation()}>
                <header className="flex justify-between items-center p-6 sm:p-8 border-b-4 border-gray-700 shrink-0">
                    <h2 className="text-2xl font-black text-white uppercase tracking-tighter">Settings</h2>
                    <button onClick={onClose} className="p-4 rounded-2xl bg-gray-700 active:scale-90 transition-transform"><XIcon className="w-8 h-8 text-gray-300"/></button>
                </header>

                <div className="flex-grow p-5 sm:p-8 space-y-10 overflow-y-auto scroll-smooth pb-20">
                    {wizardStep === 0 ? (
                        <>
                            {/* Profile Section */}
                            <div className="bg-gray-900 p-6 rounded-[2.5rem] border-4 border-blue-600 shadow-2xl flex items-center gap-6">
                                <div className="relative shrink-0">
                                    {userPhoto ? <img src={userPhoto} alt="" className="w-20 h-20 rounded-full border-4 border-blue-400 shadow-lg" />
                                    : <div className="w-20 h-20 rounded-full bg-blue-600 flex items-center justify-center border-4 border-blue-400 shadow-xl"><UserIcon className="w-10 h-10 text-white" /></div>}
                                </div>
                                <div className="flex-grow overflow-hidden">
                                    <p className="text-blue-400 font-black text-[10px] uppercase tracking-widest mb-1">Signed In As</p>
                                    <p className="text-white text-2xl font-black truncate leading-none uppercase tracking-tighter">{userName}</p>
                                </div>
                            </div>

                            {/* App Installation Section */}
                            <SettingsSection title="System & App">
                                {isInstallable ? (
                                    <button 
                                        onClick={installApp}
                                        className="w-full flex items-center justify-between p-6 bg-blue-600 rounded-[2.5rem] border-4 border-blue-400 shadow-xl active:scale-95 transition-all group"
                                    >
                                        <div className="flex items-center gap-5 text-white">
                                            <PlusCircleIcon className="w-12 h-12" />
                                            <div className="text-left">
                                                <p className="text-xl font-black uppercase tracking-tighter">Install App</p>
                                                <p className="text-xs font-bold text-blue-200 uppercase tracking-widest mt-1">Get Full Screen & Share Menu</p>
                                            </div>
                                        </div>
                                        <div className="bg-white text-blue-600 px-5 py-3 rounded-2xl font-black text-xs uppercase">Install</div>
                                    </button>
                                ) : (
                                    <div className="p-6 bg-gray-900 rounded-[2.5rem] border-4 border-gray-800 border-dashed space-y-4">
                                        <div className="flex justify-between items-center">
                                            <div className="text-left">
                                                <p className="text-gray-400 font-black uppercase tracking-tighter">App is Standalone</p>
                                                <p className="text-[10px] font-bold text-gray-600 uppercase tracking-widest mt-1">Status: Operational</p>
                                            </div>
                                            <button 
                                                onClick={() => setShowManualInstall(!showManualInstall)}
                                                className="text-blue-500 font-black text-xs uppercase tracking-widest hover:underline"
                                            >
                                                {showManualInstall ? 'Hide Help' : 'Help Installing?'}
                                            </button>
                                        </div>

                                        {showManualInstall && (
                                            <div className="bg-blue-600/10 p-5 rounded-2xl border-2 border-blue-600/30 animate-slide-up space-y-3">
                                                <p className="text-white text-sm font-bold">To get the Share Menu on Android:</p>
                                                <ol className="text-xs text-blue-200 font-bold space-y-2 list-decimal list-inside">
                                                    <li>Open this app in Google Chrome.</li>
                                                    <li>Tap the 3 dots in the top right.</li>
                                                    <li>Select "Install App".</li>
                                                    <li>Wait for the icon to appear on home.</li>
                                                </ol>
                                            </div>
                                        )}
                                    </div>
                                )}
                            </SettingsSection>

                            {/* Connections Section */}
                            <SettingsSection title="External Links">
                                <ConnectionItem 
                                    label="Google Calendar" icon={<CalendarIcon className="w-10 h-10" />}
                                    status={isGoogleUser ? 'connected' : 'available'}
                                    onClick={handleGoogleConnect}
                                    subtitle={isGoogleUser ? 'SYNCING SCHEDULE' : 'TAP TO LINK'} />

                                <ConnectionItem 
                                    label="Moodle (Dyellin)" 
                                    icon={<GraduationCapIcon className="w-10 h-10" />} 
                                    status={moodleToken ? 'connected' : 'disconnected'} 
                                    onClick={moodleToken ? () => onSaveMoodleToken('') : handleMoodleStart} 
                                    buttonText={moodleToken ? "Unlink" : "Wizard"}
                                    subtitle={moodleToken ? "FOLDERS SYNCED" : "GUIDED LOGIN"}
                                    colorClass="indigo"
                                />
                            </SettingsSection>

                            {/* Account Management */}
                            <SettingsSection title="Account">
                                <button 
                                    onClick={handleSignOut} 
                                    className="w-full flex items-center gap-5 p-6 bg-red-900/20 border-4 border-red-900/50 rounded-[2.5rem] hover:bg-red-900/30 transition-all text-red-400"
                                >
                                    <LogOutIcon className="w-10 h-10" />
                                    <div className="text-left">
                                        <p className="text-xl font-black uppercase tracking-tighter">Sign Out</p>
                                        <p className="text-xs font-bold opacity-70 uppercase tracking-widest mt-1">Logout from this device</p>
                                    </div>
                                </button>
                            </SettingsSection>

                            <div className="pt-10 text-center">
                                <p className="text-[11px] text-gray-600 font-black uppercase tracking-widest">Second Brain v2.7 • Secure Cloud Sync</p>
                            </div>
                        </>
                    ) : wizardStep === 1 ? (
                        <div className="space-y-8 animate-slide-up py-4">
                             <div className="flex items-center gap-4 text-green-400">
                                <GlobeIcon className="w-10 h-10"/>
                                <h3 className="text-3xl font-black uppercase tracking-tighter">Moodle Wizard</h3>
                             </div>
                             <div className="bg-gray-900 p-8 rounded-[2rem] border-2 border-gray-700 space-y-6">
                                <p className="text-white text-xl font-bold leading-tight">1. We opened Moodle in a new tab.</p>
                                <p className="text-white text-xl font-bold leading-tight">2. Log in and find the <span className="text-green-400">"Mobile token"</span>.</p>
                                <p className="text-white text-xl font-bold leading-tight">3. Copy it and return here.</p>
                             </div>
                             <div className="bg-blue-600/20 p-8 rounded-[2rem] border-4 border-blue-500 border-dashed flex flex-col items-center gap-4 text-center">
                                <Loader2Icon className="w-12 h-12 text-blue-400 animate-spin" />
                                <p className="text-blue-200 font-black uppercase tracking-widest text-sm">Waiting for you to copy the key...</p>
                             </div>
                             <button onClick={() => setWizardStep(0)} className="w-full py-4 text-gray-500 font-black uppercase tracking-widest">Cancel</button>
                        </div>
                    ) : (
                        <div className="space-y-8 animate-bounce-short py-6 text-center">
                             <div className="bg-green-600 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-4 shadow-[0_0_40px_rgba(22,163,74,0.4)]">
                                <CheckIcon className="w-16 h-16 text-white" />
                             </div>
                             <h3 className="text-4xl font-black text-white uppercase tracking-tighter">Detected!</h3>
                             <p className="text-xl text-gray-400 font-bold">Tap below to connect your folders.</p>
                             <button 
                                onClick={handleMoodleConnect} 
                                disabled={isConnecting}
                                className="w-full py-6 bg-blue-600 text-white font-black text-2xl rounded-[2rem] shadow-2xl border-b-8 border-blue-800 active:border-b-0 active:translate-y-2 transition-all uppercase"
                             >
                                {isConnecting ? <Loader2Icon className="w-10 h-10 animate-spin mx-auto"/> : 'CONNECT NOW'}
                             </button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
