const MoodleBrowser: React.FC<{
    token: string;
    courseName: string;
    onImport: (content: MoodleContent) => void;
    onClose: () => void;
}> = ({ token, courseName, onImport, onClose }) => {
    const [courses, setCourses] = useState<MoodleCourse[]>([]);
    const [contents, setContents] = useState<MoodleContent[]>([]);
    const [loading, setLoading] = useState(true);
    const [activeCourseId, setActiveCourseId] = useState<number | null>(null);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        const load = async () => {
            setLoading(true);
            setError(null);
            try {
                const mc = await fetchMoodleCourses(token);
                if (!mc || mc.length === 0) {
                    setError("No courses found or invalid token.");
                } else {
                    setCourses(mc);
                    // Try to auto-match current course folder
                    const match = mc.find(c => 
                        c.fullname.toLowerCase().includes(courseName.toLowerCase()) || 
                        courseName.toLowerCase().includes(c.shortname.toLowerCase())
                    );
                    if (match) setActiveCourseId(match.id);
                }
            } catch (err: any) {
                console.error("Moodle Browser Error:", err);
                setError(err.message || "Connection error. Please try again.");
            } finally {
                setLoading(false);
            }
        };
        load();
    }, [token, courseName]);

    useEffect(() => {
        if (activeCourseId) {
            setLoading(true);
            setError(null);
            fetchCourseContents(token, activeCourseId)
                .then(c => {
                    setContents(c);
                    if (c.length === 0) setError("This folder appears to be empty.");
                })
                .catch((err: any) => {
                    console.error("Moodle Content Error:", err);
                    setError(err.message || "Failed to load folder contents.");
