        <main className="flex-grow min-h-0 relative z-10 flex flex-col">
          <div className="flex-grow overflow-y-auto p-4 sm:p-6 lg:p-10 scroll-smooth pb-10">
            <div className="max-w-7xl mx-auto h-full">
              {renderView()}
