                ))}
            </div>

            <main className="flex-grow overflow-y-auto space-y-3 pb-40 px-0.5">
                {filteredMemories.length === 0 ? (
                    <div className="text-center py-20 bg-gray-800/20 rounded-[2rem] border-4 border-dashed border-gray-700 opacity-50">
