                                <p className="text-gray-400 font-bold text-lg px-4">
                                    {wizardStep === 1 
                                        ? "Log in to Moodle in the other tab, go to 'Mobile web services' and COPY your key. I'll detect it here." 
                                        : "I've detected your college key. Tap below to finish syncing."}
                                </p>
                            </div>
                            {wizardStep === 2 && (
                                <button 
                                    onClick={handleMoodleConnect}
                                    disabled={isConnecting}
                                    className="w-full py-6 bg-green-600 text-white font-black text-2xl rounded-3xl shadow-xl active:scale-95 transition-all flex items-center justify-center gap-4"
                                >
                                    {isConnecting ? <Loader2Icon className="w-8 h-8 animate-spin" /> : <PlusCircleIcon className="w-8 h-8" />}
                                    {isConnecting ? 'SYNCING...' : 'FINISH SYNC'}
                                </button>
                            )}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

