const StudyChat: React.FC<{ memories: AnyMemory[], initialContext: string }> = ({ memories, initialContext }) => {
    // A specialized chat instance that focuses on cross-document synthesis
    const [messages, setMessages] = useState<{sender: 'user'|'ai', text: string}[]>([]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    const handleSend = async () => {
        if (!input.trim() || isLoading) return;
        const q = input;
        setInput('');
        setMessages(prev => [...prev, { sender: 'user', text: q }]);
        setIsLoading(true);

        try {
            // Enhanced context that includes the study hub context + selected memories
            const contextPrompt = `You are in a Deep Research Hub. 
            CONTEXT FROM CURRENT STUDY POD: ${initialContext}

            USER QUESTION: ${q}

            TASK: Answer the question using the provided context. 
            CRITICAL: Also search the user's OTHER memories (provided in your overall context window) to find relevant connections across courses.
            If you find a link to a different course or note, explicitly mention it (e.g. "This relates to your Physics note from Tuesday...")`;

            const response = await answerQuestionFromContext(memories, [], contextPrompt);
            setMessages(prev => [...prev, { sender: 'ai', text: response }]);
        } catch (e) {
            console.error(e);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="flex flex-col h-full space-y-4">
            <div className="flex-grow overflow-y-auto space-y-4 pr-1 scrollbar-hide">
                {messages.length === 0 && (
                    <div className="py-20 text-center space-y-4 opacity-50">
                        <BrainCircuitIcon className="w-16 h-16 mx-auto text-blue-500" />
                        <p className="font-black text-white uppercase">Ask about connections...</p>
                    </div>
                )}
                {messages.map((m, i) => (
                    <div key={i} className={`flex ${m.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[85%] p-5 rounded-3xl text-xl font-bold ${m.sender === 'user' ? 'bg-blue-600 text-white rounded-br-none' : 'bg-gray-800 text-gray-200 border-2 border-gray-700 rounded-bl-none'}`}>
                            {m.text}
                        </div>
                    </div>
                ))}
                {isLoading && <div className="flex justify-start"><div className="bg-gray-800 p-5 rounded-3xl animate-pulse"><Loader2Icon className="w-8 h-8 animate-spin text-blue-500"/></div></div>}
            </div>
            <div className="bg-gray-800 p-3 rounded-3xl flex gap-3 border-4 border-gray-700 shadow-inner">
                <input 
                    value={input} 
                    onChange={e => setInput(e.target.value)} 
                    onKeyPress={e => e.key === 'Enter' && handleSend()}
                    placeholder="Ask a deep question..." 
                    className="flex-grow bg-transparent text-white font-bold p-3 outline-none"
                />
                <button onClick={handleSend} className="p-4 bg-blue-600 text-white rounded-2xl active:scale-90 transition-transform"><PlusIcon className="w-8 h-8 rotate-45"/></button>
            </div>
        </div>
    );
};

