import { GoogleGenAI, Modality, Type, FunctionDeclaration } from "@google/genai";
import { getGeminiInstance } from '../utils/gemini';
import type { AnyMemory, Task, CalendarEvent } from '../types';

const model = "gemini-3-pro-preview";
const UNAVAILABLE_ERROR_MESSAGE = "AI features are unavailable. Please check your API key configuration.";

const createCalendarEventTool: FunctionDeclaration = {
  name: "createCalendarEvent",
  description: "Schedules a time slot or event in the user's calendar.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING, description: "The title of the event" },
      startTime: { type: Type.STRING, description: "ISO 8601 formatted start time" },
      endTime: { type: Type.STRING, description: "ISO 8601 formatted end time" },
      category: { type: Type.STRING, enum: ["college", "personal"], description: "The category of the event" },
      description: { type: Type.STRING, description: "Optional details about the event" }
    },
    required: ["title", "startTime", "endTime", "category"]
  }
};

export async function generateStudyOverview(
    memories: AnyMemory[], 
    focus: string, 
    type: 'written' | 'audio' | 'video'
): Promise<{ content: string, title: string, imageUrl?: string }> {
    const ai = getGeminiInstance();
    if (!ai) throw new Error("AI Unavailable");

    const context = memories.map(m => `[SOURCE: ${m.title}] ${
        m.type === 'voice' ? (m as any).transcript : (m as any).extractedText || (m as any).summary
    }`).join('\n\n---\n\n');

    let prompt = "";
    if (type === 'written') {
        prompt = `Create a structured, academic deep-dive summary of these materials. 
        FOCUS: ${focus || 'General synthesis'}. Use bullet points and clear headings.`;
    } else if (type === 'audio') {
        prompt = `Write a script for a "Study Podcast" episode where an expert host breaks down these materials. 
        FOCUS: ${focus || 'Key takeaways'}. The host should be engaging and clarify complex concepts. 
        Preserve the language of the source materials (Hebrew/English). 
        Start immediately with the discussion.`;
    } else {
        prompt = `Provide a rich, conceptual visual description and walkthrough of these materials. 
        FOCUS: ${focus || 'Main themes'}. Describe what an infographic of this topic would look like.`;
    }

    const response = await ai.models.generateContent({
        model,
        contents: `CONTEXT:\n${context}\n\nGOAL: ${prompt}`,
        config: { systemInstruction: "You are an advanced education research assistant specializing in cross-document connections." }
    });

    const content = response.text || "Failed to generate summary.";
    const title = await generateTitleForContent(content);

    let imageUrl = undefined;
    if (type === 'video') {
        // Generate a conceptual image for the topic
        try {
            const imgRes = await ai.models.generateContent({
                model: 'gemini-2.5-flash-image',
                contents: `A clean, academic, conceptual 3D illustration or infographic representing the following topic: ${title}. High quality, minimal style.`,
                config: { imageConfig: { aspectRatio: "16:9" } }
            });
            for (const part of imgRes.candidates?.[0]?.content?.parts || []) {
                if (part.inlineData) imageUrl = `data:image/png;base64,${part.inlineData.data}`;
            }
        } catch (e) { console.error("Image generation failed", e); }
    }

    return { content, title, imageUrl };
}

export async function answerQuestionFromContext(
    memories: AnyMemory[], 
    tasks: Task[], 
    question: string,
    calendarEvents: CalendarEvent[] = [],
    onToolCall?: (toolCall: any) => Promise<any>
): Promise<string> {
  const ai = getGeminiInstance();
  if (!ai) return UNAVAILABLE_ERROR_MESSAGE;

  const memoryContext = memories.map(mem => `[NOTE/FILE] ${mem.title}: ${
      mem.type === 'voice' ? (mem as any).transcript : 
      mem.type === 'document' ? (mem as any).extractedText : 
      (mem as any).summary || (mem as any).content || ''
  }`).join('\n\n---\n\n');

  const systemInstruction = `You are a personal assistant for a visually impaired student.
  Current Date/Time: ${new Date().toLocaleString()}

  IMPORTANT: The context provided is the user's SELECTED documents. 
  However, you have access to their ENTIRE "Second Brain". 
  If the user asks about connections to other materials, search your provided global context to find links between different courses or subjects. 
  Highlight connections like "This theory reminds me of the History note you saved last week."`;

  try {
    const response = await ai.models.generateContent({
        model,
        contents: `OVERALL SECOND BRAIN CONTEXT:\n${memoryContext}\n\nUSER QUESTION/REQUEST:\n${question}`,
        config: {
            systemInstruction,
            tools: [{ functionDeclarations: [createCalendarEventTool] }]
        },
    });

    if (response.functionCalls && onToolCall) {
        let finalResponse = "";
        for (const call of response.functionCalls) {
            const result = await onToolCall(call);
            const finalResult = await ai.models.generateContent({
                model,
                contents: [
                    { role: 'user', parts: [{ text: question }] },
                    { role: 'model', parts: [{ functionCall: call }] },
                    { role: 'user', parts: [{ functionResponse: { name: call.name, response: { result } } }] }
                ]
            });
            finalResponse += finalResult.text;
        }
        return finalResponse || "Processed.";
    }

    return response.text ?? "I'm not sure.";
  } catch (error) {
    return "Error processing request.";
  }
}

export async function generateTitleForContent(content: string): Promise<string> {
    const ai = getGeminiInstance();
    if (!ai || !content.trim()) return "Untitled";
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Short, uppercase 2-3 word title for: ${content.substring(0, 1000)}`,
            config: { stopSequences: ['\n'] },
        });
        return (response.text ?? "Untitled").trim().replace(/"/g, ''); 
    } catch (error) { return "Untitled"; }
}

export async function generateSpeechFromText(text: string): Promise<string | null> {
    const ai = getGeminiInstance();
    if (!ai) return null;
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text: text.substring(0, 5000) }] }],
            config: { responseModalities: [Modality.AUDIO], speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } } },
        });
        return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || null;
    } catch (error) { return null; }
}

export async function extractTextFromImage(base64Data: string, mimeType: string): Promise<string> {
    const ai = getGeminiInstance();
    if (!ai) return UNAVAILABLE_ERROR_MESSAGE;
    try {
        const response = await ai.models.generateContent({
            model,
            contents: { 
                parts: [
                    { inlineData: { mimeType, data: base64Data } }, 
                    { text: `Extract text precisely. Hebrew/English.` }
                ] 
            },
        });
        return response.text ?? "No text found.";
    } catch (error) { return "Error extracting text."; }
}

export async function analyzeVoiceNote(content: string): Promise<{ title: string; actionItems: string[] }> {
    const ai = getGeminiInstance();
    if (!ai) return { title: "Untitled", actionItems: [] };
    try {
        const response = await ai.models.generateContent({
            model,
            contents: `Note: ${content.substring(0, 4000)}. Provide Title and Action Items in JSON.`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        actionItems: { type: Type.ARRAY, items: { type: Type.STRING } }
                    },
                    required: ["title", "actionItems"]
                }
            }
        });
        return JSON.parse(response.text || "{}");
    } catch (error) { return { title: "Voice Note", actionItems: [] }; }
}

export async function processSharedUrl(url: string, title: string, text: string): Promise<{ 
    title: string; 
    summary: string; 
    type: 'Article' | 'Video'; 
    takeaways: string[] 
}> {
    const ai = getGeminiInstance();
    if (!ai) throw new Error("AI Unavailable");
    try {
        const response = await ai.models.generateContent({
            model,
            contents: `URL: ${url}. Analyze and return JSON with summary and takeaways.`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        summary: { type: Type.STRING },
                        type: { type: Type.STRING, enum: ['Article', 'Video'] },
                        takeaways: { type: Type.ARRAY, items: { type: Type.STRING } }
                    },
                    required: ["title", "summary", "type", "takeaways"]
                }
            }
        });
        return JSON.parse(response.text || "{}");
    } catch (error) { return { title: title || "Shared Link", summary: text, type: 'Article', takeaways: [] }; }
}

import { useState, useEffect, useCallback } from 'react';

export const useServiceWorker = () => {
    const [waitingWorker, setWaitingWorker] = useState<ServiceWorker | null>(null);
    const [updateAvailable, setUpdateAvailable] = useState(false);

    const onUpdate = useCallback((registration: ServiceWorkerRegistration) => {
        if (registration.waiting) {
            setWaitingWorker(registration.waiting);
            setUpdateAvailable(true);
        }
    }, []);

    useEffect(() => {
        if ('serviceWorker' in navigator) {
            const registerAndListen = () => {
                // Fix: Force the registration to use the current window's origin
                // to avoid mismatch errors in proxied preview environments.
                const swUrl = new URL('sw.js', window.location.href).href;

                navigator.serviceWorker.register(swUrl).then(registration => {
                    if (registration.waiting) {
                        onUpdate(registration);
                    }
                    registration.addEventListener('updatefound', () => {
                        const newWorker = registration.installing;
                        if (newWorker) {
                            newWorker.addEventListener('statechange', () => {
                                if (newWorker.state === 'installed') {
                                    onUpdate(registration);
                                }
                            });
                        }
                    });
                }).catch(error => {
                    console.error('Service Worker registration failed:', error);
                });
            };

            if (document.readyState === 'complete') {
                registerAndListen();
            } else {
                window.addEventListener('load', registerAndListen);
                return () => window.removeEventListener('load', registerAndListen);
            }

            let refreshing = false;
            navigator.serviceWorker.addEventListener('controllerchange', () => {
                if (!refreshing) {
                    window.location.reload();
                    refreshing = true;
                }
            });
        }
    }, [onUpdate]);

    const updateServiceWorker = useCallback(() => {
        if (waitingWorker) {
            waitingWorker.postMessage({ type: 'SKIP_WAITING' });
        }
    }, [waitingWorker]);

    return { updateAvailable, updateServiceWorker };
};

import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import type { AnyMemory, DocumentMemory, VoiceMemory, PhysicalItemMemory, VideoItemMemory, FileMemory } from '../types';
import { 
    FolderIcon, MicIcon, CameraIcon, FileTextIcon, GraduationCapIcon, 
    DownloadIcon, PlusIcon, XIcon, GlobeIcon, Loader2Icon, 
    SearchIcon, ShareIcon, Volume2Icon, PlayIcon, EyeIcon, VideoIcon, StopCircleIcon, ArrowLeftIcon,
    TrashIcon, CheckIcon, PenToolIcon, BrainCircuitIcon, BotIcon
} from './Icons';
import AddDocumentModal from './AddDocumentModal';
import { generateSpeechFromText, answerQuestionFromContext, generateStudyOverview } from '../services/geminiService';
import { decode, decodeAudioData } from '../utils/audio';

interface FilesViewProps {
    memories: AnyMemory[];
    onSave: (memory: Omit<AnyMemory, 'id' | 'date'>) => void;
    onDelete: (id: string) => void;
    onUpdate: (id: string, updates: Partial<AnyMemory>) => void;
